def _load_session() -> RunSession:
    """Load the active session (creates default if none exists)."""
    return RunSession.load(DEFAULT_SESSION_FILE)


def _get_logger(session: RunSession) -> DecisionLog:
    """Get the decision log for the current run."""
    run_id = session.run_id or "default"
    return DecisionLog(run_id)


_DESTROY_TIME_PODS_TARGETS = {
    "chronophobia",
    "lightning war",
    "destroy pods",
    "destroy time pod",
    "destroy time pods",
    "destroy timepods",
}


def _normalized_target_labels(session: RunSession | None) -> set[str]:
    labels = set()
    for value in (
        list(getattr(session, "achievement_targets", None) or [])
        + list(getattr(session, "tags", None) or [])
    ):
        text = str(value).strip().lower().replace("_", " ").replace("-", " ")
        if text:
            labels.add(text)
    return labels


def _destroy_time_pods_policy_active(
    session: RunSession | None,
    *,
    explicit: bool = False,
) -> bool:
    if explicit:
        return True
    return bool(_normalized_target_labels(session) & _DESTROY_TIME_PODS_TARGETS)


_DESTROY_TIME_PODS_SURVIVAL_PENALTY = -1_000_000.0
_DESTROY_TIME_PODS_PICKUP_PENALTY = -2_000_000.0


def _destroy_time_pods_weight_overlay(
    base_weights: dict | None,
    applied: list[str] | None = None,
) -> tuple[dict, list[str]]:
    """Prefer pod destruction while making mech collection very unattractive."""
    weights = dict(base_weights or {})
    overlays = list(applied or [])
    weights["pod_uncollected"] = min(
        float(weights.get("pod_uncollected", 0) or 0),
        _DESTROY_TIME_PODS_SURVIVAL_PENALTY,
    )
    weights["pod_proximity"] = min(
        float(weights.get("pod_proximity", 0) or 0),
        0.0,
    )
    weights["pod_collected"] = min(
        float(weights.get("pod_collected", 0) or 0),
        _DESTROY_TIME_PODS_PICKUP_PENALTY,
    )
    if "destroy_time_pods" not in overlays:
        overlays.append("destroy_time_pods")
    return weights, overlays


def _achievement_weight_overlay(
    session: RunSession | None,
    base_weights: dict | None,
) -> tuple[dict | None, list[str]]:
    """Apply narrow live-run scoring nudges for active achievement targets."""
    targets = {
        str(t).strip().lower()
        for t in (getattr(session, "achievement_targets", None) or [])
        if str(t).strip()
    }
    if not targets:
        return base_weights, []

    weights = dict(base_weights or {})
    applied: list[str] = []
    normalized_targets = {
        target.replace("_", " ").replace("-", " ")
        for target in targets
    }

    if "this is fine" in targets:
        # The run goal is five enemies burning at once, not fast cleanup.
        # Keep ordinary safety weights intact, but reward burning Vek enough
        # that safe fire-spreading lines beat unnecessary kills.
        weights["enemy_on_fire_bonus"] = max(
            float(weights.get("enemy_on_fire_bonus", 0) or 0),
            3500.0,
        )
        weights["enemy_killed"] = min(
            float(weights.get("enemy_killed", 0) or 0),
            -500.0,
        )
        weights["enemy_hp_remaining"] = max(
            float(weights.get("enemy_hp_remaining", -100) or -100),
            -25.0,
        )
        applied.append("this_is_fine")

    if "healing" in targets:
        # Hazardous Mechs' Healing achievement counts actual HP restored by
        # Viscera Nanobots, so prefer safe kill lines that restore missing HP
        # over equivalent full-health kills.
        weights["viscera_nanobots_heal_bonus"] = max(
            float(weights.get("viscera_nanobots_heal_bonus", 0) or 0),
            9000.0,
        )
        applied.append("healing")

    if "stay with me!" in normalized_targets or "stay with me" in normalized_targets:
        # Mist Eaters: the achievement counts real HP restored across the
        # island. Reward actual repairs from Nanofilter Mending, direct Repair,
        # and repair platforms enough to beat routine kills, while leaving
        # building/grid safety high in the candidate frontier.
        weights["stay_with_me_heal_bonus"] = max(
            float(weights.get("stay_with_me_heal_bonus", 0) or 0),
            3000.0,
        )
        weights["enemy_killed"] = min(
            float(weights.get("enemy_killed", 900) or 900),
            250.0,
        )
        weights["enemy_hp_remaining"] = max(
            float(weights.get("enemy_hp_remaining", -100) or -100),
            -25.0,
        )
        applied.append("stay_with_me")

    if "hold the line" in targets:
        # The Blitzkrieg achievement needs four simultaneous spawn blocks.
        # Strongly prefer safe blocks over routine kills so earlier blocked
        # emergence tiles can accumulate into the four-marker setup.
        weights["spawn_blocked"] = max(
            float(weights.get("spawn_blocked", 0) or 0),
            8000.0,
        )
        weights["enemy_killed"] = min(
            float(weights.get("enemy_killed", 900) or 900),
            250.0,
        )
        weights["enemy_hp_remaining"] = max(
            float(weights.get("enemy_hp_remaining", -100) or -100),
            -25.0,
        )
        applied.append("hold_the_line")

    if "powered blast" in targets:
        # Bombermechs: reward the exact AP Cannon-through-Walking-Bomb kill
        # event enough that safe setup lines beat ordinary cleanup.
        weights["powered_blast_bonus"] = max(
            float(weights.get("powered_blast_bonus", 0) or 0),
            120000.0,
        )
        applied.append("powered_blast")

    if normalized_targets & {"on the backburner", "on the backbuner"}:
        # Mist Eaters: reward the exact 4+ effective-damage Reverse Thrusters
        # event, including the Detritus A.C.I.D. two-tile cheese.
        weights["reverse_thrusters_four_damage_bonus"] = max(
            float(weights.get("reverse_thrusters_four_damage_bonus", 0) or 0),
            120000.0,
        )
        applied.append("on_the_backburner")

    if "lightning war" in targets:
        # Lightning War is pure real-time throughput: pods add reward UI and
        # do not help the achievement. Keep safety weights intact, but remove
        # ordinary pod-seeking pressure and make intentional pickup lose to
        # almost any equivalent non-pod line.
        weights["pod_uncollected"] = 0.0
        weights["pod_proximity"] = 0.0
        weights["pod_collected"] = min(
            float(weights.get("pod_collected", 0) or 0),
            -4000.0,
        )
        # Fewer spawned Vek means shorter enemy turns and fewer future
        # decisions; do not overpower building/grid protection.
        weights["spawn_blocked"] = max(
            float(weights.get("spawn_blocked", 0) or 0),
            1600.0,
        )
        applied.append("lightning_war")

    if normalized_targets & _DESTROY_TIME_PODS_TARGETS:
        weights, applied = _destroy_time_pods_weight_overlay(weights, applied)

    return weights, applied


