def _atomic_json_write(filepath: Path, data: dict) -> None:
    """Write JSON atomically: tmp file -> fsync -> os.replace."""
    filepath.parent.mkdir(parents=True, exist_ok=True)
    tmp_path = filepath.with_suffix(f".tmp.{os.getpid()}")
    try:
        with open(tmp_path, "w") as f:
            json.dump(data, f, indent=2, default=str)
            f.flush()
            os.fsync(f.fileno())
        os.replace(str(tmp_path), str(filepath))
    except Exception:
        if tmp_path.exists():
            tmp_path.unlink()
        raise


def _recording_dir(session: RunSession) -> Path:
    """Get the recording directory for the current run."""
    run_id = session.run_id or "default"
    run_dir = RECORDING_DIR / run_id
    run_dir.mkdir(parents=True, exist_ok=True)
    return run_dir


def _active_post_enemy_block(session: RunSession) -> dict | None:
    """Return a normalized unresolved post-enemy hard stop, if any."""
    block = session.post_enemy_block
    if not isinstance(block, dict):
        return None
    if os.environ.get("ITB_ALLOW_UNRESOLVED_POST_ENEMY") == "1":
        return None
    result = dict(block)
    result.setdefault("status", "INVESTIGATE_POST_ENEMY")
    result.setdefault("blocking", True)
    result.setdefault("source", "session_post_enemy_block")
    result.setdefault("next_step", (
        "Resolve this post-enemy investigation before solving, executing, "
        "or emitting another End Turn plan. Use `research_next`/diagnosis "
        "or `resolve_post_enemy_block --reason ...` after the miss is understood."
    ))
    return result


def _post_enemy_block_result(session: RunSession) -> dict | None:
    block = _active_post_enemy_block(session)
    if block is None:
        return None
    return {
        "status": block.get("status", "INVESTIGATE_POST_ENEMY"),
        "blocking": True,
        "source": block.get("source", "session_post_enemy_block"),
        "post_enemy_investigation": block,
        "mission_index": block.get("mission_index"),
        "turn": block.get("turn"),
        "deltas": block.get("deltas", {}),
        "next_step": block.get("next_step"),
    }


def _attach_post_enemy_block(result: dict, session: RunSession) -> None:
    """Annotate read/status-style results without hiding their payload."""
    block = _post_enemy_block_result(session)
    if block is None:
        return
    result.setdefault("status", block["status"])
    result.setdefault("blocking", True)
    result.setdefault("post_enemy_investigation", block["post_enemy_investigation"])
    result.setdefault("next_step", block["next_step"])


def _install_post_enemy_block(
    session: RunSession,
    result: dict,
    *,
    record_path: Path | None = None,
) -> dict:
    """Persist a worse-than-predicted post-enemy audit as a hard stop."""
    block_id = (
        f"{session.run_id or 'default'}_m{int(result.get('mission_index', 0)):02d}"
        f"_t{int(result.get('turn', 0)):02d}_post_enemy"
    )
    block = {
        "id": block_id,
        "status": result.get("status", "INVESTIGATE_POST_ENEMY"),
        "blocking": True,
        "run_id": session.run_id or "default",
        "mission_index": result.get("mission_index", session.mission_index),
        "turn": result.get("turn"),
        "created_at": datetime.now().isoformat(),
        "source": result.get("source", "record_post_enemy"),
        "record_path": str(record_path) if record_path is not None else None,
        "reason": result.get("reason"),
        "deltas": result.get("deltas", {}),
        "triggers": result.get("triggers", []),
        "actual_outcome": result.get("actual_outcome"),
        "predicted_outcome": result.get("predicted_outcome"),
        "next_step": result.get("next_step") or (
            "Investigate this enemy-phase prediction miss before solving, "
            "executing, or emitting another End Turn plan. Clear only after "
            "the simulator/process cause is understood."
        ),
    }
    session.post_enemy_block = block
    return block


def _hard_stop_result(status: str, **extra) -> dict:
    result = {
        "status": status,
        "blocking": True,
        "next_step": (
            "Stop live combat commands and resolve the hard stop before "
            "continuing."
        ),
    }
    result.update(extra)
    return result


def _is_hard_stop_status(status: object) -> bool:
    return isinstance(status, str) and (
        status in _HARD_STOP_STATUSES
        or status.startswith("INVESTIGATE")
        or status.startswith("SAFETY_BLOCKED")
    )


def _threat_audit_requires_block(
    threat_audit: dict | None,
    plan_safety: dict | None,
    session: RunSession,
    *,
    dirty_consent_validated: bool = False,
    lightning_speed_loss_allowed: bool = False,
) -> bool:
    """Block End Turn when the pre-click audit still sees protected damage."""
    if not isinstance(threat_audit, dict):
        return False
    still_threatened = int(threat_audit.get("still_threatened_count") or 0)
    if still_threatened <= 0:
        return False
    safety = plan_safety if isinstance(plan_safety, dict) else {}
    if dirty_consent_validated and _dirty_plan_covers_threat_audit_loss(
        threat_audit,
        safety,
    ):
        return False
    if lightning_speed_loss_allowed and _lightning_speed_plan_covers_threat_audit_loss(
        threat_audit,
        safety,
    ):
        return False
    if lightning_speed_loss_allowed and _lightning_speed_unplanned_threat_loss_allowed(
        threat_audit,
        safety,
    ):
        return False
    if final_cave_emergency_pylon_loss_allowed(safety):
        current = safety.get("current") if isinstance(safety.get("current"), dict) else {}
        predicted = (
            safety.get("predicted")
            if isinstance(safety.get("predicted"), dict)
            else {}
        )
        cur_pylons = current.get("pylons_alive")
        pred_pylons = predicted.get("pylons_alive")
        pylon_losses = (
            cur_pylons - pred_pylons
            if isinstance(cur_pylons, int) and isinstance(pred_pylons, int)
            else 0
        )
        if int(threat_audit.get("still_threatened_count") or 0) <= pylon_losses:
            return False
    return True


def _lightning_speed_plan_covers_threat_audit_loss(
    threat_audit: dict,
    plan_safety: dict,
) -> bool:
    """True when a Lightning speed-policy loss accounts for held threats."""
    still_threatened = int(threat_audit.get("still_threatened_count") or 0)
    if still_threatened <= 0:
        return True
    if not isinstance(plan_safety, dict):
        return False

    covered_losses = max(
        _safety_int_loss(plan_safety, "grid_power"),
        _safety_int_loss(plan_safety, "building_hp_total"),
        _safety_int_loss(plan_safety, "buildings_alive"),
        _safety_int_loss(plan_safety, "objective_buildings_alive"),
        _safety_int_loss(plan_safety, "objective_building_hp_total"),
        _safety_int_loss(plan_safety, "protected_objective_units_alive"),
    )
    return covered_losses >= still_threatened


def _lightning_speed_unplanned_threat_loss_allowed(
    threat_audit: dict,
    plan_safety: dict,
) -> bool:
    """Allow ordinary unplanned building hits for Lightning War pace only."""
    still_threatened = int(threat_audit.get("still_threatened_count") or 0)
    if still_threatened <= 0:
        return True
    current = plan_safety.get("current")
    if not isinstance(current, dict):
        return False
    grid_power = current.get("grid_power")
    if not isinstance(grid_power, int) or grid_power - still_threatened <= 0:
        return False

    protected_fields = ("pylons_alive", "pylon_hp_total", "bigbomb_alive")
    for field in protected_fields:
        value = current.get(field)
        if isinstance(value, bool):
            if value:
                return False
        elif isinstance(value, int) and value > 0:
            return False

    entries = threat_audit.get("entries")
    if not isinstance(entries, list):
        return False
    live_entries = [
        entry for entry in entries
        if isinstance(entry, dict)
        and (
            not isinstance(entry.get("coverage"), dict)
            or entry.get("coverage", {}).get("reason") in {
                "still_threatened",
                "still_threatened_current",
                "still_threatened_initial",
            }
        )
    ]
    if len(live_entries) < still_threatened:
        return False
    for entry in live_entries[:still_threatened]:
        if not isinstance(entry, dict):
            return False
        target_hp = entry.get("target_hp")
        if not isinstance(target_hp, int) or target_hp <= 0:
            return False
    return True


def _dirty_plan_covers_threat_audit_loss(
    threat_audit: dict,
    plan_safety: dict,
) -> bool:
    """Return true when a reviewed dirty plan already accounts for threats.

    The threat audit runs after actions, just before End Turn. During Lightning
    War we may intentionally accept an ordinary grid/building hit for speed.
    In that case the audit should not demand a second manual override when the
    remaining threat count is no larger than the already-reviewed ordinary
    building/grid loss. Objective, pylon, timeline-collapse, and mech-loss
    cases still block here.
    """
    still_threatened = int(threat_audit.get("still_threatened_count") or 0)
    if still_threatened <= 0:
        return True
    if not isinstance(plan_safety, dict) or not plan_safety.get("blocking"):
        return False

    kinds = {
        v.get("kind")
        for v in plan_safety.get("violations", []) or []
        if isinstance(v, dict) and v.get("blocking")
    }
    allowed_kinds = {
        "grid_damage",
        "building_hp_loss",
        "building_destroyed",
        "mech_hp_loss",
        "pod_lost",
    }
    if not kinds or any(kind not in allowed_kinds for kind in kinds):
        return False

    current = plan_safety.get("current")
    predicted = plan_safety.get("predicted")
    if not isinstance(current, dict) or not isinstance(predicted, dict):
        return False

    def loss(field: str) -> int:
        cur = current.get(field)
        pred = predicted.get(field)
        if isinstance(cur, int) and isinstance(pred, int):
            return max(0, cur - pred)
        return 0

    ordinary_hits = max(
        loss("grid_power"),
        loss("building_hp_total"),
        loss("buildings_alive"),
    )
    return ordinary_hits >= still_threatened


def _end_turn_click_plan_result(*, bridge_ack: str | None = None) -> dict:
    recalibrate()
    batch = plan_end_turn()
    codex_batch = [
        c["codex_computer_use"]
        for c in batch
        if isinstance(c, dict) and c.get("codex_computer_use")
    ]
    result = {
        "status": "PLAN",
        "batch": batch,
        "codex_computer_use_batch": codex_batch,
        "next_step": (
            "dispatch codex_computer_use_batch with Computer Use "
            "(or legacy batch with screen-coordinate batch tools), "
            "wait ~6s, then `read`"
        ),
    }
    if bridge_ack is not None:
        result["bridge_ack"] = bridge_ack
    return result


def _dirty_consent_id(
    session: RunSession,
    turn: int,
    plan_safety: dict | None,
    actions: list[SolverAction],
    *,
    candidate_rank: int | None = None,
) -> str:
    active = session.active_solution
    payload = {
        "run_id": session.run_id or "default",
        "mission_index": session.mission_index,
        "turn": turn,
        "input_fingerprint": active.input_fingerprint if active else "",
        "candidate_rank": candidate_rank,
        "loss_profile": safety_loss_profile(plan_safety),
        "actions": [a.to_dict() for a in actions],
    }
    raw = json.dumps(payload, sort_keys=True, separators=(",", ":"))
    return hashlib.sha256(raw.encode("utf-8")).hexdigest()[:16]


