_LIGHTNING_BRIDGE_PREVIEW_MAX_STATE_AGE_SECONDS = 8.0


def _lightning_newest_bridge_state_age_seconds() -> float | None:
    mtimes: list[float] = []
    for path in (STATE_FILE, STATE_TMP):
        try:
            if path.exists():
                mtimes.append(path.stat().st_mtime)
        except OSError:
            continue
    if not mtimes:
        return None
    return max(0.0, time.time() - max(mtimes))


def _lightning_bridge_preview_freshness() -> dict:
    heartbeat_alive = is_bridge_alive(max_stale_sec=5.0)
    state_age = _lightning_newest_bridge_state_age_seconds()
    state_fresh = (
        state_age is not None
        and state_age <= _LIGHTNING_BRIDGE_PREVIEW_MAX_STATE_AGE_SECONDS
    )
    return {
        "bridge_heartbeat_alive": heartbeat_alive,
        "bridge_heartbeat_stale": not heartbeat_alive,
        "bridge_state_age_seconds": (
            round(state_age, 3) if state_age is not None else None
        ),
        "bridge_state_fresh": state_fresh,
        "bridge_preview_live": bool(heartbeat_alive and state_fresh),
    }


def _lightning_bridge_preview_recommendation_stale(
    recommendation: dict | None,
) -> bool:
    if not isinstance(recommendation, dict):
        return False
    if recommendation.get("source") != "bridge_preview":
        return False
    if recommendation.get("bridge_preview_live") is False:
        return True
    if recommendation.get("bridge_heartbeat_stale") is True:
        return True
    if recommendation.get("bridge_heartbeat_alive") is False:
        return True
    if recommendation.get("bridge_state_fresh") is False:
        return True
    return False


def _lightning_normalize_visible_preview_text(texts: list[str]) -> str:
    blob = " ".join(str(text or "") for text in texts).lower()
    blob = re.sub(r"[^a-z0-9]+", " ", blob)
    return re.sub(r"\s+", " ", blob).strip()


def _lightning_visible_preview_mission_from_texts(
    texts: list[str],
    *,
    screenshot_path: str | Path | None = None,
) -> dict:
    normalized = _lightning_normalize_visible_preview_text(texts)
    matches: list[dict[str, str]] = []
    for mission_id, patterns in _LIGHTNING_VISIBLE_PREVIEW_MISSION_PATTERNS:
        for pattern in patterns:
            if pattern in normalized:
                matches.append({"mission_id": mission_id, "pattern": pattern})
    matched_missions = sorted({match["mission_id"] for match in matches})
    if len(matched_missions) > 1:
        if (
            "Mission_Holes" in matched_missions
            and (
                "erosion points" in normalized
                or "no fly zone" in normalized
                or "air superiority" in normalized
            )
        ):
            first_match = next(
                match for match in matches if match["mission_id"] == "Mission_Holes"
            )
            result = {
                "status": "OK",
                "source": "visible_preview_ocr",
                "mission_id": first_match["mission_id"],
                "matched_pattern": first_match["pattern"],
                "matched_patterns": matches,
                "resolved_conflict": True,
                "conflicting_missions": matched_missions,
                "start_authority": "veto_only",
                "texts": texts,
                "normalized_text": normalized,
            }
            if screenshot_path is not None:
                result["screenshot_path"] = str(screenshot_path)
            return result
        if (
            "Mission_Cataclysm" in matched_missions
            and "Mission_Terraform" in matched_missions
            and (
                "cataclysmic" in normalized
                or "fall into the depths" in normalized
                or "cataclysm" in normalized
            )
        ):
            first_match = next(
                match
                for match in matches
                if match["mission_id"] == "Mission_Cataclysm"
            )
            result = {
                "status": "OK",
                "source": "visible_preview_ocr",
                "mission_id": first_match["mission_id"],
                "matched_pattern": first_match["pattern"],
                "matched_patterns": matches,
                "resolved_conflict": True,
                "conflicting_missions": matched_missions,
                "start_authority": "veto_only",
                "texts": texts,
                "normalized_text": normalized,
            }
            if screenshot_path is not None:
                result["screenshot_path"] = str(screenshot_path)
            return result
        for priority_mission in (
            "Mission_Airstrike",
            "Mission_Tides",
            "Mission_Mines",
        ):
            priority_matches = [
                match for match in matches if match["mission_id"] == priority_mission
            ]
            if priority_matches:
                first_match = priority_matches[0]
                result = {
                    "status": "OK",
                    "source": "visible_preview_ocr",
                    "mission_id": first_match["mission_id"],
                    "matched_pattern": first_match["pattern"],
                    "matched_patterns": matches,
                    "resolved_conflict": True,
                    "conflicting_missions": matched_missions,
                    "start_authority": "veto_only",
                    "texts": texts,
                    "normalized_text": normalized,
                }
                if screenshot_path is not None:
                    result["screenshot_path"] = str(screenshot_path)
                return result
        result = {
            "status": "UNKNOWN",
            "reason": "conflicting_known_preview_text_matches",
            "matched_missions": matched_missions,
            "matched_patterns": matches,
            "texts": texts,
            "normalized_text": normalized,
        }
        if screenshot_path is not None:
            result["screenshot_path"] = str(screenshot_path)
        return result
    if matches:
        first_match = matches[0]
        result = {
            "status": "OK",
            "source": "visible_preview_ocr",
            "mission_id": first_match["mission_id"],
            "matched_pattern": first_match["pattern"],
            "matched_patterns": matches,
            "start_authority": "veto_only",
            "texts": texts,
            "normalized_text": normalized,
        }
        if screenshot_path is not None:
            result["screenshot_path"] = str(screenshot_path)
        return result
    for mission_id, required_patterns in _LIGHTNING_VISIBLE_PREVIEW_GENERIC_SPEED_PATTERNS:
        if all(pattern in normalized for pattern in required_patterns):
            result = {
                "status": "OK",
                "source": "visible_preview_ocr",
                "mission_id": mission_id,
                "matched_pattern": "generic_vek_threat_coal_plant_mech_damage",
                "matched_patterns": [
                    {"mission_id": mission_id, "pattern": pattern}
                    for pattern in required_patterns
                ],
                "start_authority": "veto_only",
                "texts": texts,
                "normalized_text": normalized,
            }
            if screenshot_path is not None:
                result["screenshot_path"] = str(screenshot_path)
            return result
    startish = any(
        pattern in normalized
        for pattern in (
            "start mission",
            "start miission",
            "tart mission",
        )
    )
    if "vek threat detected" in normalized and startish:
        result = {
            "status": "OK",
            "source": "visible_preview_ocr",
            "mission_id": "Mission_GenericThreat",
            "matched_pattern": "generic_vek_threat_detected_speed_card",
            "matched_patterns": [
                {"mission_id": "Mission_GenericThreat", "pattern": "vek threat detected"},
                {"mission_id": "Mission_GenericThreat", "pattern": "speed_card"},
            ],
            "start_authority": "veto_only",
            "texts": texts,
            "normalized_text": normalized,
        }
        if screenshot_path is not None:
            result["screenshot_path"] = str(screenshot_path)
        return result
    result = {
        "status": "UNKNOWN",
        "reason": "no_known_preview_text_match",
        "texts": texts,
        "normalized_text": normalized,
    }
    if screenshot_path is not None:
        result["screenshot_path"] = str(screenshot_path)
    return result


def _lightning_visible_preview_mission_from_screenshot(
    screenshot_path: str | Path,
) -> dict:
    """Infer a preview mission from visible text for veto-only route safety."""
    ocr = _lightning_ocr_texts_from_image(screenshot_path)
    if ocr.get("status") != "OK":
        return {
            "status": "UNKNOWN",
            "reason": "preview_ocr_unavailable",
            "ocr": ocr,
            "screenshot_path": str(screenshot_path),
        }
    texts = [str(text) for text in (ocr.get("texts") or [])]
    return _lightning_visible_preview_mission_from_texts(
        texts,
        screenshot_path=screenshot_path,
    )


def _lightning_visible_preview_mission_from_visible_ui(
    visible_ui: dict | None,
) -> dict | None:
    """Infer preview mission from an existing UI snapshot before slow refreshes."""
    if not isinstance(visible_ui, dict) or visible_ui.get("status") != "OK":
        return None
    texts: list[str] = []
    for key in ("ocr_texts", "texts"):
        value = visible_ui.get(key)
        if isinstance(value, list):
            texts.extend(str(text) for text in value if str(text).strip())
    for key in ("visible_text", "ocr_text", "text"):
        value = visible_ui.get(key)
        if isinstance(value, str) and value.strip():
            texts.extend(value.splitlines())
    if texts:
        return _lightning_visible_preview_mission_from_texts(texts)
    screenshot_path = visible_ui.get("screenshot_path")
    if screenshot_path:
        return _lightning_visible_preview_mission_from_screenshot(screenshot_path)
    return None


def _lightning_visible_preview_mission_ocr() -> dict:
    """Capture the current preview screen and infer any veto-only mission id."""
    if os.name == "nt":
        return {
            "status": "UNKNOWN",
            "reason": "preview_ocr_unavailable",
            "ocr": {
                "status": "UNAVAILABLE",
                "reason": "macos_vision_only",
                "error": (
                    "Visible preview OCR currently requires macOS Vision/PyObjC."
                ),
            },
        }
    tmp_path = Path(tempfile.gettempdir()) / f"itb_lightning_preview_ocr_{os.getpid()}.png"

    from src.capture.window import take_screenshot

    try:
        take_screenshot(tmp_path)
    except Exception as exc:
        return {
            "status": "UNKNOWN",
            "reason": "preview_ocr_screenshot_failed",
            "error": str(exc),
            "screenshot_path": str(tmp_path),
        }
    return _lightning_visible_preview_mission_from_screenshot(tmp_path)


def _lightning_visible_pause_timer_from_screenshot(
    screenshot_path: str | Path,
) -> dict:
    """Read the visible pause-menu timer from a screenshot when possible."""
    visible_ui = _classify_lightning_ui_image(screenshot_path)
    if visible_ui.get("status") != "OK":
        return {
            "status": "UNKNOWN",
            "reason": "screen_classification_failed",
            "visible_ui": visible_ui,
            "screenshot_path": str(screenshot_path),
        }

    ocr = _lightning_ocr_texts_from_image(screenshot_path)
    if ocr.get("status") != "OK":
        return {
            "status": "UNKNOWN",
            "reason": "ocr_unavailable",
            "ocr": ocr,
            "visible_ui": visible_ui,
            "screenshot_path": str(screenshot_path),
        }

    matches: list[dict] = []
    ocr_texts = [str(text) for text in (ocr.get("texts") or [])]
    has_timeline_label = any(
        "timeline" in text.lower() or "playtime" in text.lower()
        for text in ocr_texts
    )
    has_game_time_label = any("game time" in text.lower() for text in ocr_texts)
    for text in ocr.get("texts") or []:
        seconds = _lightning_parse_visible_timer_ocr_seconds(text)
        if seconds is None:
            continue
        compact_text = str(text).lower().replace(" ", "")
        matches.append({
            "text": text,
            "game_seconds": seconds,
            "game_timer": _lightning_format_seconds(seconds),
            "pause_timer_like": bool(
                re.search(r"[0o]h.*[0o]m.*[0-9oil]+(?:s|5)", compact_text)
                or re.search(r"[0-9oil]+h.*[0-9oil]+m.*[0-9oil]+(?:s|5)", compact_text)
            ),
        })
    if not matches:
        return {
            "status": "UNKNOWN",
            "reason": "visible_timer_text_not_found",
            "ocr": ocr,
            "visible_ui": visible_ui,
            "screenshot_path": str(screenshot_path),
        }
    if (
        visible_ui.get("visible_ui") != "pause_menu"
        and not has_timeline_label
        and not has_game_time_label
    ):
        return {
            "status": "UNKNOWN",
            "reason": "timer_label_not_visible",
            "ocr": ocr,
            "visible_ui": visible_ui,
            "screenshot_path": str(screenshot_path),
        }

    candidate_matches = matches
    discarded_matches: list[dict] = []
    if has_timeline_label:
        pause_matches = [item for item in matches if item.get("pause_timer_like")]
        if pause_matches:
            candidate_matches = pause_matches
    plausible_matches = [
        item for item in candidate_matches if int(item["game_seconds"]) <= 7200
    ]
    if plausible_matches:
        discarded_matches = [
            item for item in candidate_matches if item not in plausible_matches
        ]
        candidate_matches = plausible_matches
    best = max(candidate_matches, key=lambda item: int(item["game_seconds"]))
    source = (
        "visible_game_timer"
        if has_game_time_label and not has_timeline_label
        else "visible_pause_menu_timer"
    )
    return {
        "status": "OK",
        "source": source,
        "game_seconds": float(best["game_seconds"]),
        "game_timer": best["game_timer"],
        "ocr_text": best["text"],
        "timer_matches": matches,
        "discarded_timer_matches": discarded_matches,
        "classifier_visible_ui": visible_ui.get("visible_ui"),
        "timeline_label_seen": has_timeline_label,
        "game_time_label_seen": has_game_time_label,
        "visible_ui": visible_ui,
        "screenshot_path": str(screenshot_path),
    }


def _lightning_read_visible_pause_timer() -> dict:
    """Capture the current window and OCR the pause-menu timer if visible."""
    visible_ui = _lightning_visible_ui_snapshot()
    screenshot_path = visible_ui.get("screenshot_path")
    if not screenshot_path:
        return {
            "status": "UNKNOWN",
            "reason": "screenshot_unavailable",
            "visible_ui": visible_ui,
        }
    result = _lightning_visible_pause_timer_from_screenshot(screenshot_path)
    result.setdefault("visible_ui", visible_ui)
    return result


def _lightning_effective_timer_source(
    save_timer: dict,
    visible_timer: dict | None = None,
) -> dict:
    """Choose screenshot timer proof when visible; save/profile is fallback only."""
    candidates: list[dict] = []
    if (
        visible_timer
        and visible_timer.get("status") == "OK"
        and visible_timer.get("game_seconds") is not None
    ):
        visible_candidate = {
            "source": visible_timer.get("source") or "visible_timer",
            "game_seconds": float(visible_timer["game_seconds"]),
            "game_timer": visible_timer.get("game_timer"),
        }
        candidates.append(visible_candidate)
        if save_timer.get("status") == "OK" and save_timer.get("game_seconds") is not None:
            candidates.append({
                "source": save_timer.get("source") or "save_timer",
                "game_seconds": float(save_timer["game_seconds"]),
                "game_timer": save_timer.get("game_timer"),
            })
        return {
            "status": "OK",
            **visible_candidate,
            "candidates": candidates,
            "selection_reason": "visible_timer_ground_truth",
        }
    if save_timer.get("status") == "OK" and save_timer.get("game_seconds") is not None:
        candidates.append({
            "source": save_timer.get("source") or "save_timer",
            "game_seconds": float(save_timer["game_seconds"]),
            "game_timer": save_timer.get("game_timer"),
        })
    if not candidates:
        return {
            "status": "UNKNOWN",
            "source": None,
            "game_seconds": None,
            "game_timer": None,
            "candidates": [],
        }
    return {"status": "OK", **candidates[0], "candidates": candidates}


def _lightning_preflight_has_visible_pause_timer(preflight: dict | None) -> bool:
    if not isinstance(preflight, dict):
        return False
    visible_timer = preflight.get("visible_timer")
    if not isinstance(visible_timer, dict):
        return False
    return (
        visible_timer.get("status") == "OK"
        and visible_timer.get("source") == "visible_pause_menu_timer"
        and bool(visible_timer.get("timeline_label_seen"))
        and visible_timer.get("game_seconds") is not None
    )


def _lightning_game_timer_budget(
    game_seconds: int | float | None,
    *,
    max_game_seconds: int | float = _LIGHTNING_ACHIEVEMENT_SECONDS,
) -> dict:
    budget = {
        "game_seconds": (
            round(float(game_seconds), 3)
            if game_seconds is not None
            else None
        ),
        "game_timer": _lightning_format_seconds(game_seconds),
        "max_game_seconds": max_game_seconds,
        "max_game_timer": _lightning_format_seconds(max_game_seconds),
    }
    if game_seconds is None:
        budget["game_status"] = "UNKNOWN"
        return budget
    remaining = float(max_game_seconds) - float(game_seconds)
    budget["game_status"] = "EXCEEDED" if remaining <= 0 else "OK"
    budget["remaining_game_seconds"] = round(remaining, 3)
    budget["remaining_game_timer"] = _lightning_format_seconds(remaining)
    return budget


def _lightning_first_mission_start_timer_guard(
    *,
    max_game_seconds: int | float = _LIGHTNING_FIRST_MISSION_OPENING_SECONDS,
) -> dict:
    """Require OCR proof that the first island/map opening hit the speed target."""
    visible_timer = _lightning_read_visible_pause_timer()
    if (
        visible_timer.get("status") != "OK"
        or visible_timer.get("game_seconds") is None
    ):
        return {
            "status": "BLOCKED",
            "reason": "first_mission_start_timer_unverified",
            "visible_timer": visible_timer,
            "gate_seconds": float(max_game_seconds),
            "gate_timer": _lightning_format_seconds(max_game_seconds),
            "next_step": (
                "The first island is paused, but the visible Timeline "
                "Playtime OCR proof is missing. Capture/inspect pause-menu "
                "timer proof before route planning or restart."
            ),
        }

    budget = _lightning_game_timer_budget(
        visible_timer.get("game_seconds"),
        max_game_seconds=max_game_seconds,
    )
    if budget.get("game_status") == "EXCEEDED":
        return {
            "status": "BLOCKED",
            "reason": "first_mission_start_timer_not_reset",
            "visible_timer": visible_timer,
            "game_budget": budget,
            "next_step": (
                "The first island is paused, but visible Timeline Playtime "
                f"is {budget.get('game_timer')}, at/over the "
                f"{budget.get('max_game_timer')} first-mission opening gate. "
                "Abandon to setup or fix timer reset before selecting a "
                "mission."
            ),
        }

    return {
        "status": "OK",
        "reason": "first_mission_start_timer_verified",
        "visible_timer": visible_timer,
        "game_budget": budget,
    }


def _lightning_first_mission_route_start_pace_gate(
    *,
    profile: str = "Alpha",
    route_routing: str = "lightning_war",
    max_game_seconds: int | float = _LIGHTNING_FIRST_MISSION_ROUTE_START_SECONDS,
) -> dict | None:
    """Block first-mission route clicks when visible OCR has already spent the route budget."""
    if str(route_routing or "").strip() != "lightning_war":
        return None
    try:
        session = _load_session()
    except Exception as exc:
        return {
            "status": "BLOCKED",
            "reason": "first_mission_route_start_session_unverified",
            "exception_type": type(exc).__name__,
            "error": str(exc),
            "traceback": traceback.format_exc(),
            "next_step": (
                "Session state could not be loaded before first-mission route "
                "start. Recover session proof before clicking a route."
            ),
        }
    current_mission = str(getattr(session, "current_mission", "") or "").strip()
    completed = list(getattr(session, "islands_completed", []) or [])
    try:
        mission_index = int(getattr(session, "mission_index", 0) or 0)
    except (TypeError, ValueError):
        return {
            "status": "BLOCKED",
            "reason": "first_mission_route_start_session_unverified",
            "session": {
                "current_island": getattr(session, "current_island", None),
                "current_mission": getattr(session, "current_mission", None),
                "mission_index": getattr(session, "mission_index", None),
                "islands_completed": completed,
            },
            "next_step": (
                "Session mission_index is unreadable before first-mission "
                "route start. Recover session proof before clicking a route."
            ),
        }
    if current_mission or mission_index > 0 or completed:
        return None

    visible_timer = _lightning_read_visible_pause_timer()
    if (
        visible_timer.get("status") != "OK"
        or visible_timer.get("game_seconds") is None
    ):
        return {
            "status": "BLOCKED",
            "reason": "first_mission_route_start_timer_unverified",
            "visible_timer": visible_timer,
            "gate_seconds": float(max_game_seconds),
            "gate_timer": _lightning_format_seconds(max_game_seconds),
            "next_step": (
                "Visible pause-menu Timeline Playtime proof is missing before "
                "first-mission route start. Capture timer proof before route "
                "clicks or restart from setup."
            ),
        }
    budget = _lightning_game_timer_budget(
        visible_timer.get("game_seconds"),
        max_game_seconds=max_game_seconds,
    )
    if budget.get("game_status") != "EXCEEDED":
        return None
    deployment_probe = cmd_lightning_snap_pause(
        "first_mission_route_gate_deployment_probe",
        note=(
            "Route-start pace gate tripped; verify whether route already "
            "reached deployment before restarting."
        ),
        run_seconds=0.02,
        include_ocr=True,
    )
    if (
        isinstance(deployment_probe, dict)
        and deployment_probe.get("pause_verified")
    ):
        for candidate in (
            deployment_probe.get("evidence_ui"),
            deployment_probe.get("pause_verify"),
        ):
            if not (isinstance(candidate, dict) and candidate.get("status") == "OK"):
                continue
            if candidate.get("visible_ui") == "deployment_screen":
                return None
            if _lightning_pause_menu_has_deployment_underlay(candidate):
                return None
    return {
        "status": "BLOCKED",
        "reason": "first_mission_route_start_pace_gate",
        "visible_timer": visible_timer,
        "deployment_probe": deployment_probe,
        "game_budget": budget,
        "session": {
            "current_island": getattr(session, "current_island", None),
            "current_mission": current_mission,
            "mission_index": mission_index,
            "islands_completed": completed,
        },
        "next_step": (
            "Visible Timeline Playtime is already at/over the conservative "
            f"{budget.get('max_game_timer')} first-mission route-start gate. "
            "Restart instead of spending route/deployment time on this "
            "timeline."
        ),
    }


def _lightning_first_mission_route_start_timeout_active(
    *,
    profile: str = "Alpha",
    route_routing: str = "lightning_war",
) -> bool:
    """Return whether the opening route probe must fail fast for pace."""
    if str(route_routing or "").strip() != "lightning_war":
        return False
    try:
        session = _load_session()
    except Exception:
        return False
    current_mission = str(getattr(session, "current_mission", "") or "").strip()
    completed = list(getattr(session, "islands_completed", []) or [])
    try:
        mission_index = int(getattr(session, "mission_index", 0) or 0)
    except (TypeError, ValueError):
        return False
    return not current_mission and mission_index <= 0 and not completed


def _lightning_first_mission_opening_route_context(
    *,
    route_routing: str = "lightning_war",
    mission_index: int | None = None,
    current_mission: str | None = None,
    islands_completed: list | tuple | None = None,
) -> bool:
    """Return true while the first timed mission has not been safely started."""
    if str(route_routing or "").strip() != "lightning_war":
        return False
    if mission_index is None and current_mission is None and islands_completed is None:
        return _lightning_first_mission_route_start_timeout_active(
            route_routing=route_routing,
        )
    try:
        index = int(mission_index if mission_index is not None else 0)
    except (TypeError, ValueError):
        index = 0
    completed = list(islands_completed or [])
    mission = str(current_mission or "").strip()
    return index <= 0 and not completed and not mission


def _lightning_mission_objective_tokens(entry: dict) -> set[str]:
    mission_id = str(entry.get("mission_id") or "")
    tokens: set[str] = set()
    if not mission_id:
        return tokens
    tokens.add(mission_id)
    tokens.add(f"{mission_id}_Obj")
    if mission_id.startswith("Mission_"):
        suffix = mission_id.removeprefix("Mission_")
        tokens.add(f"Mission_{suffix.replace('_', '')}_Obj")
    return tokens


def _lightning_save_region_match_score(entry: dict, region: dict) -> int:
    objective_texts = set(region.get("objective_texts") or [])
    objective_params = set(region.get("objective_params") or [])
    score = 0

    if objective_texts & _lightning_mission_objective_tokens(entry):
        score += 8

    asset_id = str(entry.get("asset_id") or "")
    if asset_id and f"{asset_id}_Name" in objective_params:
        score += 3

    for bonus_id in entry.get("bonus_objective_ids") or []:
        try:
            bonus_key = int(bonus_id)
        except (TypeError, ValueError):
            bonus_key = bonus_id
        token = _BONUS_SAVE_TEXT.get(bonus_key)
        if token and token in objective_texts:
            score += 1

    if entry.get("boss") and region.get("name") == "Corporate HQ":
        score += 6

    return score


def _lightning_annotate_island_map_with_save_regions(
    island_map: list[dict] | None,
    save_regions: list[dict],
) -> tuple[list[dict] | None, dict]:
    """Attach save-region state hints so completed entries stop ranking."""
    if not island_map:
        return island_map, {"status": "NO_ISLAND_MAP"}
    if not save_regions:
        return island_map, {"status": "NO_SAVE_REGIONS"}

    annotated: list[dict] = []
    matched = 0
    unavailable = 0
    for entry in island_map:
        best_region = None
        best_score = 0
        for region in save_regions:
            score = _lightning_save_region_match_score(entry, region)
            if score > best_score:
                best_region = region
                best_score = score

        out = dict(entry)
        if best_region is not None and best_score >= 2:
            matched += 1
            state = best_region.get("state")
            out["save_region_index"] = best_region.get("region_index")
            out["save_region_name"] = best_region.get("name")
            out["save_region_state"] = state
            out["save_region_state_label"] = best_region.get("state_label")
            out["save_region_match_score"] = best_score
            if state == 1:
                out["current"] = True
                unavailable += 1
            elif state == 2:
                out["completed"] = True
                unavailable += 1
            elif state == 3:
                out["overrun"] = True
                unavailable += 1
        annotated.append(out)

    return annotated, {
        "status": "OK",
        "entries": len(island_map),
        "save_regions": len(save_regions),
        "matched": matched,
        "unavailable": unavailable,
    }


def _lightning_extract_red_regions_from_image(image_path: str | Path) -> dict:
    """Extract available red corp-map region centers from a screenshot."""
    try:
        import cv2
        import numpy as np
        from PIL import Image
    except Exception as exc:
        return {"status": "UNAVAILABLE", "error": f"vision deps unavailable: {exc}"}

    try:
        image = Image.open(image_path).convert("RGB")
    except Exception as exc:
        return {"status": "ERROR", "error": f"failed to open screenshot: {exc}"}

    width, height = image.size
    base_w, base_h = _LIGHTNING_UI_BASE_SIZE
    raw_scale_x = width / base_w if base_w else 1.0
    raw_scale_y = height / base_h if base_h else 1.0
    scale_x, scale_y, scale_source = _lightning_macos_region_coordinate_scales(
        raw_scale_x,
        raw_scale_y,
    )
    scale_x = scale_x or 1.0
    scale_y = scale_y or 1.0
    left = int(250 * scale_x)
    top = int(120 * scale_y)
    right = int(1160 * scale_x)
    bottom = int(700 * scale_y)
    arr = np.asarray(image)[top:bottom, left:right]
    red = arr[:, :, 0].astype("int16")
    green = arr[:, :, 1].astype("int16")
    blue = arr[:, :, 2].astype("int16")
    mask = (
        (red >= 135)
        & (green <= 115)
        & (blue <= 115)
        & (red >= green + 45)
        & (red >= blue + 45)
    ).astype("uint8")

    min_area = int(4500 * scale_x * scale_y)

    def collect_regions(component_mask) -> list[dict]:
        count, labels, stats, centroids = cv2.connectedComponentsWithStats(
            component_mask,
            8,
        )
        found: list[dict] = []
        for label in range(1, count):
            area = int(stats[label, cv2.CC_STAT_AREA])
            if area < min_area:
                continue
            x = int(stats[label, cv2.CC_STAT_LEFT]) + left
            y = int(stats[label, cv2.CC_STAT_TOP]) + top
            w = int(stats[label, cv2.CC_STAT_WIDTH])
            h = int(stats[label, cv2.CC_STAT_HEIGHT])
            cx = float(centroids[label][0]) + left
            cy = float(centroids[label][1]) + top
            found.append(
                {
                    "window_x": int(round(cx / scale_x)),
                    "window_y": int(round(cy / scale_y)),
                    "bbox_window": [
                        int(round(x / scale_x)),
                        int(round(y / scale_y)),
                        int(round((x + w) / scale_x)),
                        int(round((y + h) / scale_y)),
                    ],
                    "area_px": area,
                    "area_window": round(area / (scale_x * scale_y), 1),
                }
            )
        return _lightning_merge_visual_regions(found)

    raw_regions = collect_regions(mask)
    kernel_size = max(2, int(round(3 * max(scale_x, scale_y))))
    kernel = np.ones((kernel_size, kernel_size), np.uint8)
    eroded_mask = cv2.erode(mask, kernel, iterations=1)
    eroded_regions = collect_regions(eroded_mask)
    use_eroded = len(eroded_regions) > len(raw_regions)
    regions = eroded_regions if use_eroded else raw_regions
    regions.sort(key=lambda r: (r["window_y"], r["window_x"]))
    for index, region in enumerate(regions):
        region["index"] = index
        base_x = int(region["window_x"])
        base_y = int(region["window_y"])
        base_bbox = [int(value) for value in region["bbox_window"]]
        image_x = int(round(base_x * scale_x))
        image_y = int(round(base_y * scale_y))
        image_bbox = [
            int(round(base_bbox[0] * scale_x)),
            int(round(base_bbox[1] * scale_y)),
            int(round(base_bbox[2] * scale_x)),
            int(round(base_bbox[3] * scale_y)),
        ]
        region["base_window_x"] = base_x
        region["base_window_y"] = base_y
        region["bbox_base_window"] = base_bbox
        region["image_x"] = image_x
        region["image_y"] = image_y
        region["bbox_image"] = image_bbox
        region["coordinate_space"] = (
            "physical_window" if os.name == "nt" else "base_window"
        )
        if os.name == "nt":
            region["window_x"] = image_x
            region["window_y"] = image_y
            region["bbox_window"] = image_bbox

    return {
        "status": "OK",
        "screenshot_path": str(image_path),
        "regions": regions,
        "region_count": len(regions),
        "segmentation": "eroded" if use_eroded else "raw",
        "raw_region_count": len(raw_regions),
        "eroded_region_count": len(eroded_regions),
        "crop_window": [
            int(round(left / scale_x)),
            int(round(top / scale_y)),
            int(round(right / scale_x)),
            int(round(bottom / scale_y)),
        ],
        "coordinate_scale": {
            "x": round(scale_x, 4),
            "y": round(scale_y, 4),
            "raw_x": round(raw_scale_x, 4),
            "raw_y": round(raw_scale_y, 4),
            "source": scale_source or "raw",
        },
    }


def _lightning_merge_visual_regions(regions: list[dict]) -> list[dict]:
    """Merge same-territory red blobs split by labels/icons or thin overlays."""
    merged = [dict(region) for region in regions]

    def x_overlap(a: dict, b: dict) -> float:
        a0, _a1, a2, _a3 = a["bbox_window"]
        b0, _b1, b2, _b3 = b["bbox_window"]
        return max(0.0, min(a2, b2) - max(a0, b0))

    def y_gap(a: dict, b: dict) -> float:
        _a0, a1, _a2, a3 = a["bbox_window"]
        _b0, b1, _b2, b3 = b["bbox_window"]
        if a3 < b1:
            return b1 - a3
        if b3 < a1:
            return a1 - b3
        return 0.0

    def width(region: dict) -> float:
        x0, _y0, x1, _y1 = region["bbox_window"]
        return max(1.0, x1 - x0)

    def should_merge(a: dict, b: dict) -> bool:
        overlap = x_overlap(a, b)
        min_width = min(width(a), width(b))
        if overlap < min_width * 0.45:
            return False
        center_gap = abs(float(a["window_x"]) - float(b["window_x"]))
        gap = y_gap(a, b)
        if gap == 0:
            return center_gap <= 80
        min_area = min(
            float(a.get("area_window") or 0.0),
            float(b.get("area_window") or 0.0),
        )
        return gap <= 60 and center_gap <= 90 and min_area <= 12000

    def merge_pair(a: dict, b: dict) -> dict:
        area_a = float(a.get("area_px") or 0)
        area_b = float(b.get("area_px") or 0)
        total = max(area_a + area_b, 1.0)
        bbox_a = a["bbox_window"]
        bbox_b = b["bbox_window"]
        area_window = float(a.get("area_window") or 0.0) + float(
            b.get("area_window") or 0.0
        )
        return {
            "window_x": int(
                round(
                    (
                        float(a["window_x"]) * area_a
                        + float(b["window_x"]) * area_b
                    )
                    / total
                )
            ),
            "window_y": int(
                round(
                    (
                        float(a["window_y"]) * area_a
                        + float(b["window_y"]) * area_b
                    )
                    / total
                )
            ),
            "bbox_window": [
                min(bbox_a[0], bbox_b[0]),
                min(bbox_a[1], bbox_b[1]),
                max(bbox_a[2], bbox_b[2]),
                max(bbox_a[3], bbox_b[3]),
            ],
            "area_px": int(area_a + area_b),
            "area_window": round(area_window, 1),
            "merged_parts": int(a.get("merged_parts") or 1)
            + int(b.get("merged_parts") or 1),
        }

    changed = True
    while changed:
        changed = False
        for i, first in enumerate(merged):
            for j in range(i + 1, len(merged)):
                second = merged[j]
                if not should_merge(first, second):
                    continue
                replacement = merge_pair(first, second)
                merged = [
                    region
                    for index, region in enumerate(merged)
                    if index not in {i, j}
                ]
                merged.append(replacement)
                changed = True
                break
            if changed:
                break

    return merged


def _lightning_visual_regions_from_recommendation(recommendation: dict | None) -> dict | None:
    if not recommendation:
        return None
    pause_map_peek = recommendation.get("pause_map_peek") or {}
    screenshot_path = pause_map_peek.get("map_screenshot_path")
    if screenshot_path:
        result = _lightning_extract_red_regions_from_image(screenshot_path)
        if result.get("status") == "OK" and result.get("regions"):
            return _lightning_attach_region_ocr_labels(result, screenshot_path)
    panel_clear = pause_map_peek.get("panel_clear") or {}
    visible_ui = panel_clear.get("visible_ui") or {}
    screenshot_path = visible_ui.get("screenshot_path")
    if not screenshot_path:
        return None
    result = _lightning_extract_red_regions_from_image(screenshot_path)
    if result.get("status") != "OK" or not result.get("regions"):
        return result
    return _lightning_attach_region_ocr_labels(result, screenshot_path)


_LIGHTNING_ROUTE_DEFAULT_START_MODE = "preview-board"
_LIGHTNING_BASELINE_ROUTE_DEFAULT_START_MODE = (
    "dialogue-region-repeat-preview-board"
)
_LIGHTNING_ROUTE_LEGACY_DIALOGUE_BOARD_START_MODES = {
    "dialogue_region_repeat_preview_board",
    "dialogue_region_repeat_preview_board_twice",
    "advisor_region_repeat_preview_board",
    "advisor_region_repeat_preview_board_twice",
    "dialogue_repeat_preview_board",
    "dialogue_repeat_preview_board_twice",
}
_LIGHTNING_FIRST_OPENING_DIALOGUE_START_MODE = (
    "dialogue-region-repeat-preview-board"
)
_LIGHTNING_ROUTE_START_SUBCALL_TIMEOUT_SECONDS = 55.0


def _lightning_effective_route_start_mode(
    start_mode: str | None,
    *,
    route_routing: str,
    include_start_click: bool = True,
    start_window_x: int | None = None,
    start_window_y: int | None = None,
    require_auto_start_safe_preview: bool = False,
    expected_preview_mission: str | None = None,
) -> str:
    """Return the safest route-start mode for the selected routing policy."""
    if start_mode is None:
        requested = (
            _LIGHTNING_BASELINE_ROUTE_DEFAULT_START_MODE
            if str(route_routing or "") == "lightning_baseline"
            else _LIGHTNING_ROUTE_DEFAULT_START_MODE
        )
    else:
        requested = str(start_mode or _LIGHTNING_ROUTE_DEFAULT_START_MODE)
    if (
        start_mode is None
        and str(route_routing or "") == "lightning_war"
        and include_start_click
        and start_window_x is None
        and start_window_y is None
        and _lightning_normalized_route_start_mode(requested)
        in _LIGHTNING_ROUTE_LEGACY_DIALOGUE_BOARD_START_MODES
        and not require_auto_start_safe_preview
    ):
        return "visible-text"
    return requested


def _lightning_forced_preview_route_allowed(
    ranked: list[dict],
    *,
    source: str | None = None,
) -> bool:
    """Allow a single unavoidable bridge preview during Lightning War."""
    if source != "bridge_preview" or len(ranked) != 1:
        return False
    return not _lightning_bridge_preview_option_stale(ranked[0])


def _lightning_bridge_preview_option_stale(option: dict | None) -> bool:
    if not isinstance(option, dict):
        return False
    if option.get("bridge_preview_live") is False:
        return True
    if option.get("bridge_heartbeat_stale") is True:
        return True
    if option.get("bridge_heartbeat_alive") is False:
        return True
    if option.get("bridge_state_fresh") is False:
        return True
    return False


def _lightning_route_identity_exact(identity: dict | None) -> bool:
    if not isinstance(identity, dict):
        return False
    return identity.get("exact") is True and str(identity.get("status") or "") == "exact"


def _lightning_auto_route_identity_block_reason(
    candidate: dict | None,
    *,
    routing: str | None,
) -> str | None:
    """Block real Lightning War auto-start candidates without exact identity."""
    if routing != "lightning_war" or not isinstance(candidate, dict):
        return None
    if (
        str(candidate.get("auto_route_probe") or "") == "live_preview_required"
        and not str(candidate.get("mission_id") or "").strip()
    ):
        return None
    if candidate.get("route_routing") != "lightning_war" and "route_identity" not in candidate:
        return None
    identity = candidate.get("route_identity")
    if not isinstance(identity, dict):
        return "missing_exact_route_identity"
    if _lightning_route_identity_exact(identity):
        return None
    status = str(identity.get("status") or "non_exact_route_identity")
    if _lightning_unassigned_visible_label_live_probe_reason(
        candidate,
        routing=routing,
    ):
        return None
    return f"non_exact_route_identity:{status}"


def _lightning_unassigned_visible_label_live_probe_reason(
    candidate: dict | None,
    *,
    routing: str | None,
) -> str | None:
    """Allow uniquely labeled unassigned regions to prove themselves by preview."""
    if routing != "lightning_war" or not isinstance(candidate, dict):
        return None
    if str(candidate.get("mission_id") or "").strip():
        return None
    identity = candidate.get("route_identity")
    if not isinstance(identity, dict) or _lightning_route_identity_exact(identity):
        return None
    if str(identity.get("status") or "").lower() != "unassigned":
        return None
    if not _lightning_visible_region_label_identity(candidate):
        return None
    return "unassigned_visible_label_live_preview"


