def _lightning_route_auto_start_veto_reason(
    option: dict,
    *,
    routing: str = "lightning_war",
) -> str | None:
    explicit = str(option.get("route_auto_start_veto_reason") or "").strip()
    if explicit:
        return explicit
    mission_id = str(option.get("mission_id") or "").strip()
    if not mission_id:
        return "missing_route_mission_id"
    if routing == "lightning_baseline":
        mission_vetoes = _LIGHTNING_ROUTE_AUTO_START_BASELINE_VETO_MISSIONS
        tag_vetoes = _LIGHTNING_ROUTE_AUTO_START_BASELINE_VETO_TAGS
        veto_prefix = "baseline_vetoed"
    else:
        mission_vetoes = _LIGHTNING_ROUTE_AUTO_START_SPEED_VETO_MISSIONS
        tag_vetoes = _LIGHTNING_ROUTE_AUTO_START_SPEED_VETO_TAGS
        veto_prefix = "vetoed"
    if mission_id in mission_vetoes:
        return f"{veto_prefix}_mission:{mission_id}"
    tags = {
        str(tag)
        for tag in (option.get("mission_tags") or [])
        if str(tag).strip()
    }
    blocked_tags = sorted(tags & tag_vetoes)
    if blocked_tags:
        return f"{veto_prefix}_tags:" + ",".join(blocked_tags)
    try:
        bonus_ids = {int(value) for value in (option.get("bonus_objective_ids") or [])}
    except (TypeError, ValueError):
        bonus_ids = set()
    blocked_bonuses = sorted(bonus_ids & _LIGHTNING_ROUTE_AUTO_START_VETO_BONUS_IDS)
    if blocked_bonuses:
        return f"{veto_prefix}_bonus_ids:" + ",".join(
            str(value) for value in blocked_bonuses
        )
    return None


def _lightning_speed_route_status(
    ranked: list[dict],
    routing: str,
    *,
    source: str | None = None,
) -> dict | None:
    """Summarize whether the top Lightning route is fast enough to auto-start."""
    if routing not in {"lightning_war", "lightning_baseline"}:
        return None
    if not ranked:
        return {
            "status": "NO_ROUTE",
            "auto_start_allowed": False,
            "reason": "no_ranked_missions",
        }
    top = ranked[0]
    score = top.get("score")
    boss = bool(top.get("boss")) or str(top.get("mission_id") or "").endswith("Boss")
    forced_preview_allowed = _lightning_forced_preview_route_allowed(
        ranked,
        source=source,
    )
    veto_reason = None if boss else _lightning_route_auto_start_veto_reason(
        top,
        routing=routing,
    )
    if forced_preview_allowed and routing != "lightning_baseline":
        veto_reason = None
    if veto_reason:
        return {
            "status": "AUTO_START_BLOCKED",
            "auto_start_allowed": False,
            "reason": veto_reason,
            "top_score": score,
            "top_mission_id": top.get("mission_id"),
            "top_save_region_name": top.get("save_region_name"),
        }
    stale_bridge_preview = (
        source == "bridge_preview"
        and len(ranked) == 1
        and _lightning_bridge_preview_option_stale(top)
    )
    if stale_bridge_preview:
        return {
            "status": "AUTO_START_BLOCKED",
            "auto_start_allowed": False,
            "reason": "stale_bridge_preview",
            "top_score": score,
            "top_mission_id": top.get("mission_id"),
            "top_save_region_name": top.get("save_region_name"),
        }
    return {
        "status": "AUTO_START_OK",
        "auto_start_allowed": True,
        "reason": (
            "forced_boss_route"
            if boss
            else "forced_bridge_preview_route"
            if forced_preview_allowed
            else f"{routing}_no_mission_veto"
        ),
        "top_score": score,
        "top_mission_id": top.get("mission_id"),
        "top_save_region_name": top.get("save_region_name"),
    }


def _lightning_preview_can_override_stale_route_target(
    preview_recommendation: dict,
    actual_preview_mission: str | None,
) -> bool:
    """Trust a live bridge boss preview over stale save-map assignment."""
    if not actual_preview_mission:
        return False
    if preview_recommendation.get("source") != "bridge_preview":
        return False
    top3 = preview_recommendation.get("top3")
    if not isinstance(top3, list) or not top3 or not isinstance(top3[0], dict):
        return False
    top = top3[0]
    if str(top.get("mission_id") or "").strip() != actual_preview_mission:
        return False
    speed_status = preview_recommendation.get("speed_route_status")
    boss = bool(top.get("boss")) or actual_preview_mission.endswith("Boss")
    return (
        boss
        and isinstance(speed_status, dict)
        and speed_status.get("reason") == "forced_boss_route"
    )


def _lightning_auto_start_preview_block_reason(
    preview_recommendation: dict,
    actual_preview_mission: str | None,
    *,
    routing: str = "lightning_war",
    allow_unknown_lightning_war_preview: bool = False,
) -> str | None:
    """Return why an unlabeled live preview is unsafe to auto-start."""
    mission_id = str(actual_preview_mission or "").strip()
    if not mission_id:
        if routing == "lightning_war" and allow_unknown_lightning_war_preview:
            return None
        return "missing_route_mission_id"
    preview_source = str(preview_recommendation.get("source") or "").strip()
    top: dict = {"mission_id": mission_id}
    top3 = preview_recommendation.get("top3")
    if isinstance(top3, list) and top3 and isinstance(top3[0], dict):
        top_mission = str(top3[0].get("mission_id") or "").strip()
        if top_mission == mission_id:
            top = dict(top3[0])
            top["mission_id"] = mission_id

    boss = bool(top.get("boss")) or mission_id.endswith("Boss")
    if boss:
        return None
    if preview_source == "visible_preview_ocr":
        visible_preview_ocr = preview_recommendation.get("visible_preview_ocr")
        if (
            isinstance(visible_preview_ocr, dict)
            and visible_preview_ocr.get("status") == "OK"
            and visible_preview_ocr.get("source") == "visible_preview_ocr"
            and str(visible_preview_ocr.get("mission_id") or "").strip()
            == mission_id
        ):
            early_veto = _lightning_route_auto_start_veto_reason(
                top,
                routing=routing,
            )
            if early_veto:
                return early_veto
    if not _lightning_route_preview_source_verified(
        preview_recommendation,
        mission_id,
        routing=routing,
    ):
        return f"unverified_preview_source:{preview_source or 'unknown'}"
    return _lightning_route_auto_start_veto_reason(top, routing=routing)


def _lightning_visible_preview_ocr_start_authorized(
    visible_preview_ocr: Any,
    mission_id: str | None,
    *,
    routing: str = "lightning_war",
) -> bool:
    """Permit OCR-only preview starts for narrow, policy-safe route cases."""
    if not isinstance(visible_preview_ocr, dict):
        return False
    if visible_preview_ocr.get("status") != "OK":
        return False
    if visible_preview_ocr.get("source") != "visible_preview_ocr":
        return False
    ocr_mission = str(visible_preview_ocr.get("mission_id") or "").strip()
    if not ocr_mission or ocr_mission != str(mission_id or "").strip():
        return False
    if routing not in {"lightning_baseline", "lightning_war"}:
        return False
    return (
        _lightning_route_auto_start_veto_reason(
            {"mission_id": ocr_mission},
            routing=routing,
        )
        is None
    )


def _lightning_visible_preview_generic_label_start_authorized(
    visible_preview_ocr: Any,
    mission_id: str | None,
    *,
    selected_visual_region: dict | None,
    visual_regions: dict | None,
    routing: str = "lightning_war",
) -> bool:
    """Permit speed starts when generic preview OCR is tied to a unique map label."""
    if routing != "lightning_war":
        return False
    if str(mission_id or "").strip() != "Mission_GenericThreat":
        return False
    if not isinstance(visible_preview_ocr, dict):
        return False
    if visible_preview_ocr.get("status") != "OK":
        return False
    if visible_preview_ocr.get("source") != "visible_preview_ocr":
        return False
    if str(visible_preview_ocr.get("mission_id") or "").strip() != "Mission_GenericThreat":
        return False
    if not isinstance(selected_visual_region, dict):
        return False
    label_key = _lightning_visible_region_label_identity(selected_visual_region)
    if not label_key:
        return False
    spaced_label = _lightning_region_ocr_label_key(
        selected_visual_region.get("visible_label"),
    )
    for text in selected_visual_region.get("visible_label_texts") or []:
        spaced_label = f"{spaced_label} {_lightning_region_ocr_label_key(text)}".strip()
    if any(keyword in spaced_label for keyword in _LIGHTNING_ROUTE_GENERIC_OCR_LABEL_BLOCK_KEYWORDS):
        return False
    route_option = selected_visual_region.get("route_option")
    if isinstance(route_option, dict) and _lightning_route_auto_start_veto_reason(
        route_option,
        routing=routing,
    ):
        return False
    regions = (
        visual_regions.get("regions")
        if isinstance(visual_regions, dict)
        else []
    )
    concrete_regions = [region for region in regions if isinstance(region, dict)]
    if len(concrete_regions) <= 1:
        return True
    labels = [_lightning_visible_region_label_identity(region) for region in concrete_regions]
    return bool(
        all(labels)
        and len(set(str(label) for label in labels)) == len(labels)
        and label_key in set(str(label) for label in labels)
    )


def _lightning_baseline_expected_preview_unknown_authorized(
    *,
    expected_preview_mission: str,
    actual_preview_mission: str | None,
    visible_preview_ocr: Any,
    selected_visual_region: dict | None,
    route_target_hint: dict | None,
    visual_regions: dict | None,
    routing: str,
) -> bool:
    """Allow baseline starts when save-backed region proof beats silent OCR."""
    expected = str(expected_preview_mission or "").strip()
    if routing != "lightning_baseline" or not expected:
        return False
    if _lightning_route_auto_start_veto_reason(
        {"mission_id": expected},
        routing=routing,
    ):
        return False
    actual = str(actual_preview_mission or "").strip()
    if actual and actual != expected:
        return False
    if isinstance(visible_preview_ocr, dict):
        ocr_mission = str(visible_preview_ocr.get("mission_id") or "").strip()
        if ocr_mission and ocr_mission != expected:
            return False
    if not isinstance(selected_visual_region, dict):
        return False
    route_option = selected_visual_region.get("route_option")
    if (
        isinstance(route_option, dict)
        and str(route_option.get("mission_id") or "").strip() == expected
    ):
        return True
    if (
        isinstance(route_target_hint, dict)
        and str(route_target_hint.get("mission_id") or "").strip() == expected
    ):
        regions = (
            visual_regions.get("regions")
            if isinstance(visual_regions, dict)
            else []
        )
        concrete_regions = [region for region in regions if isinstance(region, dict)]
        return len(concrete_regions) == 1
    return False


def _lightning_route_preview_source_verified(
    preview_recommendation: dict | None,
    actual_preview_mission: str | None,
    *,
    routing: str = "lightning_war",
) -> bool:
    """Return true when preview evidence is strong enough to apply route policy."""
    if not isinstance(preview_recommendation, dict):
        return False
    mission_id = str(actual_preview_mission or "").strip()
    if not mission_id:
        return False
    preview_source = str(preview_recommendation.get("source") or "").strip()
    if preview_source == "bridge_preview":
        return not _lightning_bridge_preview_recommendation_stale(
            preview_recommendation,
        )
    if preview_source == "bridge":
        return preview_recommendation.get("bridge_refresh_ok") is not False
    if (
        preview_source == "visible_preview_ocr"
        and preview_recommendation.get(
            "visible_preview_generic_label_start_authorized",
        )
        is True
    ):
        return True
    return _lightning_visible_preview_ocr_start_authorized(
        preview_recommendation.get("visible_preview_ocr"),
        mission_id,
        routing=routing,
    )


def _lightning_unassigned_multi_region_preview_block_reason(
    visual_regions: dict | None,
    selected_visual_region: dict | None,
) -> str | None:
    """Block unlabeled auto-starts when a preview cannot prove the clicked region."""
    if not isinstance(visual_regions, dict) or visual_regions.get("status") != "OK":
        return None
    regions = [
        region
        for region in (visual_regions.get("regions") or [])
        if isinstance(region, dict)
    ]
    if len(regions) <= 1:
        return None
    if not isinstance(selected_visual_region, dict):
        return "unassigned_multi_region_preview"
    route_option = selected_visual_region.get("route_option")
    if (
        isinstance(route_option, dict)
        and str(route_option.get("mission_id") or "").strip()
    ):
        return None
    selected_label = _lightning_visible_region_label_identity(selected_visual_region)
    if selected_label:
        labels = [
            _lightning_visible_region_label_identity(region)
            for region in regions
        ]
        if (
            all(label for label in labels)
            and len(set(str(label) for label in labels)) == len(labels)
        ):
            return None
    return "unassigned_multi_region_preview"


def _lightning_recommend_save_routes(
    profile: str = "Alpha",
    *,
    routing: str = "lightning_war",
) -> dict:
    """Score the current save-backed island route options without bridge IO."""
    from src.strategy.mission_picker import score_island_map

    save_result = _lightning_build_save_island_map(profile)
    island_map = save_result.get("island_map") or []
    if not island_map:
        return {
            "status": "NO_ISLAND_MAP",
            "source": "saveData",
            "routing": routing,
            "ranked": [],
            "top3": [],
            "save_island_map": save_result,
            "speed_route_status": _lightning_speed_route_status([], routing),
        }
    try:
        ranked = score_island_map(
            island_map,
            save_result.get("units") or [],
            int(save_result.get("grid_power") or 7),
            routing=routing,
        )
    except ValueError as exc:
        return {"status": "ERROR", "source": "saveData", "error": str(exc)}
    return {
        "status": "OK" if ranked else "NO_AVAILABLE_MISSIONS",
        "source": "saveData",
        "routing": routing,
        "grid_power": save_result.get("grid_power"),
        "available": len(island_map),
        "ranked": ranked,
        "top3": ranked[:3],
        "save_island_map": save_result,
        "speed_route_status": _lightning_speed_route_status(
            ranked,
            routing,
            source="saveData",
        ),
    }


def _lightning_route_options_for_visual_assignment(
    recommendation: dict | None,
) -> list[dict]:
    """Return ranked save-backed routes in visual-map order."""
    if not isinstance(recommendation, dict):
        return []
    ranked = recommendation.get("ranked")
    if not isinstance(ranked, list):
        return []

    def route_region_index(option: dict) -> int | None:
        for key in ("save_region_index", "region_id"):
            if option.get(key) is None:
                continue
            try:
                return int(option[key])
            except (TypeError, ValueError):
                continue
        return None

    options = []
    for option in ranked:
        if not isinstance(option, dict):
            continue
        region_index = route_region_index(option)
        if region_index is None:
            continue
        out = dict(option)
        out.setdefault("save_region_index", region_index)
        out.setdefault("region_id", region_index)
        options.append(out)
    options.sort(
        key=lambda option: (
            int(option.get("save_region_index") or 0),
            str(option.get("save_region_name") or ""),
        )
    )
    return options


def _lightning_visual_route_signature(
    region: dict,
    *,
    visual_order: int | None = None,
) -> dict:
    """Small stable witness for the visual blob a route identity was assigned to."""
    signature = {
        key: region.get(key)
        for key in (
            "index",
            "window_x",
            "window_y",
            "area_window",
            "area_px",
            "bbox_window",
        )
        if region.get(key) is not None
    }
    if visual_order is not None:
        signature["visual_order"] = int(visual_order)
    return signature


def _lightning_route_identity(
    *,
    recommendation: dict | None,
    assignment_status: str,
    assignment_method: str,
    visual_signature: dict,
    route_option: dict | None = None,
    identity_status: str | None = None,
    exact: bool = False,
    reason: str | None = None,
) -> dict:
    """Describe how strongly a visible route blob is tied to a mission."""
    source = (
        recommendation.get("source")
        if isinstance(recommendation, dict)
        else None
    )
    routing = (
        recommendation.get("routing")
        if isinstance(recommendation, dict)
        else None
    )
    identity = {
        "status": identity_status or ("exact" if exact else "diagnostic"),
        "exact": bool(exact),
        "assignment_status": assignment_status,
        "assignment_method": assignment_method,
        "assignment_source": source,
        "routing": routing,
        "visual_signature": dict(visual_signature),
    }
    if reason:
        identity["reason"] = reason
    if isinstance(route_option, dict):
        for key in (
            "mission_id",
            "mission_slot",
            "mission_index",
            "region_id",
            "save_region_index",
            "save_region_name",
            "source",
        ):
            if route_option.get(key) is not None:
                identity[key] = route_option.get(key)
    return {key: value for key, value in identity.items() if value is not None}


def _lightning_assign_visual_route_options(
    visual_regions: dict | None,
    recommendation: dict | None,
) -> dict | None:
    """Attach save-backed mission ids to red blobs when counts line up."""
    if not isinstance(visual_regions, dict) or visual_regions.get("status") != "OK":
        return visual_regions
    regions = visual_regions.get("regions")
    if not isinstance(regions, list) or not regions:
        return visual_regions
    options = _lightning_route_options_for_visual_assignment(recommendation)
    if not options:
        return visual_regions

    out = dict(visual_regions)
    out_regions = [dict(region) for region in regions if isinstance(region, dict)]
    source = (
        recommendation.get("source")
        if isinstance(recommendation, dict)
        else None
    )
    exact_assignment = source == "saveData"

    option_by_label: dict[str, dict] = {}
    duplicate_option_labels: set[str] = set()
    for option in options:
        label_key = _lightning_region_label_match_key(
            option.get("save_region_name"),
        )
        if not label_key:
            continue
        if label_key in option_by_label:
            duplicate_option_labels.add(label_key)
            continue
        option_by_label[label_key] = option
    for key in duplicate_option_labels:
        option_by_label.pop(key, None)

    label_matches: list[tuple[int, dict, str]] = []
    used_label_options: set[int] = set()
    label_assignment_failed = False
    if option_by_label:
        for visual_order, region in enumerate(out_regions):
            label_key = _lightning_visible_region_label_identity(region)
            if not label_key or label_key not in option_by_label:
                label_assignment_failed = True
                break
            option = option_by_label[label_key]
            option_id = id(option)
            if option_id in used_label_options:
                label_assignment_failed = True
                break
            used_label_options.add(option_id)
            label_matches.append((visual_order, option, label_key))
    if (
        label_matches
        and not label_assignment_failed
        and len(label_matches) == len(out_regions)
    ):
        for visual_order, option, _label_key in label_matches:
            region = out_regions[visual_order]
            region["route_option"] = {
                key: option.get(key)
                for key in (
                    "mission_id",
                    "mission_slot",
                    "mission_index",
                    "region_id",
                    "save_region_index",
                    "save_region_name",
                    "score",
                    "boss",
                    "source",
                    "routing",
                    "mission_tags",
                    "bonus_objective_ids",
                    "route_auto_start_veto_reason",
                )
                if option.get(key) is not None
            }
            if (
                isinstance(recommendation, dict)
                and recommendation.get("routing") is not None
            ):
                region["route_option"].setdefault(
                    "routing",
                    recommendation.get("routing"),
                )
            region["route_identity"] = _lightning_route_identity(
                recommendation=recommendation,
                assignment_status="OK",
                assignment_method="visible_ocr_label_to_save_region_name",
                visual_signature=_lightning_visual_route_signature(
                    region,
                    visual_order=visual_order,
                ),
                route_option=region["route_option"],
                identity_status="exact" if exact_assignment else "diagnostic",
                exact=exact_assignment,
                reason=None if exact_assignment else "non_save_assignment_source",
            )
        out["regions"] = out_regions
        out["route_assignment"] = {
            "status": "OK",
            "method": "visible_ocr_label_to_save_region_name",
            "visual_regions": len(out_regions),
            "save_route_options": len(options),
            "matched_visible_labels": len(label_matches),
        }
        return out

    if len(out_regions) != len(options):
        for visual_order, region in enumerate(out_regions):
            region["route_identity"] = _lightning_route_identity(
                recommendation=recommendation,
                assignment_status="COUNT_MISMATCH",
                assignment_method="save_region_index_to_visual_order",
                visual_signature=_lightning_visual_route_signature(
                    region,
                    visual_order=visual_order,
                ),
                identity_status="count_mismatch",
                exact=False,
                reason="visual_region_count_does_not_match_save_route_options",
            )
        out["route_assignment"] = {
            "status": "COUNT_MISMATCH",
            "method": "save_region_index_to_visual_order",
            "visual_regions": len(out_regions),
            "save_route_options": len(options),
        }
        out["regions"] = out_regions
        return out

    for visual_order, (region, option) in enumerate(zip(out_regions, options)):
        region["route_option"] = {
            key: option.get(key)
            for key in (
                "mission_id",
                "mission_slot",
                "mission_index",
                "region_id",
                "save_region_index",
                "save_region_name",
                "score",
                "boss",
                "source",
                "routing",
                "mission_tags",
                "bonus_objective_ids",
                "route_auto_start_veto_reason",
            )
            if option.get(key) is not None
        }
        if (
            isinstance(recommendation, dict)
            and recommendation.get("routing") is not None
        ):
            region["route_option"].setdefault("routing", recommendation.get("routing"))
        region["route_identity"] = _lightning_route_identity(
            recommendation=recommendation,
            assignment_status="OK",
            assignment_method="save_region_index_to_visual_order",
            visual_signature=_lightning_visual_route_signature(
                region,
                visual_order=visual_order,
            ),
            route_option=region["route_option"],
            identity_status="exact" if exact_assignment else "diagnostic",
            exact=exact_assignment,
            reason=None if exact_assignment else "non_save_assignment_source",
        )
    out["regions"] = out_regions
    out["route_assignment"] = {
        "status": "OK",
        "method": "save_region_index_to_visual_order",
        "visual_regions": len(out_regions),
        "save_route_options": len(options),
    }
    return out


def _lightning_red_regions_have_route_labels(red_regions: dict | None) -> bool:
    if not isinstance(red_regions, dict) or red_regions.get("status") != "OK":
        return False
    regions = red_regions.get("regions")
    if not isinstance(regions, list) or len(regions) < 2:
        return False
    labeled = 0
    for region in regions:
        if not isinstance(region, dict):
            continue
        label = str(region.get("visible_label") or "").strip()
        texts = region.get("visible_label_texts")
        if label or (isinstance(texts, list) and any(str(t).strip() for t in texts)):
            labeled += 1
    return labeled >= 2


def _lightning_map_region_screen_guard(
    image_path: str | Path,
    *,
    red_regions: dict | None = None,
) -> dict | None:
    """Return a blocking guard when a screenshot is not a clean island map."""
    visible_ui = _classify_lightning_ui_image(image_path)
    if not isinstance(visible_ui, dict) or visible_ui.get("status") != "OK":
        return None
    visible_name = str(visible_ui.get("visible_ui") or "")
    if visible_name == "pause_menu":
        return {
            "status": "BLOCKED",
            "reason": "pause_menu_visible",
            "visible_ui": visible_name,
            "confidence": visible_ui.get("confidence"),
            "next_step": (
                "Resume briefly, capture a clean island-map screenshot, then "
                "rerun lightning_map_regions."
            ),
        }
    if visible_name == "mission_preview_panel":
        return {
            "status": "BLOCKED",
            "reason": "mission_preview_panel_visible",
            "visible_ui": visible_name,
            "confidence": visible_ui.get("confidence"),
            "recommended_control": visible_ui.get("recommended_control"),
            "next_step": (
                "Do not derive route candidates from an open mission preview; "
                "dismiss or reselect the preview first."
            ),
        }

    scores = visible_ui.get("scores")
    if not isinstance(scores, dict):
        return None
    preview = scores.get("mission_preview_dialogue")
    if not isinstance(preview, dict):
        return None
    card = preview.get("card")
    if not isinstance(card, dict):
        card = {}
    dialogue = preview.get("dialogue")
    if not isinstance(dialogue, dict):
        dialogue = {}
    try:
        preview_score = float(preview.get("score") or 0.0)
        card_blue = int(card.get("blue") or 0)
        card_bright = int(card.get("bright") or 0)
        card_dark = float(card.get("dark_fraction") or 0.0)
        dialogue_red = int(dialogue.get("red") or 0)
    except (TypeError, ValueError):
        return None

    # A selected island mission shows a dark hover/preview card over the map.
    # Red-region extraction still sees blobs behind it, but visual-order route
    # assignment can be wrong because the card occludes/splits the regions.
    # Plain route maps can also produce a noisy advisor-preview score from
    # large red regions plus tooltips; visible OCR labels on multiple regions
    # prove this is still a clean map.
    if (
        visible_name in {"island_map", "island_map_or_unknown"}
        and not _lightning_red_regions_have_route_labels(red_regions)
        and preview_score >= 0.30
        and card_bright >= 2500
        and card_blue >= 2000
        and card_dark >= 0.20
        and dialogue_red >= 4000
    ):
        return {
            "status": "BLOCKED",
            "reason": "route_preview_card_visible",
            "visible_ui": visible_name,
            "preview_score": preview_score,
            "card_blue": card_blue,
            "card_bright": card_bright,
            "card_dark_fraction": card_dark,
            "dialogue_red": dialogue_red,
            "next_step": (
                "Dismiss the open route preview or use a reselect start mode, "
                "then capture a clean map before emitting route candidates."
            ),
        }
    return None


def _lightning_candidate_auto_block_reason(
    candidate: dict,
    *,
    routing: str = "lightning_war",
) -> str | None:
    option = candidate.get("route_option") or {}
    if candidate.get("forced_preview_ambiguous"):
        return "forced_bridge_preview_multiple_visible_regions"
    if not option.get("mission_id"):
        return "missing_route_mission_id"
    if candidate.get("forced_preview_route") and not candidate.get(
        "forced_preview_ambiguous"
    ):
        return None
    return _lightning_route_auto_start_veto_reason(option, routing=routing)


def _lightning_candidate_auto_allowed(
    candidate: dict,
    *,
    routing: str = "lightning_war",
) -> bool:
    return _lightning_candidate_auto_block_reason(
        candidate,
        routing=routing,
    ) is None


def _lightning_candidate_score(candidate: dict) -> float:
    try:
        return float(candidate.get("score"))
    except (TypeError, ValueError):
        return -9999.0


def _lightning_route_start_candidates(
    visual_regions: dict | None,
    *,
    start_mode: str = _LIGHTNING_ROUTE_DEFAULT_START_MODE,
    target_hint: dict | None = None,
    recommendation: dict | None = None,
) -> list[dict]:
    """Return ready-to-run route handoff commands for detected map regions."""
    visual_regions = _lightning_assign_visual_route_options(
        visual_regions,
        recommendation,
    )
    if not isinstance(visual_regions, dict):
        return []
    if visual_regions.get("status") != "OK":
        return []
    ranked = (
        recommendation.get("ranked")
        if isinstance(recommendation, dict)
        else None
    )
    forced_preview_allowed = (
        isinstance(ranked, list)
        and _lightning_forced_preview_route_allowed(
            [entry for entry in ranked if isinstance(entry, dict)],
            source=(
                str(recommendation.get("source"))
                if isinstance(recommendation, dict)
                and recommendation.get("source") is not None
                else None
            ),
        )
    )
    recommendation_source = (
        str(recommendation.get("source"))
        if isinstance(recommendation, dict)
        and recommendation.get("source") is not None
        else None
    )
    route_routing = (
        str(recommendation.get("routing") or "lightning_war")
        if isinstance(recommendation, dict)
        else "lightning_war"
    )
    regions = [
        region
        for region in (visual_regions.get("regions") or [])
        if isinstance(region, dict)
    ]
    forced_preview_ambiguous = forced_preview_allowed and len(regions) != 1
    bridge_preview_ambiguous = (
        recommendation_source == "bridge_preview" and len(regions) != 1
    )
    target_hint_can_guard = len(regions) == 1 and not bridge_preview_ambiguous
    forced_preview_option = (
        dict(ranked[0])
        if forced_preview_allowed
        and not forced_preview_ambiguous
        and isinstance(ranked, list)
        and ranked
        and isinstance(ranked[0], dict)
        else None
    )
    route_assignment = (
        visual_regions.get("route_assignment")
        if isinstance(visual_regions.get("route_assignment"), dict)
        else {}
    )
    candidates: list[dict] = []
    for visual_order, region in enumerate(regions):
        visual_window_x = region.get("window_x")
        visual_window_y = region.get("window_y")
        window_x = region.get("click_window_x")
        window_y = region.get("click_window_y")
        if route_routing == "lightning_war" and isinstance(visual_window_x, int) and isinstance(visual_window_y, int):
            # OCR-label interior clicks are useful evidence, but the measured
            # Lightning opener is more reliable when the first timed click lands
            # on the red body/visual center of the region.
            window_x = visual_window_x
            window_y = visual_window_y
        elif not isinstance(window_x, int) or not isinstance(window_y, int):
            window_x = visual_window_x
            window_y = visual_window_y
        if not isinstance(window_x, int) or not isinstance(window_y, int):
            continue
        region_index = region.get("index", len(candidates))
        route_option = region.get("route_option")
        expected_mission_id = None
        if isinstance(route_option, dict):
            expected_mission_id = route_option.get("mission_id")
        if expected_mission_id is None and target_hint_can_guard and isinstance(
            target_hint,
            dict,
        ):
            expected_mission_id = target_hint.get("mission_id")
        route_target_arg = (
            f"--route-target-mission-id {expected_mission_id} "
            if expected_mission_id else ""
        )
        route_start_target_arg = (
            f"--expected-mission-id {expected_mission_id} "
            if expected_mission_id else ""
        )
        route_start_command = (
            "python3 game_loop.py lightning_route_start "
            f"--visual-region-index {region_index} "
            f"{route_start_target_arg}"
            f"--route-routing {route_routing} "
            f"--start-mode {start_mode}"
        )
        coordinate_command = (
            "python3 game_loop.py lightning_route_start "
            "--no-route-check "
            f"--window-x {window_x} --window-y {window_y} "
            f"{route_start_target_arg}"
            f"--route-routing {route_routing} "
            f"--start-mode {start_mode}"
        )
        if isinstance(region_index, int):
            command = (
                "python3 game_loop.py lightning_segment "
                f"--route-visual-region-index {region_index} "
                f"{route_target_arg}"
                f"--route-routing {route_routing} "
                f"--route-start-mode {start_mode}"
            )
        else:
            command = coordinate_command
            route_start_command = coordinate_command
        candidate = {
            "index": region_index,
            "window_x": window_x,
            "window_y": window_y,
            "command": command,
            "route_start_command": route_start_command,
            "coordinate_command": coordinate_command,
            "route_routing": route_routing,
        }
        if isinstance(visual_window_x, int) and isinstance(visual_window_y, int):
            candidate["visual_region_window_x"] = visual_window_x
            candidate["visual_region_window_y"] = visual_window_y
        if isinstance(region.get("route_click_target"), dict):
            candidate["route_click_target"] = dict(region["route_click_target"])
        if isinstance(region.get("route_click_target_label_below"), dict):
            candidate["route_click_target_label_below"] = dict(
                region["route_click_target_label_below"],
            )
        for label_key in (
            "visible_label",
            "visible_label_texts",
            "visible_label_source",
        ):
            if region.get(label_key) is not None:
                candidate[label_key] = region.get(label_key)
        if isinstance(region.get("route_identity"), dict):
            candidate["route_identity"] = dict(region["route_identity"])
        elif isinstance(recommendation, dict):
            candidate["route_identity"] = _lightning_route_identity(
                recommendation=recommendation,
                assignment_status=str(
                    route_assignment.get("status") or "UNASSIGNED",
                ),
                assignment_method=str(
                    route_assignment.get("method") or "no_route_option_assignment",
                ),
                visual_signature=_lightning_visual_route_signature(
                    region,
                    visual_order=visual_order,
                ),
                identity_status="unassigned",
                exact=False,
                reason="no_route_option_assigned_to_visual_region",
            )
        if isinstance(route_option, dict) and route_option:
            candidate["route_option"] = dict(route_option)
            candidate["visual_order"] = visual_order
            candidate["mission_id"] = route_option.get("mission_id")
            candidate["save_region_index"] = route_option.get("save_region_index")
            candidate["save_region_name"] = route_option.get("save_region_name")
            candidate["score"] = route_option.get("score")
            candidate["auto_route_allowed"] = _lightning_candidate_auto_allowed(
                candidate,
                routing=route_routing,
            )
            if not candidate["auto_route_allowed"]:
                candidate["auto_route_block_reason"] = (
                    _lightning_candidate_auto_block_reason(
                        candidate,
                        routing=route_routing,
                    )
                )
        elif forced_preview_option is not None:
            candidate["route_option"] = dict(forced_preview_option)
            candidate["route_identity"] = _lightning_route_identity(
                recommendation=recommendation,
                assignment_status="FORCED_PREVIEW",
                assignment_method="single_visible_forced_preview",
                visual_signature=_lightning_visual_route_signature(
                    region,
                    visual_order=visual_order,
                ),
                route_option=forced_preview_option,
                identity_status="diagnostic",
                exact=False,
                reason="forced_preview_single_visible_region",
            )
            candidate["visual_order"] = visual_order
            candidate["mission_id"] = forced_preview_option.get("mission_id")
            candidate["score"] = forced_preview_option.get("score")
            candidate["forced_preview_route"] = True
            candidate["auto_route_allowed"] = _lightning_candidate_auto_allowed(
                candidate,
                routing=route_routing,
            )
            if not candidate["auto_route_allowed"]:
                candidate["auto_route_block_reason"] = (
                    _lightning_candidate_auto_block_reason(
                        candidate,
                        routing=route_routing,
                    )
                )
        elif forced_preview_ambiguous and isinstance(ranked, list) and ranked:
            top = ranked[0]
            if isinstance(top, dict):
                candidate["route_identity"] = _lightning_route_identity(
                    recommendation=recommendation,
                    assignment_status="AMBIGUOUS_FORCED_PREVIEW",
                    assignment_method="forced_preview_without_single_visible_region",
                    visual_signature=_lightning_visual_route_signature(
                        region,
                        visual_order=visual_order,
                    ),
                    route_option=top,
                    identity_status="ambiguous",
                    exact=False,
                    reason="forced_preview_multiple_visible_regions",
                )
                candidate["visual_order"] = visual_order
                candidate["bridge_preview_candidate_mission_id"] = top.get(
                    "mission_id",
                )
                candidate["bridge_preview_candidate_score"] = top.get("score")
                candidate["score"] = top.get("score")
                candidate["forced_preview_route"] = True
                candidate["forced_preview_ambiguous"] = True
                candidate["auto_route_allowed"] = _lightning_candidate_auto_allowed(
                    candidate,
                    routing=route_routing,
                )
                if not candidate["auto_route_allowed"]:
                    candidate["auto_route_block_reason"] = (
                        _lightning_candidate_auto_block_reason(
                            candidate,
                            routing=route_routing,
                        )
                        or "forced_bridge_preview_multiple_visible_regions"
                    )
        if target_hint:
            candidate["target_hint"] = dict(target_hint)
        candidates.append(candidate)
    if any("route_option" in candidate for candidate in candidates):
        candidates.sort(
            key=lambda candidate: (
                not bool(candidate.get("auto_route_allowed")),
                -_lightning_candidate_score(candidate),
                int(candidate.get("visual_order") or 0),
            )
        )
    return candidates


def _lightning_route_target_hint_from_recommendation(
    recommendation: dict | None,
) -> dict | None:
    """Compact the top recommended mission into a visual matching hint."""
    if not isinstance(recommendation, dict):
        return None
    top3 = recommendation.get("top3")
    if not isinstance(top3, list) or not top3:
        return None
    first = top3[0]
    if not isinstance(first, dict):
        return None
    fields = (
        "mission_id",
        "region_id",
        "save_region_name",
        "save_region_index",
        "save_region_state_label",
        "environment",
        "score",
    )
    hint = {key: first.get(key) for key in fields if first.get(key) is not None}
    if not hint:
        return None
    label = (
        hint.get("save_region_name")
        or hint.get("mission_id")
        or f"region {hint.get('region_id')}"
    )
    hint["match_label"] = str(label)
    return hint


def _lightning_route_target_hint_from_args(
    *,
    target_name: str | None = None,
    target_mission_id: str | None = None,
    target_region_id: int | None = None,
) -> dict | None:
    """Build an operator-provided visual matching hint for screenshot routing."""
    hint: dict = {}
    if target_name:
        hint["save_region_name"] = str(target_name)
    if target_mission_id:
        hint["mission_id"] = str(target_mission_id)
    if target_region_id is not None:
        hint["region_id"] = int(target_region_id)
    if not hint:
        return None
    hint["match_label"] = str(
        hint.get("save_region_name")
        or hint.get("mission_id")
        or f"region {hint.get('region_id')}"
    )
    return hint


def _lightning_attach_primary_route_candidate(
    result: dict,
    route_candidates: list[dict],
) -> dict:
    """Promote the first route candidate to a compact timed-run shortcut."""
    if not route_candidates:
        return result
    first = route_candidates[0]
    if not isinstance(first, dict):
        return result
    route_routing = str(
        result.get("route_routing")
        or first.get("route_routing")
        or ""
    )
    identityless_candidates = []
    for candidate in route_candidates:
        if not isinstance(candidate, dict):
            continue
        identity = candidate.get("route_identity")
        has_exact_identity = (
            isinstance(identity, dict)
            and (
                identity.get("exact") is True
                or str(identity.get("status") or "").lower() == "exact"
            )
        )
        target_hint = candidate.get("target_hint")
        hint_has_mission = (
            isinstance(target_hint, dict)
            and bool(target_hint.get("mission_id"))
        )
        route_option = candidate.get("route_option")
        option_has_mission = (
            isinstance(route_option, dict)
            and bool(route_option.get("mission_id"))
        )
        has_route_identity = any(
            (
                candidate.get("mission_id"),
                candidate.get("save_region_index") is not None,
                candidate.get("save_region_name"),
                has_exact_identity,
                hint_has_mission,
                option_has_mission,
            )
        )
        if not has_route_identity:
            identityless_candidates.append(candidate)
    if (
        route_routing == "lightning_war"
        and len(route_candidates) > 1
        and len(identityless_candidates) == len(route_candidates)
    ):
        result["primary_route_candidate"] = {
            "auto_route_allowed": False,
            "auto_route_block_reason": "multi_region_route_identity_unassigned",
            "route_routing": route_routing,
            "candidate_count": len(route_candidates),
            "candidate_indices": [
                candidate.get("index")
                for candidate in route_candidates
                if isinstance(candidate, dict)
                and candidate.get("index") is not None
            ],
        }
        result["primary_route_block_reason"] = (
            "multi_region_route_identity_unassigned"
        )
        result["next_step"] = (
            "Do not start a Lightning War route from these unassigned visual "
            "regions. Capture/derive route identity first, or restart through "
            "the Lightning runner."
        )
        return result
    command = first.get("command")
    if command:
        result["primary_next_command"] = command
    if first.get("index") is not None:
        result["primary_route_candidate_index"] = first.get("index")
    result["primary_route_candidate"] = {
        key: first.get(key)
        for key in (
            "index",
            "window_x",
            "window_y",
            "mission_id",
            "save_region_index",
            "save_region_name",
            "score",
            "auto_route_allowed",
            "auto_route_block_reason",
            "forced_preview_route",
            "forced_preview_ambiguous",
            "auto_route_probe",
            "ocr_probe_route",
            "route_routing",
            "route_identity",
            "route_option",
        )
        if first.get(key) is not None
    }
    target_hint = first.get("target_hint")
    if isinstance(target_hint, dict) and target_hint:
        result["primary_route_target_hint"] = dict(target_hint)
    return result


def _lightning_visual_region_by_index(
    visual_regions: dict | None,
    visual_region_index: int | None,
) -> dict | None:
    """Return the detected map region matching a visual extractor index."""
    if visual_region_index is None:
        return None
    if not isinstance(visual_regions, dict):
        return None
    if visual_regions.get("status") != "OK":
        return None
    for offset, region in enumerate(visual_regions.get("regions") or []):
        if not isinstance(region, dict):
            continue
        region_index = region.get("index", offset)
        if region_index != visual_region_index:
            continue
        if not isinstance(region.get("window_x"), int):
            return None
        if not isinstance(region.get("window_y"), int):
            return None
        return region
    return None


def _lightning_visual_region_route_start_point(
    region: dict | None,
    *,
    route_routing: str = "lightning_war",
) -> tuple[int | None, int | None]:
    """Return the click point to open/start a route from a visual region."""
    if not isinstance(region, dict):
        return None, None
    visual_x = region.get("window_x")
    visual_y = region.get("window_y")
    if (
        route_routing == "lightning_war"
        and isinstance(visual_x, int)
        and isinstance(visual_y, int)
    ):
        return visual_x, visual_y
    return (
        region.get("click_window_x", visual_x),
        region.get("click_window_y", visual_y),
    )


def _lightning_visual_regions_from_pause_map_peek() -> tuple[dict | None, dict]:
    """Briefly expose the island map, then extract detected red regions."""
    peek = _lightning_bridge_island_map_pause_peek()
    visual_regions = _lightning_visual_regions_from_recommendation(
        {"pause_map_peek": peek},
    )
    return visual_regions, {
        key: value
        for key, value in peek.items()
        if key != "bridge_data"
    }


def _target_names(session: RunSession) -> set[str]:
    return {
        str(t).strip().lower()
        for t in (getattr(session, "achievement_targets", []) or [])
        if str(t).strip()
    }


def cmd_bridge_speed(mode: str = "fast") -> dict:
    """Set the Lua bridge animation/execution mode."""
    if mode not in ("fast", "visual"):
        result = {"status": "ERROR", "error": "mode must be fast or visual"}
        _print_result(result)
        return result
    if not is_bridge_active():
        result = {"status": "NO_BRIDGE", "mode": mode}
        _print_result(result)
        return result
    try:
        ack = set_bridge_speed(mode)
    except (TimeoutError, BridgeError) as e:
        result = {"status": "ERROR", "error": str(e), "mode": mode}
        _print_result(result)
        return result
    result = {"status": "OK", "mode": mode, "ack": ack}
    _print_result(result)
    return result


def _parse_bridge_ui_probe_ack(ack: str) -> dict:
    prefix = "OK UI_PROBE "
    if not ack.startswith(prefix):
        return {
            "status": "ERROR",
            "reason": "unexpected_ack",
            "ack": ack,
        }
    try:
        probe = json.loads(ack[len(prefix):])
    except json.JSONDecodeError as exc:
        return {
            "status": "ERROR",
            "reason": "probe_json_parse_failed",
            "error": str(exc),
            "ack": ack,
        }
    if not isinstance(probe, dict):
        return {
            "status": "ERROR",
            "reason": "probe_payload_not_object",
            "ack": ack,
            "payload_type": type(probe).__name__,
        }

    available_globals: list[str] = []
    for entry in probe.get("globals") or []:
        if not isinstance(entry, dict):
            continue
        if entry.get("ok") and entry.get("type") != "nil":
            available_globals.append(str(entry.get("label")))

    successful_values: list[dict] = []
    callable_errors: list[dict] = []
    for entry in probe.get("values") or []:
        if not isinstance(entry, dict):
            continue
        if entry.get("ok"):
            successful_values.append(entry)
        elif "not callable" not in str(entry.get("error") or ""):
            callable_errors.append(entry)

    return {
        "status": "OK",
        "probe": probe,
        "summary": {
            "available_globals": available_globals,
            "callable": probe.get("callable") or {},
            "successful_values": successful_values,
            "non_callable_errors": callable_errors,
        },
        "ack": ack,
    }


def cmd_bridge_ui_probe() -> dict:
    """Run the read-only Lua UI/menu probe."""
    if not is_bridge_alive(max_stale_sec=5.0):
        result = {
            "status": "NO_BRIDGE",
            "reason": "bridge_heartbeat_stale_or_missing",
            "next_step": (
                "Install/restart the modloader if needed, then run this probe "
                "once with the pause menu closed and once after pressing Esc."
            ),
        }
        _print_result(result)
        return result
    try:
        ack = bridge_ui_probe()
    except (TimeoutError, BridgeError) as e:
        result = {"status": "ERROR", "error": str(e)}
        _print_result(result)
        return result
    result = _parse_bridge_ui_probe_ack(ack)
    print("\n=== BRIDGE UI PROBE ===")
    print(f"  status: {result.get('status')}")
    summary = result.get("summary") or {}
    if summary:
        globals_count = len(summary.get("available_globals") or [])
        values_count = len(summary.get("successful_values") or [])
        print(f"  available globals: {globals_count}")
        print(f"  successful values: {values_count}")
        callable_map = summary.get("callable") or {}
        callable_bits = [
            f"{label}={','.join(names)}"
            for label, names in callable_map.items()
            if names
        ]
        if callable_bits:
            print(f"  callable methods:  {'; '.join(callable_bits)}")
    _print_result(result)
    return result


def cmd_lightning_preflight(
    profile: str = "Alpha",
    set_fast_bridge: bool = False,
    advanced_content: str = "any",
) -> dict:
    """Check the known Lightning War speed blockers before a fresh attempt."""
    if advanced_content not in {"on", "off", "any"}:
        raise ValueError(f"unknown advanced content mode {advanced_content!r}")
    session = _load_session()
    settings = _read_settings_lua()
    save_advanced = _read_save_advanced_content(profile)
    live_difficulty = _read_save_file_difficulty(profile)
    save_timer = _lightning_read_save_game_timer(profile)
    visible_timer = _lightning_read_visible_pause_timer()
    effective_timer = _lightning_effective_timer_source(save_timer, visible_timer)
    game_budget = _lightning_game_timer_budget(effective_timer.get("game_seconds"))
    targets = _target_names(session)
    issues: list[str] = []
    warnings: list[str] = []

    if session.squad and session.squad.strip().lower() != "blitzkrieg":
        issues.append(f"active session squad is {session.squad!r}, not Blitzkrieg")
    if int(session.difficulty or 0) != 0:
        issues.append(f"active session difficulty is {session.difficulty}, not Easy/0")
    if live_difficulty is not None and live_difficulty != 0:
        issues.append(f"save-file difficulty is {live_difficulty}, not Easy/0")
    if targets and "lightning war" not in targets:
        warnings.append(
            "active achievement targets do not include Lightning War"
        )
    if "hold the line" in targets:
        issues.append("Hold the Line target is active; do not use the speed loop")

    research_gate = _lightning_research_gate_status(session)
    pending_research = research_gate.get("pending_research") or []
    if research_gate.get("status") == "BLOCK":
        issues.append(f"{len(pending_research)} unresolved research queue item(s)")
    elif research_gate.get("status") == "DEFERRED":
        warnings.append(
            f"{len(pending_research)} stale/non-current research queue item(s) deferred"
        )
    pending_diagnosis = _pending_diagnosis_entries(session)
    if pending_diagnosis:
        warnings.append(f"{len(pending_diagnosis)} pending diagnosis item(s)")

    block = _post_enemy_block_result(session)
    if block is not None:
        issues.append("persistent post-enemy block is active")

    if game_budget.get("game_status") == "EXCEEDED":
        issues.append(
            "save-file in-game timer is "
            f"{game_budget.get('game_timer')}, at/over the Lightning War "
            f"limit of {game_budget.get('max_game_timer')}"
        )
    elif game_budget.get("game_status") == "UNKNOWN":
        warnings.append("save-file in-game timer could not be read")
    if (
        visible_timer.get("status") == "OK"
        and save_timer.get("status") == "OK"
        and visible_timer.get("game_seconds") is not None
        and save_timer.get("game_seconds") is not None
        and float(visible_timer["game_seconds"]) - float(save_timer["game_seconds"]) >= 30
    ):
        warnings.append(
            "visible pause-menu timer is newer than save/profile current.time; "
            "using the visible timer for the budget guard"
        )
    if (
        game_budget.get("game_status") == "OK"
        and not session.islands_completed
        and (game_budget.get("game_seconds") or 0) >= 20 * 60
    ):
        warnings.append(
            "no island is complete after 20+ game minutes; restart is recommended "
            "for Lightning War"
        )

    if settings.get("timer_ui") != 1:
        warnings.append("settings.lua timer_ui is not enabled")
    settings_speed = settings.get("speed")
    advanced_keys = ("new_enemies", "new_missions", "new_equip", "new_abilities")
    settings_advanced_state = {
        key: settings.get(key)
        for key in advanced_keys
        if key in settings
    }
    advanced_state = (
        save_advanced.get("state")
        if save_advanced.get("status") == "OK"
        else settings_advanced_state
    )
    advanced_state_source = (
        save_advanced.get("source")
        if save_advanced.get("status") == "OK"
        else "settings"
    )
    if advanced_content in {"on", "off"}:
        desired_value = 1 if advanced_content == "on" else 0
        mismatched = [
            key for key, value in advanced_state.items()
            if value != desired_value
        ]
        if mismatched:
            issues.append(
                "Advanced Content state mismatch for "
                f"{', '.join(mismatched)}; expected {advanced_content.upper()}"
            )
        if (
            save_advanced.get("status") == "OK"
            and settings_advanced_state
            and settings_advanced_state != advanced_state
        ):
            warnings.append(
                "settings.lua Advanced Content keys differ from the active "
                "save/profile run state; trusting save/profile for this preflight"
            )
        missing_advanced_keys = [
            key for key in advanced_keys
            if key not in advanced_state
        ]
        if missing_advanced_keys:
            warnings.append(
                "settings.lua lacks Advanced Content key(s): "
                f"{', '.join(missing_advanced_keys)}"
            )
    if isinstance(settings_speed, int):
        if settings_speed < _LIGHTNING_MIN_FAST_SETTINGS_SPEED:
            issues.append(
                "settings.lua speed is "
                f"{settings_speed}, below Lightning War fast threshold "
                f"{_LIGHTNING_MIN_FAST_SETTINGS_SPEED}"
            )
    elif settings and "speed" not in settings:
        warnings.append("settings.lua has no speed key")
    elif settings:
        warnings.append(f"settings.lua speed is not numeric: {settings_speed!r}")
    if not settings:
        warnings.append("settings.lua could not be read")

    bridge_speed = None
    if set_fast_bridge:
        bridge_speed = cmd_bridge_speed("fast")
        if bridge_speed.get("status") not in ("OK", "NO_BRIDGE"):
            warnings.append(f"bridge fast-mode request failed: {bridge_speed}")

    status = "FAIL" if issues else "WARN" if warnings else "PASS"

    print("\n=== LIGHTNING WAR PREFLIGHT ===")
    print(f"Status:          {status}")
    print(f"Squad:           {session.squad or '(unknown)'}")
    print(f"Difficulty:      {session.difficulty}")
    print(f"Save difficulty: {live_difficulty if live_difficulty is not None else '(unknown)'}")
    print(f"Targets:         {session.achievement_targets}")
    print(f"Timer UI:        {settings.get('timer_ui', '(unknown)')}")
    print(f"Settings speed:  {settings.get('speed', '(unknown)')}")
    print(f"Advanced target: {advanced_content.upper()}")
    print(f"Advanced state:  {advanced_state or '(unknown)'} source={advanced_state_source}")
    print(
        "Game timer:      "
        f"{game_budget.get('game_timer') or '(unknown)'} "
        f"source={effective_timer.get('source') or '(unknown)'}"
    )
    if visible_timer.get("status") == "OK":
        print(
            "Visible timer:   "
            f"{visible_timer.get('game_timer')} "
            f"text={visible_timer.get('ocr_text')!r}"
        )
    if issues:
        print("Issues:")
        for issue in issues:
            print(f"  - {issue}")
    if warnings:
        print("Warnings:")
        for warning in warnings:
            print(f"  - {warning}")

    result = {
        "status": status,
        "issues": issues,
        "warnings": warnings,
        "session": {
            "run_id": session.run_id,
            "squad": session.squad,
            "difficulty": session.difficulty,
            "save_difficulty": live_difficulty,
            "achievement_targets": session.achievement_targets,
        },
        "settings": {
            "timer_ui": settings.get("timer_ui"),
            "speed": settings_speed,
            "speed_fast_threshold": _LIGHTNING_MIN_FAST_SETTINGS_SPEED,
            "speed_fast_ready": (
                isinstance(settings_speed, int)
                and settings_speed >= _LIGHTNING_MIN_FAST_SETTINGS_SPEED
            ),
            "new_missions": settings.get("new_missions"),
            "new_enemies": settings.get("new_enemies"),
            "new_equip": settings.get("new_equip"),
            "new_abilities": settings.get("new_abilities"),
            "advanced_content_target": advanced_content,
            "advanced_content_state": advanced_state,
            "advanced_content_source": advanced_state_source,
            "settings_advanced_content_state": settings_advanced_state,
            "save_advanced_content": save_advanced,
        },
        "save_timer": save_timer,
        "visible_timer": visible_timer,
        "effective_timer": effective_timer,
        "game_budget": game_budget,
        "pending_research_count": len(pending_research),
        "research_gate": research_gate,
        "pending_diagnosis_count": len(pending_diagnosis),
        "bridge_speed": bridge_speed,
        "next_step": (
            "Start/continue only after FAIL issues are cleared. During the "
            "attempt, use recommend_mission --routing lightning_war and "
            "lightning_loop from clean player-turn combat."
        ),
    }
    _print_result(result)
    return result


def _parse_session_run_wall_seconds(session: RunSession) -> float | None:
    """Conservative wall-clock elapsed estimate from the session run id."""
    run_id = str(session.run_id or "")
    # Run ids are ``YYYYMMDD_HHMMSS_mmm``; the timestamp prefix is 15 chars.
    if len(run_id) < 15:
        return None
    try:
        started = datetime.strptime(run_id[:15], "%Y%m%d_%H%M%S")
    except ValueError:
        return None
    elapsed = (datetime.now() - started).total_seconds()
    return max(0.0, elapsed)


def _lightning_budget_summary(
    session: RunSession,
    *,
    profile: str = "Alpha",
    max_wall_seconds: float | None = None,
    max_game_seconds: int | float = _LIGHTNING_ACHIEVEMENT_SECONDS,
) -> dict:
    wall_seconds = _parse_session_run_wall_seconds(session)
    save_timer = _lightning_read_save_game_timer(profile)
    game_budget = _lightning_game_timer_budget(
        save_timer.get("game_seconds"),
        max_game_seconds=max_game_seconds,
    )
    wall_status = "UNKNOWN" if wall_seconds is None else "OK"
    remaining_wall_seconds = None
    if wall_seconds is not None and max_wall_seconds is not None:
        remaining_wall_seconds = max_wall_seconds - wall_seconds
        wall_status = "EXCEEDED" if remaining_wall_seconds <= 0 else "OK"
    summary = {
        "wall_seconds": round(wall_seconds, 1) if wall_seconds is not None else None,
        "max_wall_seconds": max_wall_seconds,
        "mission_index": session.mission_index,
        "current_mission": session.current_mission,
        "islands_completed": session.islands_completed,
        "save_timer": save_timer,
        **game_budget,
        "wall_status": wall_status,
    }
    if remaining_wall_seconds is not None:
        summary["remaining_wall_seconds"] = round(remaining_wall_seconds, 1)
    if (
        game_budget.get("game_status") == "EXCEEDED"
        or wall_status == "EXCEEDED"
    ):
        summary["status"] = "EXCEEDED"
    elif game_budget.get("game_status") == "UNKNOWN" and wall_status == "UNKNOWN":
        summary["status"] = "UNKNOWN"
    else:
        summary["status"] = "OK"
    return summary


def _lightning_live_snapshot(*, refresh: bool = True) -> dict:
    """Read a compact bridge snapshot without doing full cmd_read side effects."""
    if not is_bridge_active():
        return {"status": "NO_BRIDGE"}
    try:
        if refresh:
            refresh_bridge_state()
        board, bridge_data = read_bridge_state()
    except (TimeoutError, BridgeError) as e:
        return {"status": "ERROR", "error": str(e)}
    if not isinstance(bridge_data, dict):
        return {"status": "ERROR", "error": "bridge read returned no data"}

    units = bridge_data.get("units") or []
    active_mechs = sum(
        1 for unit in units
        if unit.get("mech") and unit.get("active") and int(unit.get("hp") or 0) > 0
    )
    mech_count = sum(
        1 for unit in units
        if unit.get("mech") and int(unit.get("hp") or 0) > 0
    )
    deploy_zone = bridge_data.get("deployment_zone") or []
    island_map = bridge_data.get("island_map") or []
    heartbeat_alive = is_bridge_alive(max_stale_sec=5.0)
    snapshot = {
        "status": "OK",
        "phase": bridge_data.get("phase", "unknown"),
        "turn": bridge_data.get("turn", 0),
        "mission_id": bridge_data.get("mission_id", ""),
        "active_mechs": active_mechs,
        "mech_count": mech_count,
        "deployment_zone_count": len(deploy_zone),
        "island_map_count": len(island_map),
        "island_map_debug": bridge_data.get("island_map_debug"),
        "in_active_mission": bridge_data.get("in_active_mission"),
        "total_turns": bridge_data.get("total_turns"),
        "remaining_spawns": bridge_data.get("remaining_spawns"),
        "is_infinite_spawn": bridge_data.get("is_infinite_spawn"),
        "bridge_heartbeat_alive": heartbeat_alive,
    }
    if not refresh:
        snapshot["bridge_refresh_skipped"] = True
    if not heartbeat_alive:
        snapshot["bridge_heartbeat_stale"] = True
    if board is not None:
        grid_power = getattr(board, "grid_power", None)
        grid_power_max = getattr(board, "grid_power_max", None)
        if grid_power is not None and grid_power_max is not None:
            snapshot["grid_power"] = f"{grid_power}/{grid_power_max}"
    return snapshot


def _lightning_live_snapshot_with_refresh(*, refresh: bool = True) -> dict:
    try:
        return _lightning_live_snapshot(refresh=refresh)
    except TypeError as exc:
        if "refresh" not in str(exc):
            raise
        return _lightning_live_snapshot()


def _lightning_snapshot_is_live_after_deploy_confirm(snapshot: dict) -> bool:
    if not isinstance(snapshot, dict) or snapshot.get("status") != "OK":
        return False
    if not _lightning_bridge_snapshot_fresh_enough(snapshot):
        return False
    phase = str(snapshot.get("phase") or "")
    try:
        mech_count = int(snapshot.get("mech_count") or 0)
    except (TypeError, ValueError):
        mech_count = 0
    try:
        active_mechs = int(snapshot.get("active_mechs") or 0)
    except (TypeError, ValueError):
        active_mechs = 0
    try:
        turn = int(snapshot.get("turn") or 0)
    except (TypeError, ValueError):
        turn = 0
    if (
        phase == "combat_player"
        and turn > 0
        and active_mechs > 0
        and mech_count >= _LIGHTNING_EXPECTED_MECH_COUNT
    ):
        return True
    try:
        deployment_zone_count = int(snapshot.get("deployment_zone_count") or 0)
    except (TypeError, ValueError):
        deployment_zone_count = 0
    if deployment_zone_count <= 0:
        return True
    return False


def _lightning_bridge_snapshot_fresh_enough(snapshot: dict | None) -> bool:
    """Treat explicit stale-heartbeat bridge snapshots as evidence only."""
    if not isinstance(snapshot, dict):
        return False
    if snapshot.get("bridge_heartbeat_stale") is True:
        return False
    if snapshot.get("bridge_heartbeat_alive") is False:
        return False
    return True


def _lightning_reactivate_player_turn_if_no_active(snapshot: dict | None) -> dict:
    """Repair the bridge's inactive-player-turn fallback, when tightly proven."""
    if not isinstance(snapshot, dict) or snapshot.get("status") != "OK":
        return {"status": "SKIPPED", "reason": "snapshot_not_ok"}
    if not _lightning_bridge_snapshot_fresh_enough(snapshot):
        return {"status": "SKIPPED", "reason": "bridge_snapshot_not_fresh"}
    if snapshot.get("phase") != "combat_player":
        return {"status": "SKIPPED", "reason": "phase_not_combat_player"}
    try:
        turn = int(snapshot.get("turn") or 0)
        active_mechs = int(snapshot.get("active_mechs") or 0)
        mech_count = int(snapshot.get("mech_count") or 0)
    except (TypeError, ValueError):
        return {"status": "SKIPPED", "reason": "invalid_snapshot_counts"}
    if turn <= 0:
        return {"status": "SKIPPED", "reason": "not_post_deployment_turn"}
    if active_mechs > 0:
        return {"status": "SKIPPED", "reason": "active_mechs_present"}
    if mech_count <= 0:
        return {"status": "SKIPPED", "reason": "no_player_mechs"}
    if snapshot.get("in_active_mission") is not True:
        return {"status": "SKIPPED", "reason": "not_in_active_mission"}
    try:
        ack = reactivate_player_pawns()
    except Exception as exc:
        return {
            "status": "ERROR",
            "reason": "reactivate_player_pawns_failed",
            "error": str(exc),
        }
    refreshed = _lightning_live_snapshot()
    try:
        refreshed_active = int(refreshed.get("active_mechs") or 0)
    except (TypeError, ValueError):
        refreshed_active = 0
    return {
        "status": "OK" if refreshed_active > 0 else "NO_CHANGE",
        "reason": (
            "player_pawns_reactivated"
            if refreshed_active > 0
            else "reactivation_did_not_restore_active_mechs"
        ),
        "ack": ack,
        "snapshot": refreshed,
    }


def _lightning_wait_for_deploy_confirm_live_bridge(
    *,
    max_seconds: float = 8.0,
    interval_seconds: float = 0.35,
) -> dict:
    """Wait for Confirm Deployment to produce a bridge state safe for combat."""
    start = time.monotonic()
    attempts: list[dict] = []
    latest: dict = {"status": "PENDING"}
    while True:
        latest = _lightning_live_snapshot()
        attempts.append({
            "elapsed_seconds": round(time.monotonic() - start, 3),
            "status": latest.get("status"),
            "phase": latest.get("phase"),
            "turn": latest.get("turn"),
            "active_mechs": latest.get("active_mechs"),
            "mech_count": latest.get("mech_count"),
            "deployment_zone_count": latest.get("deployment_zone_count"),
            "bridge_heartbeat_alive": latest.get("bridge_heartbeat_alive"),
            "bridge_heartbeat_stale": latest.get("bridge_heartbeat_stale"),
        })
        if _lightning_snapshot_is_live_after_deploy_confirm(latest):
            return {
                "status": "OK",
                "reason": "deploy_confirm_bridge_live",
                "elapsed_seconds": round(time.monotonic() - start, 3),
                "attempts": attempts,
                "snapshot": latest,
            }
        if time.monotonic() - start >= max_seconds:
            return {
                "status": "TIMEOUT",
                "reason": "deploy_confirm_bridge_not_live",
                "elapsed_seconds": round(time.monotonic() - start, 3),
                "attempts": attempts,
                "snapshot": latest,
            }
        time.sleep(max(0.05, float(interval_seconds)))


def _lightning_wait_for_live_snapshot(
    *,
    initial: dict | None = None,
    max_seconds: float = 2.0,
    interval_seconds: float = 0.2,
) -> dict:
    """Poll briefly for a bridge snapshot after a live UI transition."""
    start = time.monotonic()
    snapshot = initial if initial is not None else _lightning_live_snapshot()
    attempts = [
        {
            "elapsed_seconds": 0.0,
            "status": snapshot.get("status"),
            "phase": snapshot.get("phase"),
        }
    ]
    deadline = start + max_seconds
    while snapshot.get("status") != "OK" and time.monotonic() < deadline:
        time.sleep(interval_seconds)
        snapshot = _lightning_live_snapshot()
        attempts.append(
            {
                "elapsed_seconds": round(time.monotonic() - start, 3),
                "status": snapshot.get("status"),
                "phase": snapshot.get("phase"),
            }
        )
    return {
        "status": "OK" if snapshot.get("status") == "OK" else "TIMEOUT",
        "elapsed_seconds": round(time.monotonic() - start, 3),
        "attempts": attempts,
        "snapshot": snapshot,
    }


