def _lightning_preferred_visible_control(
    visible_name: str | None,
    control: str | None,
    visible_ui: dict | None = None,
) -> str | None:
    """Prefer controls that landed reliably in timed Lightning UI smoke tests."""
    if visible_name == "reward_panel" and control:
        return "reward_continue"
    if visible_name == "perfect_island_panel" and control:
        if _lightning_visible_ui_is_active_intro_dialogue(visible_ui):
            return "bottom_continue"
        return "panel_continue"
    if visible_name == "perfect_reward_choice" and control:
        if _lightning_visible_ui_is_perfect_reward_continue_dialogue(visible_ui):
            return "dialogue_textbox"
        return "perfect_reward_grid"
    if visible_name == "island_complete_leave" and control:
        return "leave_island"
    if (
        visible_name in {"island_map", "island_map_or_unknown"}
        and _lightning_visible_ui_is_intro_continue_panel(visible_ui)
    ):
        return "bottom_continue"
    return control


def _lightning_pause_menu_has_island_map_underlay(
    visible_ui: dict | None,
) -> bool:
    """Recognize the island map dimmed behind the pause menu."""
    if not isinstance(visible_ui, dict) or visible_ui.get("status") != "OK":
        return False
    if visible_ui.get("visible_ui") != "pause_menu" and not (
        visible_ui.get("pause_ocr_match")
        or _lightning_pause_menu_ocr_match(visible_ui)
    ):
        return False
    scores = visible_ui.get("scores")
    if not isinstance(scores, dict):
        return False
    island_map = scores.get("island_map")
    if not isinstance(island_map, dict):
        return False

    def as_int(key: str) -> int:
        try:
            return int(island_map.get(key) or 0)
        except (TypeError, ValueError):
            return 0

    try:
        score = float(island_map.get("score") or 0.0)
    except (TypeError, ValueError):
        score = 0.0

    red = as_int("red")
    green = as_int("green")
    colored = as_int("colored")
    if not colored:
        colored = red + green

    # The pause overlay darkens map regions heavily; on Windows the real
    # route-map underlay can shrink to only a few hundred colored pixels.
    return colored >= 300 and score >= 0.00025 and (red >= 50 or green >= 50)


def _lightning_paused_deployment_underlay_score(image) -> dict:
    """Detect deployment structure dimmed behind the pause menu."""
    width, height = image.size
    base_w, base_h = _LIGHTNING_UI_BASE_SIZE
    scale_x = width / base_w if base_w else 1.0
    scale_y = height / base_h if base_h else 1.0

    def crop_counts(box: tuple[int, int, int, int]) -> dict:
        left = int(box[0] * scale_x)
        top = int(box[1] * scale_y)
        right = int(box[2] * scale_x)
        bottom = int(box[3] * scale_y)
        sampled = _lightning_sampled_rgb_pixels(image, (left, top, right, bottom))
        pixels = sampled["pixels"]
        over20 = 0
        over35 = 0
        over50 = 0
        blue = 0
        for r, g, b in pixels:
            lum = (int(r) + int(g) + int(b)) // 3
            if lum > 20:
                over20 += 1
            if lum > 35:
                over35 += 1
            if lum > 50:
                over50 += 1
            if b > r + 10 and b > g + 5 and b > 30:
                blue += 1
        return {
            "over20": _lightning_scaled_pixel_count(over20, sampled),
            "over35": _lightning_scaled_pixel_count(over35, sampled),
            "over50": _lightning_scaled_pixel_count(over50, sampled),
            "blue": _lightning_scaled_pixel_count(blue, sampled),
            "pixels": int(sampled.get("total_pixels") or 0),
            "crop": sampled["crop"],
        }

    header = crop_counts((5, 35, 530, 130))
    remaining = crop_counts((5, 130, 250, 180))
    left_mechs = crop_counts((0, 160, 180, 748))
    bottom_left = crop_counts((0, 535, 360, 748))
    right_objectives = crop_counts((1000, 125, 1270, 370))
    board_right = crop_counts((970, 320, 1260, 720))
    signals = {
        "header": header.get("over20", 0) >= 9000,
        "active_mission_header": header.get("over20", 0) >= 5000,
        "left_mechs": (
            left_mechs.get("over20", 0) >= 5500
            and (
                left_mechs.get("over35", 0) >= 1800
                or left_mechs.get("over50", 0) >= 1800
                or left_mechs.get("blue", 0) >= 700
            )
        ),
        "remaining": remaining.get("over20", 0) >= 1000,
        "bottom_left": bottom_left.get("over20", 0) >= 9000,
        "right_objectives": right_objectives.get("over20", 0) >= 2500,
        "board_right": board_right.get("over20", 0) >= 4000,
    }
    signal_count = sum(1 for value in signals.values() if value)
    active_mission_under_pause = (
        signals["active_mission_header"]
        and signals["left_mechs"]
    )
    return {
        "score": round(signal_count / max(len(signals), 1), 4),
        "visible": (
            signals["header"]
            and (
                signals["bottom_left"]
                or (
                    signals["left_mechs"]
                    and signals["right_objectives"]
                    and signal_count >= 4
                )
            )
            and signal_count >= 4
        ),
        "active_mission_under_pause": active_mission_under_pause,
        "signal_count": signal_count,
        "signals": signals,
        "header": header,
        "remaining": remaining,
        "left_mechs": left_mechs,
        "bottom_left": bottom_left,
        "right_objectives": right_objectives,
        "board_right": board_right,
    }


def _lightning_pause_menu_has_deployment_underlay(
    visible_ui: dict | None,
) -> bool:
    """Recognize deployment dimmed behind the pause menu."""
    if not isinstance(visible_ui, dict) or visible_ui.get("status") != "OK":
        return False
    scores = visible_ui.get("scores")
    if not isinstance(scores, dict):
        return False
    underlay = scores.get("paused_deployment_underlay")
    if not (isinstance(underlay, dict) and bool(underlay.get("visible"))):
        return False
    preview_dialogue = scores.get("mission_preview_dialogue")
    if isinstance(preview_dialogue, dict):
        try:
            card = preview_dialogue.get("card")
            dialogue = preview_dialogue.get("dialogue")
            preview_score = float(preview_dialogue.get("score") or 0.0)
            card_red = int(card.get("red") or 0) if isinstance(card, dict) else 0
            dialogue_red = (
                int(dialogue.get("red") or 0) if isinstance(dialogue, dict) else 0
            )
        except (TypeError, ValueError):
            preview_score = 0.0
            card_red = 0
            dialogue_red = 0
        if preview_score >= 0.70 and (card_red >= 1000 or dialogue_red >= 1000):
            return False
    preview_panel = scores.get("mission_preview_panel")
    if isinstance(preview_panel, dict):
        try:
            panel_score = float(preview_panel.get("score") or 0.0)
            panel_yellow = int(preview_panel.get("yellow") or 0)
        except (TypeError, ValueError):
            panel_score = 0.0
            panel_yellow = 0
        if panel_score >= 0.006 and panel_yellow >= 1500:
            return False
    if visible_ui.get("visible_ui") == "pause_menu":
        return True
    if visible_ui.get("pause_ocr_match") or _lightning_pause_menu_ocr_match(visible_ui):
        return True
    return False


def _lightning_visible_ui_proves_deployment(
    visible_ui: dict | None,
) -> bool:
    """Return true for deployment or an active mission paused under the menu."""
    if not isinstance(visible_ui, dict) or visible_ui.get("status") != "OK":
        return False
    if visible_ui.get("visible_ui") == "deployment_screen":
        return True
    return (
        _lightning_pause_menu_has_deployment_underlay(visible_ui)
        or _lightning_pause_menu_has_started_mission_underlay(visible_ui)
    )


def _lightning_pause_menu_has_started_mission_underlay(
    visible_ui: dict | None,
) -> bool:
    """Recognize a mission/deployment scene dimmed behind pause, not the map."""
    if not _lightning_visible_ui_is_pause_menu(visible_ui):
        return False
    scores = visible_ui.get("scores") if isinstance(visible_ui, dict) else None
    if not isinstance(scores, dict):
        return False
    underlay = scores.get("paused_deployment_underlay")
    if not isinstance(underlay, dict):
        return False
    signals = underlay.get("signals")
    if not isinstance(signals, dict):
        signals = {}
    if not bool(underlay.get("active_mission_under_pause")):
        return False
    if not bool(signals.get("left_mechs")):
        return False
    if not (bool(signals.get("right_objectives")) or bool(signals.get("board_right"))):
        return False
    island_map = scores.get("island_map")
    try:
        island_colored = (
            int(island_map.get("colored") or 0)
            if isinstance(island_map, dict)
            else 0
        )
    except (TypeError, ValueError):
        island_colored = 0
    if island_colored >= 2500:
        return False
    preview_panel = scores.get("mission_preview_panel")
    try:
        preview_yellow = (
            int(preview_panel.get("yellow") or 0)
            if isinstance(preview_panel, dict)
            else 0
        )
    except (TypeError, ValueError):
        preview_yellow = 0
    if preview_yellow >= 1000:
        return False
    return True


def _lightning_pause_menu_has_safe_reward_tail_underlay(
    visible_ui: dict | None,
) -> bool:
    """Recognize paused post-mission reward text that can be continued blindly."""
    if not _lightning_visible_ui_is_pause_menu(visible_ui):
        return False
    text = "\n".join(_lightning_visible_ui_text_parts(visible_ui)).lower()
    if "continue" not in text:
        return False
    compact = re.sub(r"[^a-z0-9+]+", "", text)
    reward_markers = (
        "regionsecured",
        "civiliansprotected",
        "griddefense",
        "promoted",
        "+xp",
        "vekcasualtyreport",
    )
    return any(marker in compact for marker in reward_markers)


def _lightning_route_visible_ui_from_pause_underlay(
    visible_ui: dict,
) -> dict:
    route_visible_ui = dict(visible_ui)
    route_visible_ui["visible_ui"] = "island_map"
    route_visible_ui["recommended_control"] = None
    route_visible_ui["pause_underlay_visible_ui"] = "pause_menu"
    route_visible_ui["pause_underlay_route_signal"] = "island_map_color_signature"
    return route_visible_ui


def _lightning_visible_ui_is_active_intro_dialogue(
    visible_ui: dict | None,
) -> bool:
    if not isinstance(visible_ui, dict):
        return False
    try:
        dark_overlay = float(visible_ui.get("dark_overlay_fraction") or 0.0)
    except (TypeError, ValueError):
        dark_overlay = 0.0
    if dark_overlay >= 0.60:
        return False

    bridge = visible_ui.get("bridge_refine_snapshot")
    if isinstance(bridge, dict):
        try:
            turn = int(bridge.get("turn") or 0)
        except (TypeError, ValueError):
            turn = -1
        try:
            deployment_zones = int(bridge.get("deployment_zone_count") or 0)
        except (TypeError, ValueError):
            deployment_zones = 0
        if (
            turn == 0
            and deployment_zones > 0
            and bridge.get("in_active_mission") is True
        ):
            return True

    text_parts: list[str] = []
    for key in ("visible_text", "ocr_text", "text"):
        value = visible_ui.get(key)
        if isinstance(value, str):
            text_parts.append(value)
    for key in ("ocr_texts", "texts"):
        value = visible_ui.get(key)
        if isinstance(value, list):
            text_parts.extend(str(item) for item in value if str(item).strip())
    text = "\n".join(text_parts).lower()
    if "continue" not in text:
        return False
    if _lightning_visible_ui_has_intro_continue_text(visible_ui):
        return True
    return (
        "head office" in text
        or "your arrival" in text
        or "our island" in text
        or "the vek came" in text
    )


def _lightning_visible_ui_text_parts(visible_ui: dict | None) -> list[str]:
    if not isinstance(visible_ui, dict):
        return []
    text_parts: list[str] = []
    for key in ("visible_text", "ocr_text", "text"):
        value = visible_ui.get(key)
        if isinstance(value, str) and value.strip():
            text_parts.append(value)
    for key in ("ocr_texts", "texts"):
        value = visible_ui.get(key)
        if isinstance(value, list):
            text_parts.extend(str(item) for item in value if str(item).strip())
    ocr = visible_ui.get("ocr")
    if isinstance(ocr, dict):
        for key in ("texts", "lines"):
            value = ocr.get(key)
            if isinstance(value, list):
                text_parts.extend(str(item) for item in value if str(item).strip())
    return text_parts


def _lightning_pause_menu_ocr_match(visible_ui: dict | None) -> str | None:
    text_parts = _lightning_visible_ui_text_parts(visible_ui)
    if not text_parts:
        return None
    text = "\n".join(text_parts).lower()
    normalized = re.sub(r"[^a-z0-9]+", " ", text).strip()
    compact = re.sub(r"[^a-z0-9]+", "", text)
    if not compact:
        return None
    for phrase, label in _LIGHTNING_PAUSE_MENU_OCR_PHRASES.items():
        if phrase in compact:
            return label
    tokens = set(normalized.split())
    if "menu" in tokens and "continue" in tokens:
        if _lightning_visible_ui_has_intro_continue_text(visible_ui):
            return None
        return "MENU + CONTINUE"
    return None


def _lightning_title_screen_ocr_match(visible_ui: dict | None) -> bool:
    """Recognize the main title menu from OCR, even when it is dimmed."""
    text_parts = _lightning_visible_ui_text_parts(visible_ui)
    if not text_parts:
        return False
    text = "\n".join(text_parts).lower()
    normalized = re.sub(r"[^a-z0-9]+", " ", text).strip()
    compact = re.sub(r"[^a-z0-9]+", "", text)
    if not compact:
        return False
    tokens = set(normalized.split())
    return (
        ("newgame" in compact or ("new" in tokens and "game" in tokens))
        and "quit" in tokens
        and (
            "profile" in tokens
            or "credits" in tokens
            or "achievements" in tokens
            or "statistics" in tokens
            or "statistics" in compact
        )
    )


def _lightning_apply_title_screen_ocr_override(visible_ui: dict) -> dict:
    """Prefer explicit title-menu OCR over pause-menu geometry."""
    if not isinstance(visible_ui, dict) or visible_ui.get("status") != "OK":
        return visible_ui
    if _lightning_external_system_prompt_visible(visible_ui):
        return visible_ui
    if not _lightning_title_screen_ocr_match(visible_ui):
        return visible_ui
    original_visible = visible_ui.get("visible_ui")
    result = dict(visible_ui)
    result["visible_ui"] = "title_screen"
    result["recommended_control"] = "title_new_game"
    if original_visible != "title_screen":
        result["title_screen_ocr_override"] = {
            "from_visible_ui": original_visible,
            "from_recommended_control": visible_ui.get("recommended_control"),
        }
    return result


def _lightning_apply_pause_menu_ocr_override(visible_ui: dict) -> dict:
    """Prefer explicit pause-menu OCR over color/button false positives."""
    if not isinstance(visible_ui, dict) or visible_ui.get("status") != "OK":
        return visible_ui
    if _lightning_external_system_prompt_visible(visible_ui):
        return visible_ui
    matched = _lightning_pause_menu_ocr_match(visible_ui)
    if matched is None:
        return visible_ui
    original_visible = visible_ui.get("visible_ui")
    result = dict(visible_ui)
    result["visible_ui"] = "pause_menu"
    result["recommended_control"] = _LIGHTNING_UI_BUTTON_CROPS["pause_menu"]["control"]
    result["pause_ocr_match"] = matched
    if original_visible != "pause_menu":
        result["pause_ocr_override"] = {
            "from_visible_ui": original_visible,
            "from_recommended_control": visible_ui.get("recommended_control"),
            "matched": matched,
        }
    return result


def _lightning_system_privacy_prompt_ocr_match(visible_ui: dict | None) -> bool:
    """Recognize macOS privacy prompts by OCR when visual thresholds miss."""
    if not isinstance(visible_ui, dict):
        return False
    text = "\n".join(_lightning_visible_ui_text_parts(visible_ui)).lower()
    compact = re.sub(r"[^a-z0-9]+", " ", text).strip()
    letters_only = re.sub(r"[^a-z0-9]+", "", text)
    consent_word_seen = (
        "allow" in compact
        or "open system settings" in compact
        or "bypass" in compact
        or "pass" in compact
        or "bypass" in letters_only
        or "pass" in letters_only
        or "fass" in letters_only
    )
    return (
        "private window" in compact
        and "screen and audio" in compact
        and (
            "requesting to bypass" in compact
            or "directly access" in compact
        )
        and consent_word_seen
    )


def _lightning_apply_system_prompt_ocr_override(visible_ui: dict) -> dict:
    """Promote OCR-proven OS prompts above in-game pause/menu states."""
    if not isinstance(visible_ui, dict) or visible_ui.get("status") != "OK":
        return visible_ui
    if not _lightning_system_privacy_prompt_ocr_match(visible_ui):
        return visible_ui
    result = dict(visible_ui)
    original_visible = result.get("visible_ui")
    result["visible_ui"] = "system_privacy_prompt"
    result["recommended_control"] = None
    result["requires_user_authorization"] = True
    result["external_prompt"] = {
        "status": "OK",
        "matched": True,
        "kind": "macos_screen_audio_privacy_prompt",
        "source": "visible_ocr",
    }
    result["next_step"] = (
        "A macOS privacy prompt is covering the game. Click Allow under the "
        "standing user approval, then resample the visible UI."
    )
    if original_visible != "system_privacy_prompt":
        result["system_prompt_ocr_override"] = {
            "from_visible_ui": original_visible,
            "from_recommended_control": visible_ui.get("recommended_control"),
        }
    return result


def _lightning_deployment_screen_ocr_match(visible_ui: dict | None) -> bool:
    """Recognize live deployment screens whose yellow-tile score is weak."""
    if not isinstance(visible_ui, dict):
        return False
    text = "\n".join(_lightning_visible_ui_text_parts(visible_ui)).lower()
    if not text:
        return False
    compact = re.sub(r"[^a-z0-9]+", " ", text).strip()
    tokens = set(compact.split())
    has_deploying = "deploying" in tokens
    has_mech = "mech" in tokens
    has_drop_zone = "drop zone" in compact or (
        "drop" in tokens and "zone" in tokens
    )
    has_game_time = "game time" in compact
    has_select_location = "select a location" in compact
    return has_deploying and has_mech and (
        has_drop_zone or has_game_time or has_select_location
    )


def _lightning_apply_deployment_screen_ocr_override(visible_ui: dict) -> dict:
    """Promote OCR-proven deployment screens above map-like false positives."""
    if not isinstance(visible_ui, dict) or visible_ui.get("status") != "OK":
        return visible_ui
    if not _lightning_deployment_screen_ocr_match(visible_ui):
        return visible_ui
    result = dict(visible_ui)
    original_visible = result.get("visible_ui")
    result["visible_ui"] = "deployment_screen"
    result["recommended_control"] = "deploy_confirm"
    result["confidence"] = max(float(result.get("confidence") or 0.0), 0.85)
    if original_visible != "deployment_screen":
        result["deployment_ocr_override"] = {
            "from_visible_ui": original_visible,
            "from_recommended_control": visible_ui.get("recommended_control"),
        }
    return result


def _lightning_click_system_privacy_prompt_allow(
    visible_ui: dict,
    *,
    dry_run: bool = False,
) -> dict:
    """Click the standing-approved macOS screen/audio prompt Allow button."""
    from src.control.mac_click import click_macos_privacy_prompt_allow

    click_result = click_macos_privacy_prompt_allow(
        visible_ui,
        dry_run=dry_run,
        settle_seconds=0.35,
        hold_seconds=0.08,
    )
    result = {
        "status": click_result.get("status", "ERROR"),
        "reason": "system_privacy_prompt_allow_clicked",
        "visible_ui": visible_ui,
        "click_result": click_result,
        "standing_permission": "user_granted_click_allow_on_macos_popups",
    }
    if click_result.get("status") != "OK":
        result["reason"] = click_result.get("reason") or "system_privacy_prompt_allow_failed"
        result["error"] = click_result.get("error")
        stack_drain = _lightning_drain_system_privacy_prompt_stack_fullscreen_ocr(
            dry_run=dry_run,
        )
        result["prompt_stack_drain"] = stack_drain
        if stack_drain.get("status") == "OK":
            if not dry_run:
                time.sleep(0.2)
            current_ui = _lightning_visible_ui_snapshot(
                include_ocr=True,
                bridge_refine=False,
            )
            result["post_fullscreen_click_visible_ui"] = current_ui
            if current_ui.get("status") != "OK":
                result["status"] = "BLOCKED"
                result["reason"] = "system_privacy_prompt_resample_failed"
                return result
            if current_ui.get("visible_ui") != "system_privacy_prompt":
                result["status"] = "OK"
                result["reason"] = (
                    "system_privacy_prompt_allow_clicked_fullscreen_ocr"
                )
                return result
            result["status"] = "BLOCKED"
            result["reason"] = "system_privacy_prompt_still_visible"
            return result
        if stack_drain.get("status") == "BLOCKED":
            result["status"] = "BLOCKED"
            result["reason"] = stack_drain.get("reason") or (
                "system_privacy_prompt_stack_drain_blocked"
            )
        return result
    post_click = _lightning_visible_ui_snapshot(include_ocr=True)
    result["post_click_visible_ui"] = post_click
    if post_click.get("status") != "OK":
        result["status"] = "BLOCKED"
        result["reason"] = "system_privacy_prompt_resample_failed"
        return result
    if post_click.get("visible_ui") == "system_privacy_prompt":
        stack_drain = _lightning_drain_system_privacy_prompt_stack_fullscreen_ocr(
            dry_run=dry_run,
        )
        result["prompt_stack_drain"] = stack_drain
        if stack_drain.get("status") == "OK":
            if not dry_run:
                time.sleep(0.2)
            current_ui = _lightning_visible_ui_snapshot(
                include_ocr=True,
                bridge_refine=False,
            )
            result["post_fullscreen_click_visible_ui"] = current_ui
            if current_ui.get("status") != "OK":
                result["status"] = "BLOCKED"
                result["reason"] = "system_privacy_prompt_resample_failed"
                return result
            if current_ui.get("visible_ui") != "system_privacy_prompt":
                result["status"] = "OK"
                result["reason"] = (
                    "system_privacy_prompt_allow_clicked_fullscreen_ocr"
                )
                return result
        elif stack_drain.get("status") == "BLOCKED":
            result["status"] = "BLOCKED"
            result["reason"] = stack_drain.get("reason") or (
                "system_privacy_prompt_stack_drain_blocked"
            )
            return result
        retry_attempts: list[dict[str, Any]] = []
        current_ui = post_click
        for attempt in range(12):
            attempt_record: dict[str, Any] = {"attempt": attempt + 1}
            fullscreen_click = _lightning_click_system_privacy_prompt_allow_fullscreen_ocr(
                dry_run=dry_run,
            )
            attempt_record["fullscreen_allow_click"] = fullscreen_click
            if fullscreen_click.get("status") == "OK":
                settle_snapshots = []
                for settle_seconds in (0.2, 0.45, 0.75):
                    if not dry_run:
                        time.sleep(settle_seconds)
                    current_ui = _lightning_visible_ui_snapshot(include_ocr=True)
                    settle_snapshots.append({
                        "settle_seconds": settle_seconds,
                        "status": current_ui.get("status"),
                        "visible_ui": current_ui.get("visible_ui"),
                        "screenshot_path": current_ui.get("screenshot_path"),
                    })
                    if current_ui.get("status") != "OK":
                        attempt_record["settle_snapshots"] = settle_snapshots
                        retry_attempts.append(attempt_record)
                        result["prompt_clear_retries"] = retry_attempts
                        result["post_fullscreen_click_visible_ui"] = current_ui
                        result["status"] = "BLOCKED"
                        result["reason"] = "system_privacy_prompt_resample_failed"
                        return result
                    if current_ui.get("visible_ui") != "system_privacy_prompt":
                        attempt_record["settle_snapshots"] = settle_snapshots
                        retry_attempts.append(attempt_record)
                        result["prompt_clear_retries"] = retry_attempts
                        result["post_fullscreen_click_visible_ui"] = current_ui
                        result["status"] = "OK"
                        result["reason"] = (
                            "system_privacy_prompt_allow_clicked_fullscreen_ocr"
                        )
                        return result
                attempt_record["settle_snapshots"] = settle_snapshots
            if isinstance(current_ui, dict) and current_ui.get("visible_ui") == "system_privacy_prompt":
                followup_click = click_macos_privacy_prompt_allow(
                    current_ui,
                    dry_run=dry_run,
                    settle_seconds=0.25,
                    hold_seconds=0.08,
                )
                attempt_record["followup_window_allow_click"] = followup_click
                if followup_click.get("status") == "OK":
                    if not dry_run:
                        time.sleep(0.35)
                    current_ui = _lightning_visible_ui_snapshot(include_ocr=True)
                    attempt_record["post_followup_visible_ui"] = {
                        "status": current_ui.get("status"),
                        "visible_ui": current_ui.get("visible_ui"),
                        "screenshot_path": current_ui.get("screenshot_path"),
                    }
                    if current_ui.get("status") != "OK":
                        retry_attempts.append(attempt_record)
                        result["prompt_clear_retries"] = retry_attempts
                        result["post_followup_visible_ui"] = current_ui
                        result["status"] = "BLOCKED"
                        result["reason"] = "system_privacy_prompt_resample_failed"
                        return result
                    if current_ui.get("visible_ui") != "system_privacy_prompt":
                        retry_attempts.append(attempt_record)
                        result["prompt_clear_retries"] = retry_attempts
                        result["post_followup_visible_ui"] = current_ui
                        result["status"] = "OK"
                        result["reason"] = "system_privacy_prompt_allow_clicked_retry"
                        return result
            retry_attempts.append(attempt_record)
        result["prompt_clear_retries"] = retry_attempts
        result["post_fullscreen_click_visible_ui"] = current_ui
        result["status"] = "BLOCKED"
        result["reason"] = "system_privacy_prompt_still_visible"
    return result


def _lightning_drain_system_privacy_prompt_stack_fullscreen_ocr(
    *,
    dry_run: bool = False,
    max_clicks: int = 60,
    settle_seconds: float = 0.12,
    max_wall_seconds: float | None = 60.0,
) -> dict:
    """Click stacked macOS Allow prompts until full-screen OCR sees none."""
    if os.name == "nt":
        return {"status": "SKIPPED", "reason": "not_macos"}
    click_limit = max(1, int(max_clicks or 1))
    wall_limit = (
        None
        if max_wall_seconds is None
        else max(0.0, float(max_wall_seconds or 0.0))
    )
    started = time.monotonic()
    clicks: list[dict[str, Any]] = []
    capture_failures = 0
    for attempt in range(click_limit):
        elapsed = time.monotonic() - started
        if wall_limit is not None and elapsed >= wall_limit:
            return {
                "status": "BLOCKED",
                "reason": "system_privacy_prompt_stack_drain_wall_limit",
                "click_count": len(clicks),
                "clicks": clicks,
                "max_clicks": click_limit,
                "max_wall_seconds": wall_limit,
                "elapsed_wall_seconds": round(elapsed, 3),
            }
        click = _lightning_click_system_privacy_prompt_allow_fullscreen_ocr(
            dry_run=dry_run,
        )
        attempt_record = {
            "attempt": attempt + 1,
            "fullscreen_allow_click": click,
        }
        if click.get("status") == "OK":
            capture_failures = 0
            clicks.append(attempt_record)
            if not dry_run and settle_seconds > 0:
                time.sleep(settle_seconds)
            continue

        if click.get("reason") == "fullscreen_screencapture_failed":
            capture_failures += 1
            if capture_failures <= 5:
                if not dry_run:
                    time.sleep(min(0.75, settle_seconds + 0.25))
                continue

        target = click.get("target") if isinstance(click, dict) else None
        target_reason = (
            target.get("reason")
            if isinstance(target, dict)
            else None
        )
        allow_absent = (
            click.get("reason") == "fullscreen_allow_target_missing"
            or target_reason == "allow_ocr_target_missing"
        )
        if allow_absent:
            if clicks:
                return {
                    "status": "OK",
                    "reason": "system_privacy_prompt_stack_drained_fullscreen_ocr",
                    "click_count": len(clicks),
                    "clicks": clicks,
                    "terminal_fullscreen_probe": click,
                    "max_clicks": click_limit,
                    "max_wall_seconds": wall_limit,
                    "elapsed_wall_seconds": round(time.monotonic() - started, 3),
                }
            return {
                "status": "NOT_FOUND",
                "reason": "system_privacy_prompt_allow_absent_fullscreen_ocr",
                "click_count": 0,
                "terminal_fullscreen_probe": click,
                "max_clicks": click_limit,
                "max_wall_seconds": wall_limit,
                "elapsed_wall_seconds": round(time.monotonic() - started, 3),
            }
        return {
            "status": click.get("status", "ERROR"),
            "reason": "system_privacy_prompt_stack_drain_probe_failed",
            "click_count": len(clicks),
            "clicks": clicks,
            "terminal_fullscreen_probe": click,
            "max_clicks": click_limit,
            "max_wall_seconds": wall_limit,
            "elapsed_wall_seconds": round(time.monotonic() - started, 3),
        }

    return {
        "status": "BLOCKED",
        "reason": "system_privacy_prompt_stack_drain_click_limit",
        "click_count": len(clicks),
        "clicks": clicks,
        "max_clicks": click_limit,
        "max_wall_seconds": wall_limit,
        "elapsed_wall_seconds": round(time.monotonic() - started, 3),
        "next_step": (
            "A very large macOS privacy prompt stack is still exposing Allow "
            "after the hard click limit. Drain prompts manually or increase "
            "the reviewed limit before resuming the timer."
        ),
    }


def _lightning_allow_target_from_ocr_result(ocr: dict | None) -> dict:
    """Find an OCR-proven Allow button center in image coordinates."""
    observations = (
        ocr.get("observations", [])
        if isinstance(ocr, dict) and isinstance(ocr.get("observations"), list)
        else []
    )
    for observation in observations:
        if not isinstance(observation, dict):
            continue
        text = str(observation.get("text") or "").strip().lower()
        letters_only = re.sub(r"[^a-z0-9]+", "", text)
        consent_button_text = letters_only in {"allow", "alow", "aliow", "all0w"}
        if not consent_button_text:
            continue
        center = observation.get("center_image")
        if isinstance(center, (list, tuple)) and len(center) == 2:
            try:
                image_x = float(center[0])
                image_y = float(center[1])
            except (TypeError, ValueError):
                continue
            return {
                "status": "OK",
                "image_x": image_x,
                "image_y": image_y,
                "source": "fullscreen_ocr_center_image",
                "text": observation.get("text"),
            }
        bbox = observation.get("bbox_image")
        if isinstance(bbox, (list, tuple)) and len(bbox) == 4:
            try:
                left, top, right, bottom = [float(value) for value in bbox]
            except (TypeError, ValueError):
                continue
            if right > left and bottom > top:
                return {
                    "status": "OK",
                    "image_x": (left + right) / 2.0,
                    "image_y": (top + bottom) / 2.0,
                    "source": "fullscreen_ocr_bbox_image",
                    "text": observation.get("text"),
                    "bbox_image": [left, top, right, bottom],
                }
    return {
        "status": "NOT_FOUND",
        "reason": "allow_ocr_target_missing",
        "observation_count": len(observations),
    }


def _lightning_blue_allow_target_from_fullscreen_image(
    screenshot_path: Path,
) -> dict:
    """Find the macOS accent-blue Allow button when OCR misses its label."""
    try:
        from PIL import Image
    except Exception as exc:
        return {"status": "ERROR", "reason": "pil_unavailable", "error": str(exc)}
    try:
        image = Image.open(screenshot_path).convert("RGB")
    except Exception as exc:
        return {
            "status": "ERROR",
            "reason": "fullscreen_blue_allow_image_open_failed",
            "error": str(exc),
        }
    width, height = image.size
    if width <= 0 or height <= 0:
        return {
            "status": "ERROR",
            "reason": "fullscreen_blue_allow_invalid_image_size",
            "image_size": [width, height],
        }

    pixels = image.load()
    mask = bytearray(width * height)
    for y in range(height):
        for x in range(width):
            r, g, b = pixels[x, y]
            if (
                b > 170
                and 65 <= g <= 185
                and r < 90
                and (b - r) > 100
                and (b - g) > 25
            ):
                mask[y * width + x] = 1

    seen = bytearray(width * height)
    best: tuple[int, int, int, int, int, int, int] | None = None
    for index, value in enumerate(mask):
        if not value or seen[index]:
            continue
        stack = [index]
        seen[index] = 1
        start_y, start_x = divmod(index, width)
        min_x = max_x = start_x
        min_y = max_y = start_y
        count = 0
        while stack:
            point = stack.pop()
            count += 1
            py, px = divmod(point, width)
            min_x = min(min_x, px)
            max_x = max(max_x, px)
            min_y = min(min_y, py)
            max_y = max(max_y, py)
            neighbors = []
            if px > 0:
                neighbors.append(point - 1)
            if px < width - 1:
                neighbors.append(point + 1)
            if py > 0:
                neighbors.append(point - width)
            if py < height - 1:
                neighbors.append(point + width)
            for neighbor in neighbors:
                if mask[neighbor] and not seen[neighbor]:
                    seen[neighbor] = 1
                    stack.append(neighbor)
        component_w = max_x - min_x + 1
        component_h = max_y - min_y + 1
        if (
            component_w >= 260
            and 35 <= component_h <= 120
            and count >= 5000
            and min_y > height * 0.25
        ):
            candidate = (
                count,
                min_x,
                min_y,
                max_x,
                max_y,
                component_w,
                component_h,
            )
            if best is None or (
                candidate[4],
                candidate[3],
                candidate[0],
            ) > (
                best[4],
                best[3],
                best[0],
            ):
                best = candidate
    if best is None:
        return {
            "status": "NOT_FOUND",
            "reason": "fullscreen_blue_allow_target_missing",
            "image_size": [width, height],
        }
    count, min_x, min_y, max_x, max_y, component_w, component_h = best
    return {
        "status": "OK",
        "image_x": (min_x + max_x) / 2.0,
        "image_y": (min_y + max_y) / 2.0,
        "source": "fullscreen_blue_button_component",
        "component": {
            "pixel_count": count,
            "bbox_image": [min_x, min_y, max_x, max_y],
            "width": component_w,
            "height": component_h,
        },
    }


def _lightning_pyautogui_screen_size() -> dict:
    try:
        import pyautogui
    except Exception as exc:
        return {"status": "ERROR", "error": f"pyautogui unavailable: {exc}"}
    try:
        size = pyautogui.size()
    except Exception as exc:
        return {"status": "ERROR", "error": f"pyautogui screen size failed: {exc}"}
    try:
        if hasattr(size, "width") and hasattr(size, "height"):
            width = int(size.width)
            height = int(size.height)
        else:
            width = int(size[0])
            height = int(size[1])
    except (TypeError, ValueError, IndexError) as exc:
        return {"status": "ERROR", "error": f"invalid pyautogui screen size: {exc}"}
    if width <= 0 or height <= 0:
        return {
            "status": "ERROR",
            "error": "invalid pyautogui screen size",
            "screen_size": [width, height],
        }
    return {"status": "OK", "screen_size": [width, height]}


def _lightning_click_system_privacy_prompt_allow_fullscreen_ocr(
    *,
    dry_run: bool = False,
) -> dict:
    """Click macOS Allow using full-screen OCR coordinates when window scaling lies."""
    if os.name == "nt":
        return {"status": "SKIPPED", "reason": "not_macos"}
    from PIL import Image
    from src.control.mac_click import click_screen_point

    with tempfile.NamedTemporaryFile(
        prefix="itb_privacy_prompt_fullscreen_",
        suffix=".png",
        delete=False,
    ) as fh:
        screenshot_path = Path(fh.name)
    try:
        capture = None
        capture_errors: list[dict[str, Any]] = []
        for attempt in range(6):
            try:
                capture = subprocess.run(
                    ["screencapture", "-x", str(screenshot_path)],
                    capture_output=True,
                    text=True,
                    timeout=5,
                )
            except Exception as exc:
                capture_errors.append({
                    "attempt": attempt + 1,
                    "error": str(exc),
                })
                capture = None
            if capture is not None and capture.returncode == 0:
                break
            if capture is not None:
                capture_errors.append({
                    "attempt": attempt + 1,
                    "returncode": capture.returncode,
                    "stderr": capture.stderr,
                })
            time.sleep(0.2)
        if capture is None:
            return {
                "status": "ERROR",
                "reason": "fullscreen_screencapture_failed",
                "attempts": capture_errors,
            }
        if capture.returncode != 0:
            return {
                "status": "ERROR",
                "reason": "fullscreen_screencapture_failed",
                "returncode": capture.returncode,
                "stderr": capture.stderr,
                "attempts": capture_errors,
            }
        ocr = _lightning_ocr_texts_from_image(screenshot_path)
        if ocr.get("status") != "OK":
            return {
                "status": "ERROR",
                "reason": "fullscreen_allow_ocr_failed",
                "ocr": ocr,
            }
        target = _lightning_allow_target_from_ocr_result(ocr)
        if target.get("status") != "OK":
            ocr_target = dict(target)
            blue_target = _lightning_blue_allow_target_from_fullscreen_image(
                screenshot_path,
            )
            if blue_target.get("status") == "OK":
                target = blue_target
                target["ocr_target"] = ocr_target
            else:
                return {
                    "status": "ERROR",
                    "reason": "fullscreen_allow_target_missing",
                    "target": target,
                    "blue_target": blue_target,
                    "ocr_texts": ocr.get("texts", []),
                }
        try:
            with Image.open(screenshot_path) as image:
                image_w, image_h = [int(value) for value in image.size]
        except Exception as exc:
            return {
                "status": "ERROR",
                "reason": "fullscreen_image_size_failed",
                "error": str(exc),
                "target": target,
            }
        screen = _lightning_pyautogui_screen_size()
        if screen.get("status") != "OK":
            screen["target"] = target
            screen["image_size"] = [image_w, image_h]
            return screen
        screen_w, screen_h = screen["screen_size"]
        screen_x = int(round(float(target["image_x"]) * screen_w / image_w))
        screen_y = int(round(float(target["image_y"]) * screen_h / image_h))
        click = click_screen_point(
            screen_x,
            screen_y,
            description="macOS privacy prompt Allow full-screen OCR",
            dry_run=dry_run,
            settle_seconds=0.35,
            hold_seconds=0.08,
        )
        stack_drain_clicks = []
        return {
            "status": click.get("status", "ERROR"),
            "reason": "system_privacy_prompt_allow_fullscreen_ocr_clicked",
            "standing_permission": "user_granted_click_allow_on_macos_popups",
            "target": target,
            "image_size": [image_w, image_h],
            "screen_size": [screen_w, screen_h],
            "screen_point": [screen_x, screen_y],
            "coordinate_scale": {
                "x": screen_w / float(image_w),
                "y": screen_h / float(image_h),
            },
            "click_result": click,
            "stack_drain_clicks": stack_drain_clicks,
            "stack_drain_policy": "resample_before_followup_click",
        }
    finally:
        try:
            screenshot_path.unlink()
        except OSError:
            pass


def _lightning_setup_screen_ocr_match(visible_ui: dict | None) -> bool:
    """Recognize the new-run Difficulty Setup modal from OCR text."""
    if not isinstance(visible_ui, dict):
        return False
    text = "\n".join(_lightning_visible_ui_text_parts(visible_ui)).lower()
    if not text:
        return False
    normalized = re.sub(r"[^a-z0-9]+", " ", text).strip()
    compact = re.sub(r"[^a-z0-9]+", "", text)
    tokens = set(normalized.split())
    has_title = "difficultysetup" in compact or (
        "difficulty" in tokens and "setup" in tokens
    )
    has_advanced = "advancedcontent" in compact or (
        "advanced" in tokens and "content" in tokens
    )
    has_controls = "start" in tokens or "cancel" in tokens
    has_difficulty_choice = bool({"easy", "normal", "hard", "unfair"} & tokens)
    difficulty_setup = (
        has_title
        and has_advanced
        and has_controls
        and has_difficulty_choice
    )
    if difficulty_setup:
        return True
    has_squad_controls = "start" in tokens and "back" in tokens
    has_blitzkrieg = "blitzkrieg" in tokens or "blitzkrieg" in compact
    has_blitzkrieg_mech = any(
        mech in compact
        for mech in (
            "lightningmech",
            "hookmech",
            "bouldermech",
            "bouldepmech",
        )
    )
    has_setup_action = (
        "randomize" in tokens
        or "changesquad" in compact
        or "changetimetraveler" in compact
    )
    return (
        has_squad_controls
        and has_blitzkrieg
        and has_blitzkrieg_mech
        and has_setup_action
    )


def _lightning_apply_setup_screen_ocr_override(visible_ui: dict) -> dict:
    """Prefer explicit setup-screen OCR over mission-preview false positives."""
    if not isinstance(visible_ui, dict) or visible_ui.get("status") != "OK":
        return visible_ui
    if _lightning_external_system_prompt_visible(visible_ui):
        return visible_ui
    if not _lightning_setup_screen_ocr_match(visible_ui):
        return visible_ui
    original_visible = visible_ui.get("visible_ui")
    result = dict(visible_ui)
    result["visible_ui"] = "new_game_setup"
    result["recommended_control"] = None
    if original_visible != "new_game_setup":
        result["setup_ocr_override"] = {
            "from_visible_ui": original_visible,
            "from_recommended_control": visible_ui.get("recommended_control"),
        }
    return result


def _lightning_should_ocr_for_system_prompt(visible_ui: dict) -> bool:
    """Return true when visual prompt geometry is close enough to OCR cheaply."""
    if not isinstance(visible_ui, dict) or visible_ui.get("status") != "OK":
        return False
    if _lightning_external_system_prompt_visible(visible_ui):
        return False
    score = (
        visible_ui.get("scores", {}).get("system_privacy_prompt", {})
        if isinstance(visible_ui.get("scores"), dict)
        else {}
    )
    if not isinstance(score, dict):
        return False
    try:
        prompt_score = float(score.get("score") or 0.0)
        relaxed_score = float(score.get("relaxed_score") or 0.0)
    except (TypeError, ValueError):
        return False
    checks = score.get("checks") if isinstance(score.get("checks"), dict) else {}
    try:
        text_bright = float(checks.get("text_bright") or 0.0)
        card_mid_dark = float(checks.get("card_mid_dark") or 0.0)
        icon_color = float(checks.get("icon_color") or 0.0)
    except (TypeError, ValueError):
        text_bright = card_mid_dark = icon_color = 0.0
    return (
        max(prompt_score, relaxed_score) >= 0.20
        or (
            max(prompt_score, relaxed_score) >= 0.04
            and text_bright >= 0.75
            and card_mid_dark >= 0.25
            and icon_color >= 0.08
        )
    )


def _lightning_visible_ui_has_intro_continue_text(
    visible_ui: dict | None,
) -> bool:
    if not isinstance(visible_ui, dict) or visible_ui.get("status") != "OK":
        return False
    text = "\n".join(_lightning_visible_ui_text_parts(visible_ui))
    if not text:
        return False
    normalized = re.sub(r"[^a-z0-9]+", " ", text.lower()).strip()
    compact = re.sub(r"[^a-z0-9]+", "", text.lower())
    if "continue" not in normalized.split() and "continue" not in compact:
        return False
    return (
        "headoffice" in compact
        or "onbehalfof" in compact
        or "welcomeyou" in compact
        or "yourarrival" in compact
        or "ourisland" in compact
        or "thevekcame" in compact
    )


def _lightning_visible_ui_is_intro_continue_panel(
    visible_ui: dict | None,
) -> bool:
    if not isinstance(visible_ui, dict) or visible_ui.get("status") != "OK":
        return False
    if _lightning_visible_ui_is_active_intro_dialogue(visible_ui):
        return True
    if visible_ui.get("visible_ui") not in {
        "island_map_or_unknown",
        "mission_preview_panel",
    }:
        return False
    return _lightning_visible_ui_has_intro_continue_text(visible_ui)


def _lightning_visible_ui_has_continue_text(visible_ui: dict | None) -> bool:
    if not isinstance(visible_ui, dict) or visible_ui.get("status") != "OK":
        return False
    text = "\n".join(_lightning_visible_ui_text_parts(visible_ui))
    if not text:
        return False
    normalized = re.sub(r"[^a-z0-9]+", " ", text.lower()).strip().split()
    compact = re.sub(r"[^a-z0-9]+", "", text.lower())
    return "continue" in normalized or "continue" in compact


def _lightning_visible_ui_has_ceo_dialogue_signal(visible_ui: dict | None) -> bool:
    if not isinstance(visible_ui, dict) or visible_ui.get("status") != "OK":
        return False
    scores = visible_ui.get("scores")
    if not isinstance(scores, dict):
        return False
    dialogue = scores.get("mission_preview_dialogue")
    if not isinstance(dialogue, dict):
        return False
    card = dialogue.get("card")
    if not isinstance(card, dict):
        card = {}
    dialogue_region = dialogue.get("dialogue")
    if not isinstance(dialogue_region, dict):
        dialogue_region = {}
    try:
        score = float(dialogue.get("score") or 0.0)
        dark_fraction = float(
            dialogue.get("dialogue_dark_fraction")
            or dialogue_region.get("dark_fraction")
            or 0.0
        )
    except (TypeError, ValueError):
        return False
    try:
        dialogue_bright = int(
            dialogue.get("dialogue_bright")
            or dialogue_region.get("bright")
            or 0
        )
        dialogue_blue = int(
            dialogue.get("dialogue_blue")
            or dialogue_region.get("blue")
            or 0
        )
        card_blue = int(dialogue.get("card_blue") or card.get("blue") or 0)
    except (TypeError, ValueError):
        return False
    return (
        score >= 0.55
        and dark_fraction >= 0.70
        and dialogue_bright >= 1200
        and (dialogue_blue >= 1200 or card_blue >= 4000)
    )


def _lightning_visible_ui_is_perfect_reward_continue_dialogue(
    visible_ui: dict | None,
) -> bool:
    """Detect the post-grid-reward CEO dialogue that masquerades as the grid card."""
    if not isinstance(visible_ui, dict) or visible_ui.get("status") != "OK":
        return False
    if visible_ui.get("visible_ui") != "perfect_reward_choice":
        return False
    if not _lightning_visible_ui_has_continue_text(visible_ui):
        return False
    return _lightning_visible_ui_has_ceo_dialogue_signal(
        visible_ui
    ) or _lightning_visible_ui_has_intro_continue_text(visible_ui)


def _lightning_visible_ui_is_perfect_reward_continue_after_grid_click(
    visible_ui: dict | None,
) -> bool:
    """No-OCR fallback used only after the grid reward was already clicked."""
    if _lightning_visible_ui_is_perfect_reward_continue_dialogue(visible_ui):
        return True
    if not isinstance(visible_ui, dict) or visible_ui.get("status") != "OK":
        return False
    if visible_ui.get("visible_ui") != "perfect_reward_choice":
        return False
    return _lightning_visible_ui_has_ceo_dialogue_signal(visible_ui)


def _lightning_is_safe_clear_ui(
    visible_name: str | None,
    control: str | None = None,
    visible_ui: dict | None = None,
) -> bool:
    if (
        visible_name in {"island_map", "island_map_or_unknown"}
        and control == "bottom_continue"
        and _lightning_visible_ui_is_intro_continue_panel(visible_ui)
    ):
        return True
    if visible_name == "pod_open_panel" and control == "pod_open_door":
        return True
    if visible_name in _LIGHTNING_SAFE_CLEAR_UIS:
        return True
    return visible_name == "mission_preview_panel" and control == "dialogue_textbox"


def _lightning_score_is_actionable(
    score: dict,
    *,
    min_score: float = 0.70,
    min_bright: int = 120,
    min_border: int = 120,
) -> bool:
    return (
        float(score.get("score") or 0.0) >= min_score
        and int(score.get("bright") or 0) >= min_bright
        and int(score.get("border") or 0) >= min_border
    )


_LIGHTNING_CLASSIFIER_MAX_SAMPLE_PIXELS = 36000


def _lightning_sampled_rgb_pixels(
    image: Any,
    box: tuple[int, int, int, int],
    *,
    max_pixels: int = _LIGHTNING_CLASSIFIER_MAX_SAMPLE_PIXELS,
) -> dict:
    """Return sampled RGB pixels while preserving original crop-count scale."""
    width, height = image.size
    left = max(0, min(width, int(box[0])))
    top = max(0, min(height, int(box[1])))
    right = max(left, min(width, int(box[2])))
    bottom = max(top, min(height, int(box[3])))
    crop_w = max(0, right - left)
    crop_h = max(0, bottom - top)
    total = crop_w * crop_h
    if total <= 0:
        return {
            "pixels": [],
            "sampled_pixels": 0,
            "total_pixels": 0,
            "count_scale": 1.0,
            "crop": [left, top, right, bottom],
        }
    sample_w = crop_w
    sample_h = crop_h
    cap = max(1, int(max_pixels))
    if total > cap:
        ratio = (cap / float(total)) ** 0.5
        sample_w = max(1, int(round(crop_w * ratio)))
        sample_h = max(1, int(round(crop_h * ratio)))
    crop = image.crop((left, top, right, bottom)).convert("RGB")
    if sample_w != crop_w or sample_h != crop_h:
        crop = crop.resize((sample_w, sample_h), resample=0)
    pixels = list(crop.getdata())
    sampled = len(pixels) or 1
    return {
        "pixels": pixels,
        "sampled_pixels": sampled,
        "total_pixels": total,
        "count_scale": total / sampled,
        "crop": [left, top, right, bottom],
    }


def _lightning_scaled_pixel_count(count: int, sampled: dict) -> int:
    return int(round(int(count) * float(sampled.get("count_scale") or 1.0)))


def _lightning_prompt_region_stats(
    image: Any,
    rel_box: tuple[float, float, float, float],
) -> dict:
    """Return cheap color statistics for a relative screenshot region."""
    width, height = image.size
    left = max(0, min(width, int(round(rel_box[0] * width))))
    top = max(0, min(height, int(round(rel_box[1] * height))))
    right = max(left + 1, min(width, int(round(rel_box[2] * width))))
    bottom = max(top + 1, min(height, int(round(rel_box[3] * height))))
    sampled = _lightning_sampled_rgb_pixels(image, (left, top, right, bottom))
    pixels = sampled["pixels"]
    sampled_total = max(int(sampled.get("sampled_pixels") or 0), 1)

    def fraction(predicate: Any) -> float:
        return (
            sum(1 for red, green, blue in pixels if predicate(red, green, blue))
            / sampled_total
        )

    return {
        "box": sampled["crop"],
        "pixels": sampled["total_pixels"],
        "mid_dark_fraction": fraction(
            lambda red, green, blue: (
                32 <= red <= 100
                and 32 <= green <= 100
                and 32 <= blue <= 110
                and max(red, green, blue) - min(red, green, blue) <= 35
            )
        ),
        "button_gray_fraction": fraction(
            lambda red, green, blue: (
                55 <= red <= 100
                and 55 <= green <= 100
                and 55 <= blue <= 105
                and max(red, green, blue) - min(red, green, blue) <= 22
            )
        ),
        "bright_text_fraction": fraction(
            lambda red, green, blue: red > 175 and green > 175 and blue > 175
        ),
        "blue_icon_fraction": fraction(
            lambda red, green, blue: blue > 135 and 60 < green < 180 and red < 110
        ),
        "red_icon_fraction": fraction(
            lambda red, green, blue: red > 170 and 30 < green < 120 and blue < 120
        ),
    }


def _lightning_system_privacy_prompt_score(image: Any) -> dict:
    """Detect a macOS privacy prompt over the game without clicking it."""
    card = _lightning_prompt_region_stats(image, (0.385, 0.215, 0.590, 0.665))
    inner = _lightning_prompt_region_stats(image, (0.405, 0.245, 0.575, 0.645))
    text = _lightning_prompt_region_stats(image, (0.405, 0.350, 0.575, 0.540))
    buttons = _lightning_prompt_region_stats(image, (0.400, 0.550, 0.580, 0.640))
    icon = _lightning_prompt_region_stats(image, (0.400, 0.245, 0.455, 0.335))
    icon_color = float(icon["blue_icon_fraction"]) + float(icon["red_icon_fraction"])
    checks = {
        "card_mid_dark": float(card["mid_dark_fraction"]) / 0.65,
        "inner_mid_dark": float(inner["mid_dark_fraction"]) / 0.65,
        "button_gray": float(buttons["button_gray_fraction"]) / 0.45,
        "icon_blue": float(icon["blue_icon_fraction"]) / 0.08,
        "icon_color": icon_color / 0.12,
        "text_bright": float(text["bright_text_fraction"]) / 0.06,
    }
    strict_score = max(0.0, min(1.0, min(checks.values())))
    relaxed_score = max(
        0.0,
        min(
            1.0,
            checks["icon_color"] / 0.80,
            checks["text_bright"] / 0.75,
            checks["button_gray"] / 0.12,
            max(checks["card_mid_dark"], checks["inner_mid_dark"]) / 0.12,
        ),
    )
    score = max(strict_score, relaxed_score)
    return {
        "status": "OK",
        "matched": score >= 1.0,
        "score": score,
        "strict_score": strict_score,
        "relaxed_score": relaxed_score,
        "kind": "macos_screen_audio_privacy_prompt",
        "checks": checks,
        "regions": {
            "card": card,
            "inner": inner,
            "text": text,
            "buttons": buttons,
            "icon": icon,
        },
    }


def _lightning_system_privacy_prompt_visual_match(score: dict | None) -> bool:
    """Return true only for visually unmistakable macOS privacy prompts."""
    if not isinstance(score, dict) or score.get("matched") is not True:
        return False
    try:
        strict_score = float(score.get("strict_score") or 0.0)
        relaxed_score = float(score.get("relaxed_score") or 0.0)
    except (TypeError, ValueError):
        return False
    if strict_score >= 0.92:
        return True
    checks = score.get("checks") if isinstance(score.get("checks"), dict) else {}
    try:
        card = max(
            float(checks.get("card_mid_dark") or 0.0),
            float(checks.get("inner_mid_dark") or 0.0),
        )
        button_gray = float(checks.get("button_gray") or 0.0)
        icon_color = float(checks.get("icon_color") or 0.0)
        text_bright = float(checks.get("text_bright") or 0.0)
    except (TypeError, ValueError):
        return False
    return (
        relaxed_score >= 1.0
        and card >= 0.95
        and button_gray >= 1.0
        and icon_color >= 1.0
        and text_bright >= 1.0
    )


class _CountingOutput:
    """File-like sink that counts redirected output without retaining it."""

    def __init__(self) -> None:
        self.chars = 0
        self.complete_lines = 0
        self.pending_chars = 0

    def write(self, text: str) -> int:
        self.chars += len(text)
        parts = text.split("\n")
        if len(parts) == 1:
            self.pending_chars += len(text)
        else:
            self.complete_lines += len(parts) - 1
            self.pending_chars = len(parts[-1])
        return len(text)

    def flush(self) -> None:
        return None

    @property
    def lines(self) -> int:
        return self.complete_lines + (1 if self.pending_chars else 0)


def _clear_pending_bridge_command(reason: str) -> dict:
    """Remove stale bridge IPC files before a UI-only burst resumes the game."""
    cleared: list[str] = []
    errors: list[dict] = []
    for label, path in (("cmd", CMD_FILE), ("ack", ACK_FILE)):
        try:
            if path.exists():
                path.unlink()
                cleared.append(label)
        except OSError as exc:
            errors.append({"file": label, "path": str(path), "error": str(exc)})
    status = "ERROR" if errors else "OK"
    return {
        "status": status,
        "reason": reason,
        "cleared": cleared,
        "errors": errors,
    }


def _lightning_press_pause_escape(
    *,
    dry_run: bool = False,
    settle_seconds: float = 0.08,
) -> dict:
    """Resume a pause menu without clicking through onto the map beneath it."""
    from src.control.mac_click import press_key

    result = press_key(
        "esc",
        description="Pause menu Escape resume",
        dry_run=dry_run,
        settle_seconds=settle_seconds,
    )
    result["control"] = "pause_menu_escape"
    return result


