def _lightning_resume_key_failed(result: dict) -> bool:
    click_result = result.get("click_result") if isinstance(result, dict) else None
    if not isinstance(click_result, dict):
        return False
    error = str(click_result.get("error") or "")
    return (
        click_result.get("status") != "OK"
        and click_result.get("control") == "pause_menu_escape"
        and "pyautogui key failed" in error
    )


_LIGHTNING_SPEED_DEPLOY_INITIAL_SETTLE_SECONDS = 0.25
_LIGHTNING_SPEED_DEPLOY_BRIDGE_TIMEOUT_SECONDS = 2.5
_LIGHTNING_SPEED_DEPLOY_POST_CONFIRM_SETTLE_SECONDS = 0.70
_LIGHTNING_SPEED_DEPLOY_BRIDGE_READY_SECONDS = 2.4


def _lightning_wait_for_deployment_bridge_ready(
    *,
    timeout_seconds: float = _LIGHTNING_SPEED_DEPLOY_BRIDGE_READY_SECONDS,
) -> dict:
    """Wait after unpausing deployment until the bridge is live and actionable."""
    deadline = time.monotonic() + max(0.1, float(timeout_seconds))
    heartbeat_seen = False
    last_snapshot: dict | None = None
    while time.monotonic() < deadline:
        if not is_bridge_alive(max_stale_sec=0.75):
            time.sleep(0.08)
            continue
        heartbeat_seen = True
        snapshot = _lightning_live_snapshot(refresh=True)
        last_snapshot = snapshot
        if (
            snapshot.get("status") == "OK"
            and _lightning_bridge_snapshot_fresh_enough(snapshot)
            and int(snapshot.get("turn") or 0) == 0
            and int(snapshot.get("deployment_zone_count") or 0) > 0
        ):
            return {
                "status": "OK",
                "reason": "deployment_bridge_ready",
                "snapshot": snapshot,
            }
        time.sleep(0.08)
    return {
        "status": "TIMEOUT",
        "reason": (
            "deployment_bridge_refresh_timeout"
            if heartbeat_seen
            else "deployment_bridge_heartbeat_timeout"
        ),
        "timeout_seconds": timeout_seconds,
        "last_snapshot": last_snapshot,
    }


def _lightning_fast_bridge_deploy_confirm(
    *,
    profile: str = "Alpha",
    quiet: bool = False,
    dry_run: bool = False,
    clear_intro_continue: bool = False,
) -> dict:
    """Resume from verified pause, bridge-deploy, click Confirm, then pause."""
    result: dict = {
        "status": "DRY_RUN" if dry_run else "RUNNING",
        "reason": "fast_bridge_deploy_confirm_started",
        "profile": profile,
    }
    if dry_run:
        result["planned_steps"] = [
            "resume_from_verified_pause",
            "clear_intro_continue_if_requested",
            "deploy_recommended_bridge_first",
            "click_deploy_confirm",
            "esc_pause_and_verify",
        ]
        result["reason"] = "planned_fast_bridge_deploy_confirm"
        return result

    known_live = False

    def pause_after_failure(reason: str) -> dict:
        if not known_live:
            return _lightning_ensure_pause_state(
                dry_run=False,
                reason=reason,
            )
        return _lightning_pause_after_known_live_burst(
            reason=reason,
            transition_settle_seconds=0.05,
        )

    resume = _lightning_resume_if_paused(
        dry_run=False,
        click_ui=True,
        use_verified_guard=True,
        guard_max_age_seconds=120.0,
    )
    result["resume"] = resume
    if resume is None:
        result["resume"] = {
            "status": "SKIPPED",
            "reason": "pause_menu_not_visible_assuming_live_deployment",
            "stale_bridge_cleanup": _clear_pending_bridge_command(
                "fast_deploy_confirm_no_resume",
            ),
        }
        known_live = True
    elif resume.get("status") not in {"OK", "PLANNED"}:
        result["status"] = "ERROR"
        result["reason"] = "resume_failed"
        return result
    else:
        known_live = True

    time.sleep(_LIGHTNING_SPEED_DEPLOY_INITIAL_SETTLE_SECONDS)
    if clear_intro_continue:
        from src.control.mac_click import click_known_window_control

        intro_continue = click_known_window_control(
            "bottom_continue",
            settle_seconds=0.35,
            hold_seconds=0.08,
        )
        result["intro_continue"] = intro_continue
        if intro_continue.get("status") != "OK":
            result["status"] = "ERROR"
            result["reason"] = "intro_continue_failed_before_deploy"
            result["pause_after_failure"] = pause_after_failure(
                "fast_bridge_deploy_confirm_intro_continue_failed",
            )
            return result

    deploy, deploy_output = _lightning_quiet_call(
        cmd_deploy_recommended,
        profile=profile,
        ui_fallback=True,
        prefer_ui_fallback=False,
        verify_after=False,
        deploy_timeout_seconds=_LIGHTNING_SPEED_DEPLOY_BRIDGE_TIMEOUT_SECONDS,
        skip_initial_refresh=True,
        quiet=quiet,
    )
    if deploy_output:
        deploy["quiet_output"] = deploy_output
    result["deploy"] = deploy
    if deploy.get("status") not in {"OK", "WARN"}:
        time.sleep(0.45)
        retry_deploy, retry_output = _lightning_quiet_call(
            cmd_deploy_recommended,
            profile=profile,
            ui_fallback=True,
            prefer_ui_fallback=False,
            verify_after=False,
            deploy_timeout_seconds=_LIGHTNING_SPEED_DEPLOY_BRIDGE_TIMEOUT_SECONDS,
            skip_initial_refresh=True,
            quiet=quiet,
        )
        if retry_output:
            retry_deploy["quiet_output"] = retry_output
        result["deploy_retry"] = retry_deploy
        if retry_deploy.get("status") in {"OK", "WARN"}:
            result["deploy"] = retry_deploy
            deploy = retry_deploy
        else:
            result["status"] = "ERROR"
            result["reason"] = "deploy_failed"
            result["pause_after_failure"] = pause_after_failure(
                "fast_bridge_deploy_confirm_deploy_failed",
            )
            return result
    if deploy.get("status") not in {"OK", "WARN"}:
        result["status"] = "ERROR"
        result["reason"] = "deploy_failed"
        result["pause_after_failure"] = pause_after_failure(
            "fast_bridge_deploy_confirm_deploy_failed",
        )
        return result

    from src.control.mac_click import click_known_window_control

    confirm = click_known_window_control(
        "deploy_confirm",
        settle_seconds=0.10,
        hold_seconds=0.08,
    )
    result["deploy_confirm"] = confirm
    if confirm.get("status") != "OK":
        result["status"] = "ERROR"
        result["reason"] = "deploy_confirm_failed"
        result["pause_after_failure"] = pause_after_failure(
            "fast_bridge_deploy_confirm_confirm_failed",
        )
        return result

    pause = _lightning_pause_after_known_live_burst(
        reason="fast_bridge_deploy_confirm_pause",
        transition_settle_seconds=_LIGHTNING_SPEED_DEPLOY_POST_CONFIRM_SETTLE_SECONDS,
    )
    result["pause"] = pause
    post_confirm_snapshot = _lightning_live_snapshot(refresh=False)
    result["post_confirm_snapshot"] = post_confirm_snapshot
    if post_confirm_snapshot.get("status") == "OK":
        try:
            post_mechs = int(post_confirm_snapshot.get("mech_count") or 0)
        except (TypeError, ValueError):
            post_mechs = 0
        try:
            post_turn = int(post_confirm_snapshot.get("turn") or 0)
        except (TypeError, ValueError):
            post_turn = 0
        post_phase = str(post_confirm_snapshot.get("phase") or "")
        if (
            bool(post_confirm_snapshot.get("in_active_mission"))
            and post_turn == 0
            and post_phase in {"combat_enemy", "combat_player"}
            and post_mechs < _LIGHTNING_EXPECTED_MECH_COUNT
        ):
            result["status"] = "ERROR"
            result["reason"] = "post_confirm_incomplete_deployment"
            return result
        if _lightning_turn_zero_post_deploy_intro_snapshot(post_confirm_snapshot):
            result["post_confirm_state"] = "turn_zero_enemy_intro"
    result["status"] = "OK" if pause.get("status") == "OK" else "WARN"
    result["reason"] = "fast_bridge_deploy_confirm_completed"
    return result


def _lightning_pause_after_known_live_burst(
    *,
    reason: str,
    transition_settle_seconds: float = 0.0,
    dry_run: bool = False,
) -> dict:
    """Pause immediately after a planned live burst that is known unpaused."""
    session = _load_session()
    settle = max(0.0, float(transition_settle_seconds or 0.0))
    if dry_run:
        return {
            "status": "DRY_RUN",
            "reason": "would_pause_after_known_live_burst",
            "planned_control": "pause",
            "transition_settle_seconds": settle,
        }

    if settle:
        time.sleep(settle)
    click_result = _lightning_press_pause_escape(settle_seconds=0.08)
    pause_verify = None
    pause_verified = False
    if click_result.get("status") == "OK":
        pause_verify = _lightning_visible_ui_snapshot(include_ocr=True)
        pause_verified = _lightning_visible_ui_is_pause_menu(pause_verify)
        if (
            not pause_verified
            and isinstance(pause_verify, dict)
            and pause_verify.get("visible_ui")
            in {"island_map", "island_map_or_unknown"}
        ):
            from src.control.mac_click import click_known_window_control

            fallback_click = click_known_window_control("map_menu")
            fallback_verify = None
            fallback_verified = False
            if fallback_click.get("status") == "OK":
                fallback_verify = _lightning_visible_ui_snapshot(include_ocr=True)
                fallback_verified = _lightning_visible_ui_is_pause_menu(
                    fallback_verify,
                )
            if fallback_verified:
                pause_verify = fallback_verify
                pause_verified = True
                click_result = fallback_click
            else:
                if isinstance(pause_verify, dict):
                    pause_verify = dict(pause_verify)
                    pause_verify["map_menu_fallback"] = {
                        "click_result": fallback_click,
                        "pause_verify": fallback_verify,
                        "pause_verified": fallback_verified,
                    }

    status = click_result.get("status", "ERROR")
    result = {
        "status": status,
        "reason": "pause_clicked",
        "planned_control": "pause",
        "known_live_burst": True,
        "transition_settle_seconds": settle,
        "click_result": click_result,
        "pause_verified": pause_verified,
        "pause_verify": pause_verify,
    }
    if click_result.get("status") != "OK":
        result["reason"] = "pause_click_failed"
        result["error"] = click_result.get("error")
    elif not pause_verified:
        result["status"] = "BLOCKED"
        result["reason"] = "pause_not_verified"
        result["safe_to_think"] = False
        result["next_step"] = (
            "Inspect the screen before any timed Lightning action; the planned "
            "post-burst Esc did not visibly reach the pause menu."
        )

    result["guard"] = _lightning_write_guard(
        session,
        guard_status=result["status"],
        reason=reason,
        visible_ui=pause_verify,
        click_result=click_result,
    )
    return result


def _lightning_press_ui_key(
    key: str,
    *,
    description: str,
    dry_run: bool = False,
    settle_seconds: float = 0.08,
) -> dict:
    """Press a trusted non-combat UI key without moving the cursor."""
    from src.control.mac_click import press_key

    result = press_key(
        key,
        description=description,
        dry_run=dry_run,
        settle_seconds=settle_seconds,
    )
    result["control"] = f"ui_key_{str(key).strip().lower()}"
    return result


def _lightning_button_like_score(image, *, center: tuple[int, int],
                                 size: tuple[int, int]) -> dict:
    """Return a conservative score for a visible ITB button crop."""
    width, height = image.size
    base_w, base_h = _LIGHTNING_UI_BASE_SIZE
    scale_x = width / base_w if base_w else 1.0
    scale_y = height / base_h if base_h else 1.0
    cx, cy = center
    sw, sh = size
    scaled_cx = cx * scale_x
    scaled_cy = cy * scale_y
    scaled_w = sw * scale_x
    scaled_h = sh * scale_y
    left = max(0, int(scaled_cx - scaled_w / 2))
    top = max(0, int(scaled_cy - scaled_h / 2))
    right = min(width, int(scaled_cx + scaled_w / 2))
    bottom = min(height, int(scaled_cy + scaled_h / 2))
    if right <= left or bottom <= top:
        return {"score": 0.0, "bright": 0, "border": 0, "pixels": 0}
    sampled = _lightning_sampled_rgb_pixels(image, (left, top, right, bottom))
    pixels = sampled["pixels"]
    total = int(sampled.get("total_pixels") or 1)
    bright = 0
    border = 0
    for r, g, b in pixels:
        if r >= 185 and g >= 185 and b >= 185:
            bright += 1
        if 45 <= r <= 145 and 60 <= g <= 160 and 85 <= b <= 210 and b >= r + 20:
            border += 1
    bright = _lightning_scaled_pixel_count(bright, sampled)
    border = _lightning_scaled_pixel_count(border, sampled)
    bright_frac = bright / total
    border_frac = border / total
    score = (bright_frac * 10.0) + (border_frac * 4.0)
    return {
        "score": round(score, 4),
        "bright": bright,
        "border": border,
        "pixels": total,
        "crop": sampled["crop"],
    }


def _lightning_dark_overlay_fraction(image) -> float:
    """Estimate whether a modal/pause overlay is dimming the main game view."""
    width, height = image.size
    left = int(width * 0.12)
    top = int(height * 0.08)
    right = int(width * 0.90)
    bottom = int(height * 0.90)
    if right <= left or bottom <= top:
        return 0.0
    sampled = _lightning_sampled_rgb_pixels(image, (left, top, right, bottom))
    pixels = sampled["pixels"]
    total = int(sampled.get("sampled_pixels") or 1)
    dark = sum(1 for r, g, b in pixels if r < 45 and g < 45 and b < 55)
    return round(dark / total, 4)


def _lightning_start_mission_score(image) -> dict:
    """Detect the large yellow Start Mission text on a mission preview board."""
    width, height = image.size
    base_w, base_h = _LIGHTNING_UI_BASE_SIZE
    scale_x = width / base_w if base_w else 1.0
    scale_y = height / base_h if base_h else 1.0
    cx, cy = 815, 468
    sw, sh = 520, 260
    left = max(0, int((cx - sw / 2) * scale_x))
    top = max(0, int((cy - sh / 2) * scale_y))
    right = min(width, int((cx + sw / 2) * scale_x))
    bottom = min(height, int((cy + sh / 2) * scale_y))
    if right <= left or bottom <= top:
        return {"score": 0.0, "yellow": 0, "pixels": 0}
    sampled = _lightning_sampled_rgb_pixels(image, (left, top, right, bottom))
    pixels = sampled["pixels"]
    total = int(sampled.get("total_pixels") or 1)
    yellow = sum(1 for r, g, b in pixels if r > 180 and g > 150 and b < 80)
    yellow = _lightning_scaled_pixel_count(yellow, sampled)
    score = yellow / total
    return {
        "score": round(score, 4),
        "yellow": yellow,
        "pixels": total,
        "crop": sampled["crop"],
    }


def _lightning_start_mission_ocr_target(
    image_path: str | Path,
    *,
    search_crop: list[int],
    scale_x: float,
    scale_y: float,
) -> dict:
    """Find the Start Mission label by OCR when yellow-pixel clustering fails."""
    ocr = _lightning_ocr_texts_from_image(image_path)
    observations = ocr.get("observations") if isinstance(ocr, dict) else None
    if not isinstance(observations, list):
        return {
            "status": "NOT_FOUND",
            "reason": "ocr_start_text_not_found",
            "ocr": ocr,
        }
    left, top, right, bottom = [int(value) for value in search_crop]
    for obs in observations:
        if not isinstance(obs, dict):
            continue
        text = str(obs.get("text") or "")
        letters = re.sub(r"[^a-z]", "", text.lower())
        if "startmission" not in letters:
            continue
        center = obs.get("center_image")
        if (
            not isinstance(center, list)
            or len(center) < 2
            or center[0] is None
            or center[1] is None
        ):
            continue
        cx = float(center[0])
        cy = float(center[1])
        if not (left <= cx <= right and top <= cy <= bottom):
            continue
        if os.name == "nt":
            window_x = int(round(cx))
            window_y = int(round(cy))
        else:
            window_x = int(round(cx / scale_x))
            window_y = int(round(cy / scale_y))
        return {
            "status": "OK",
            "window_x": window_x,
            "window_y": window_y,
            "source": "ocr_start_text",
            "ocr_text": text,
            "ocr_observation": obs,
            "ocr": ocr,
        }
    return {
        "status": "NOT_FOUND",
        "reason": "ocr_start_text_not_found",
        "ocr": ocr,
    }


def _lightning_advisor_preview_score(image) -> dict:
    """Detect a mission preview covered by an advisor dialogue textbox."""
    width, height = image.size
    base_w, base_h = _LIGHTNING_UI_BASE_SIZE
    scale_x = width / base_w if base_w else 1.0
    scale_y = height / base_h if base_h else 1.0

    def crop_counts(box: tuple[int, int, int, int]) -> dict:
        left = max(0, int(box[0] * scale_x))
        top = max(0, int(box[1] * scale_y))
        right = min(width, int(box[2] * scale_x))
        bottom = min(height, int(box[3] * scale_y))
        if right <= left or bottom <= top:
            return {
                "red": 0,
                "blue": 0,
                "bright": 0,
                "dark_fraction": 0.0,
                "pixels": 0,
                "crop": [left, top, right, bottom],
            }
        sampled = _lightning_sampled_rgb_pixels(image, (left, top, right, bottom))
        pixels = sampled["pixels"]
        sampled_total = int(sampled.get("sampled_pixels") or 1)
        total = int(sampled.get("total_pixels") or 1)
        red = 0
        blue = 0
        bright = 0
        dark = 0
        for r, g, b in pixels:
            if r >= 160 and g <= 100 and b <= 110 and r >= g + 45:
                red += 1
            if 35 <= r <= 145 and 55 <= g <= 170 and 80 <= b <= 220 and b >= r + 20:
                blue += 1
            if r >= 180 and g >= 180 and b >= 180:
                bright += 1
            if r < 45 and g < 45 and b < 55:
                dark += 1
        red = _lightning_scaled_pixel_count(red, sampled)
        blue = _lightning_scaled_pixel_count(blue, sampled)
        bright = _lightning_scaled_pixel_count(bright, sampled)
        return {
            "red": red,
            "blue": blue,
            "bright": bright,
            "dark_fraction": round(dark / sampled_total, 4),
            "pixels": total,
            "crop": sampled["crop"],
        }

    card = crop_counts((250, 350, 1060, 590))
    dialogue = crop_counts((130, 165, 1150, 285))
    card_score = min(card["red"] / 1000.0, 1.0) + min(card["blue"] / 12000.0, 1.0)
    dialogue_score = (
        min(dialogue["blue"] / 3500.0, 1.0)
        + min(dialogue["bright"] / 3000.0, 1.0)
        + min(dialogue["dark_fraction"] / 0.75, 1.0)
    )
    score = (card_score + dialogue_score) / 5.0
    return {
        "score": round(score, 4),
        "card": card,
        "dialogue": dialogue,
    }


def _lightning_deployment_screen_score(image) -> dict:
    """Detect the live deployment screen so pause guards do not waste time."""
    width, height = image.size
    base_w, base_h = _LIGHTNING_UI_BASE_SIZE
    scale_x = width / base_w if base_w else 1.0
    scale_y = height / base_h if base_h else 1.0
    left = int(240 * scale_x)
    top = int(90 * scale_y)
    right = int(980 * scale_x)
    bottom = int(640 * scale_y)
    if right <= left or bottom <= top:
        return {"score": 0.0, "yellow": 0, "pixels": 0}
    sampled = _lightning_sampled_rgb_pixels(image, (left, top, right, bottom))
    pixels = sampled["pixels"]
    total = int(sampled.get("total_pixels") or 1)
    yellow = 0
    for r, g, b in pixels:
        if r >= 160 and g >= 130 and b <= 110 and r >= b + 45 and g >= b + 35:
            yellow += 1
    yellow = _lightning_scaled_pixel_count(yellow, sampled)
    return {
        "score": round(yellow / total, 4),
        "yellow": yellow,
        "pixels": total,
        "crop": sampled["crop"],
    }


def _lightning_island_map_score(image) -> dict:
    """Detect saturated red/green corporate territory regions on the island map."""
    width, height = image.size
    base_w, base_h = _LIGHTNING_UI_BASE_SIZE
    scale_x = width / base_w if base_w else 1.0
    scale_y = height / base_h if base_h else 1.0
    left = int(420 * scale_x)
    top = int(170 * scale_y)
    right = int(1120 * scale_x)
    bottom = int(690 * scale_y)
    if right <= left or bottom <= top:
        return {"score": 0.0, "red": 0, "green": 0, "pixels": 0}
    sampled = _lightning_sampled_rgb_pixels(image, (left, top, right, bottom))
    pixels = sampled["pixels"]
    total = int(sampled.get("total_pixels") or 1)
    red = 0
    green = 0
    for r, g, b in pixels:
        if r >= 120 and g <= 95 and b <= 95 and r >= g + 35:
            red += 1
        elif g >= 95 and r <= 120 and b <= 120 and g >= r + 25:
            green += 1
    red = _lightning_scaled_pixel_count(red, sampled)
    green = _lightning_scaled_pixel_count(green, sampled)
    colored = red + green
    return {
        "score": round(colored / total, 4),
        "red": red,
        "green": green,
        "colored": colored,
        "pixels": total,
        "crop": sampled["crop"],
    }


def _lightning_start_mission_target(image_path: str | Path) -> dict:
    """Find a robust window-local click target for visible Start Mission text."""
    try:
        from PIL import Image
    except Exception as exc:
        return {"status": "UNAVAILABLE", "error": f"PIL unavailable: {exc}"}
    try:
        image = Image.open(image_path).convert("RGB")
    except Exception as exc:
        return {"status": "ERROR", "error": f"failed to open screenshot: {exc}"}

    width, height = image.size
    base_w, base_h = _LIGHTNING_UI_BASE_SIZE
    scale_x = width / base_w if base_w else 1.0
    scale_y = height / base_h if base_h else 1.0
    left = int(520 * scale_x)
    top = int(300 * scale_y)
    right = int(1180 * scale_x)
    bottom = int(690 * scale_y)
    crop_w = max(0, right - left)
    crop_h = max(0, bottom - top)
    if crop_w <= 0 or crop_h <= 0:
        return {
            "status": "NOT_FOUND",
            "yellow": 0,
            "search_crop": [left, top, right, bottom],
        }
    pixels = image.load()
    mask = bytearray(crop_w * crop_h)
    yellow = 0
    for y in range(max(0, top), min(height, bottom)):
        row = (y - top) * crop_w
        for x in range(max(0, left), min(width, right)):
            r, g, b = pixels[x, y]
            if r > 180 and g > 150 and b < 90:
                mask[row + (x - left)] = 1
                yellow += 1
    if yellow < 500:
        ocr_target = _lightning_start_mission_ocr_target(
            image_path,
            search_crop=[left, top, right, bottom],
            scale_x=scale_x,
            scale_y=scale_y,
        )
        if ocr_target.get("status") == "OK":
            return {
                **ocr_target,
                "yellow": yellow,
                "search_crop": [left, top, right, bottom],
                "image_size": [width, height],
                "pixel_detection_reason": "yellow_below_threshold",
            }
        return {
            "status": "NOT_FOUND",
            "yellow": yellow,
            "search_crop": [left, top, right, bottom],
            "ocr_target": ocr_target,
        }

    visited = bytearray(crop_w * crop_h)
    components: list[dict] = []
    for start, is_yellow in enumerate(mask):
        if not is_yellow or visited[start]:
            continue
        stack = [start]
        visited[start] = 1
        count = 0
        sum_x = 0
        sum_y = 0
        min_x = crop_w
        min_y = crop_h
        max_x = 0
        max_y = 0
        while stack:
            idx = stack.pop()
            cx = idx % crop_w
            cy = idx // crop_w
            count += 1
            sum_x += cx
            sum_y += cy
            min_x = min(min_x, cx)
            min_y = min(min_y, cy)
            max_x = max(max_x, cx)
            max_y = max(max_y, cy)
            for neighbor in (
                idx - 1 if cx > 0 else -1,
                idx + 1 if cx + 1 < crop_w else -1,
                idx - crop_w if cy > 0 else -1,
                idx + crop_w if cy + 1 < crop_h else -1,
            ):
                if neighbor >= 0 and mask[neighbor] and not visited[neighbor]:
                    visited[neighbor] = 1
                    stack.append(neighbor)
        if count < 20:
            continue
        window_min_x = (left + min_x) / scale_x
        window_min_y = (top + min_y) / scale_y
        window_max_x = (left + max_x) / scale_x
        window_max_y = (top + max_y) / scale_y
        comp_width = window_max_x - window_min_x
        comp_height = window_max_y - window_min_y
        components.append(
            {
                "area": count,
                "window_min_x": window_min_x,
                "window_min_y": window_min_y,
                "window_max_x": window_max_x,
                "window_max_y": window_max_y,
                "window_cx": ((left + (sum_x / count)) / scale_x),
                "window_cy": ((top + (sum_y / count)) / scale_y),
                "window_width": comp_width,
                "window_height": comp_height,
            }
        )

    min_component_width = 1.0 if os.name == "nt" else 4.0
    min_component_height = 6.0 if os.name == "nt" else 8.0
    min_cluster_span_x = 45.0 if os.name == "nt" else 60.0
    max_cluster_span_y = 90.0
    candidates = [
        comp
        for comp in components
        if (
            80 <= comp["area"] <= 100000
            and min_component_width <= comp["window_width"] <= 320
            and min_component_height <= comp["window_height"] <= 80
            and comp["window_cy"] <= 560
        )
    ]
    clusters: list[list[dict]] = []
    for comp in sorted(candidates, key=lambda item: item["window_cy"]):
        for cluster in clusters:
            weight = sum(item["area"] for item in cluster) or 1
            cluster_y = sum(
                item["window_cy"] * item["area"] for item in cluster
            ) / weight
            if abs(cluster_y - comp["window_cy"]) <= 28:
                cluster.append(comp)
                break
        else:
            clusters.append([comp])

    best_cluster = None
    best_score = 0.0
    for cluster in clusters:
        min_x = min(item["window_min_x"] for item in cluster)
        max_x = max(item["window_max_x"] for item in cluster)
        min_y = min(item["window_min_y"] for item in cluster)
        max_y = max(item["window_max_y"] for item in cluster)
        span_x = max_x - min_x
        span_y = max_y - min_y
        area = sum(item["area"] for item in cluster)
        if span_x < min_cluster_span_x or span_y > max_cluster_span_y:
            continue
        score = area * (1.0 + min(span_x, 360) / 120.0)
        if score > best_score:
            best_score = score
            best_cluster = {
                "area": area,
                "span_x": span_x,
                "span_y": span_y,
                "window_min_x": min_x,
                "window_max_x": max_x,
                "window_min_y": min_y,
                "window_max_y": max_y,
            }

    if best_cluster is None:
        ocr_target = _lightning_start_mission_ocr_target(
            image_path,
            search_crop=[left, top, right, bottom],
            scale_x=scale_x,
            scale_y=scale_y,
        )
        if ocr_target.get("status") == "OK":
            return {
                **ocr_target,
                "yellow": yellow,
                "search_crop": [left, top, right, bottom],
                "image_size": [width, height],
                "component_count": len(components),
                "pixel_detection_reason": "no_start_text_cluster",
            }
        return {
            "status": "NOT_FOUND",
            "yellow": yellow,
            "search_crop": [left, top, right, bottom],
            "component_count": len(components),
            "reason": "no_start_text_cluster",
            "ocr_target": ocr_target,
        }

    ocr_target = _lightning_start_mission_ocr_target(
        image_path,
        search_crop=[left, top, right, bottom],
        scale_x=scale_x,
        scale_y=scale_y,
    )
    if ocr_target.get("status") == "OK":
        return {
            **ocr_target,
            "yellow": yellow,
            "search_crop": [left, top, right, bottom],
            "image_size": [width, height],
            "component_count": len(components),
            "cluster": best_cluster,
            "pixel_detection_reason": "ocr_start_text_confirmed",
        }
    if os.environ.get("ITB_ALLOW_PIXEL_ONLY_START_MISSION") != "1":
        return {
            "status": "NOT_FOUND",
            "yellow": yellow,
            "search_crop": [left, top, right, bottom],
            "image_size": [width, height],
            "component_count": len(components),
            "cluster": best_cluster,
            "reason": "pixel_cluster_without_ocr_start_text",
            "ocr_target": ocr_target,
        }

    window_x_base = (
        best_cluster["window_min_x"] + best_cluster["window_max_x"]
    ) / 2
    window_y_base = (
        best_cluster["window_min_y"] + best_cluster["window_max_y"]
    ) / 2
    if os.name == "nt":
        # Windows screenshots are captured in physical window pixels, and
        # click_window_point consumes that same coordinate space.
        window_x = int(round(window_x_base * scale_x))
        window_y = int(round(window_y_base * scale_y))
    else:
        window_x = int(round(window_x_base))
        window_y = int(round(window_y_base))
    return {
        "status": "OK",
        "window_x": window_x,
        "window_y": window_y,
        "yellow": yellow,
        "search_crop": [left, top, right, bottom],
        "image_size": [width, height],
        "component_count": len(components),
        "cluster": best_cluster,
    }


def _lightning_trusted_preview_ocr_start_target(
    visible_preview_ocr: dict | None,
) -> dict:
    """Find Start Mission from the already-trusted preview OCR screenshot."""
    if not isinstance(visible_preview_ocr, dict):
        return {"status": "NOT_FOUND", "reason": "missing_visible_preview_ocr"}
    screenshot_path = str(visible_preview_ocr.get("screenshot_path") or "").strip()
    if not screenshot_path:
        return {"status": "NOT_FOUND", "reason": "missing_preview_screenshot_path"}
    try:
        from PIL import Image
    except Exception as exc:
        return {"status": "UNAVAILABLE", "error": f"PIL unavailable: {exc}"}
    try:
        image = Image.open(screenshot_path)
    except Exception as exc:
        return {"status": "ERROR", "error": f"failed to open screenshot: {exc}"}
    width, height = image.size
    base_w, base_h = _LIGHTNING_UI_BASE_SIZE
    scale_x = width / base_w if base_w else 1.0
    scale_y = height / base_h if base_h else 1.0
    target = _lightning_start_mission_ocr_target(
        screenshot_path,
        search_crop=[0, 0, width, int(height * 0.92)],
        scale_x=scale_x,
        scale_y=scale_y,
    )
    if target.get("status") == "OK":
        target["source"] = "trusted_preview_ocr_start_text"
        target["screenshot_path"] = screenshot_path
        target["preview_mission_id"] = visible_preview_ocr.get("mission_id")
    return target


def _classify_lightning_ui_image(image_path: str | Path) -> dict:
    """Classify obvious non-combat panels from a window screenshot."""
    try:
        from PIL import Image
    except Exception as exc:
        return {"status": "UNAVAILABLE", "error": f"PIL unavailable: {exc}"}
    try:
        image = Image.open(image_path).convert("RGB")
    except Exception as exc:
        return {"status": "ERROR", "error": f"failed to open screenshot: {exc}"}

    scores: dict[str, dict] = {}
    for name, spec in _LIGHTNING_UI_BUTTON_CROPS.items():
        scores[name] = _lightning_button_like_score(
            image,
            center=spec["center"],
            size=spec["size"],
        )
    dark_overlay = _lightning_dark_overlay_fraction(image)
    start_mission = _lightning_start_mission_score(image)
    scores["mission_preview_panel"] = start_mission
    advisor_preview = _lightning_advisor_preview_score(image)
    scores["mission_preview_dialogue"] = advisor_preview
    deployment = _lightning_deployment_screen_score(image)
    scores["deployment_screen"] = deployment
    paused_deployment_underlay = _lightning_paused_deployment_underlay_score(image)
    scores["paused_deployment_underlay"] = paused_deployment_underlay
    island_map = _lightning_island_map_score(image)
    scores["island_map"] = island_map
    loadout_header = _lightning_button_like_score(
        image,
        center=(470, 176),
        size=(660, 70),
    )
    loadout_storage = _lightning_button_like_score(
        image,
        center=(950, 410),
        size=(150, 360),
    )
    loadout_test_mech = _lightning_button_like_score(
        image,
        center=(785, 615),
        size=(150, 50),
    )
    loadout_install = _lightning_button_like_score(
        image,
        center=(465, 500),
        size=(110, 100),
    )
    scores["mech_loadout_screen"] = {
        "score": min(
            float(loadout_header.get("score") or 0.0),
            float(loadout_test_mech.get("score") or 0.0),
        ),
        "header": loadout_header,
        "storage": loadout_storage,
        "test_mech": loadout_test_mech,
        "install": loadout_install,
    }
    setup_back = _lightning_button_like_score(
        image,
        center=(291, 83),
        size=(220, 80),
    )
    setup_start = _lightning_button_like_score(
        image,
        center=(1005, 83),
        size=(220, 80),
    )
    setup_back_windows = _lightning_button_like_score(
        image,
        center=(755, 248),
        size=(130, 44),
    )
    setup_start_windows = _lightning_button_like_score(
        image,
        center=(856, 248),
        size=(130, 44),
    )
    scores["new_game_setup_back"] = setup_back
    scores["new_game_setup_start"] = setup_start
    scores["new_game_setup_back_windows"] = setup_back_windows
    scores["new_game_setup_start_windows"] = setup_start_windows
    options_header = _lightning_button_like_score(
        image,
        center=(250, 95),
        size=(220, 80),
    )
    options_close = _lightning_button_like_score(
        image,
        center=(890, 680),
        size=(360, 80),
    )
    scores["options_header"] = options_header
    scores["options_close"] = options_close
    system_prompt = _lightning_system_privacy_prompt_score(image)
    scores["system_privacy_prompt"] = system_prompt
    if _lightning_system_privacy_prompt_visual_match(system_prompt):
        return {
            "status": "OK",
            "visible_ui": "system_privacy_prompt",
            "recommended_control": None,
            "confidence": system_prompt.get("score", 1.0),
            "dark_overlay_fraction": dark_overlay,
            "scores": scores,
            "requires_user_authorization": True,
            "external_prompt": {
                "status": "OK",
                "matched": True,
                "kind": "macos_screen_audio_privacy_prompt",
                "source": "visual_geometry",
            },
        }
    # We only promote very strong visual matches. Weaker prompt-like geometry is
    # kept in scores for cheap OCR routing because ITB's dark UI can rhyme with
    # macOS dialog shapes.
    title_continue = scores.get("title_continue", {})
    title_new_game = scores.get("title_new_game", {})
    if os.name == "nt":
        windows_title_new_game = _lightning_button_like_score(
            image,
            center=(68, 150),
            size=(160, 34),
        )
        windows_title_options = _lightning_button_like_score(
            image,
            center=(68, 172),
            size=(160, 34),
        )
        scores["title_new_game_windows"] = windows_title_new_game
        scores["title_options_windows"] = windows_title_options
        if (
            dark_overlay < 0.55
            and windows_title_new_game.get("score", 0.0) >= 0.40
            and windows_title_options.get("score", 0.0) >= 0.50
            and windows_title_new_game.get("bright", 0) >= 700
            and windows_title_options.get("bright", 0) >= 1000
        ):
            return {
                "status": "OK",
                "visible_ui": "title_screen",
                "recommended_control": "title_new_game",
                "confidence": min(
                    windows_title_new_game["score"],
                    windows_title_options["score"],
                ),
                "dark_overlay_fraction": dark_overlay,
                "scores": scores,
            }
    if (
        dark_overlay >= 0.70
        and setup_back_windows.get("score", 0.0) >= 0.80
        and setup_start_windows.get("score", 0.0) >= 0.80
        and setup_back_windows.get("bright", 0) >= 150
        and setup_start_windows.get("bright", 0) >= 150
        and setup_back_windows.get("border", 0) >= 2500
        and setup_start_windows.get("border", 0) >= 2500
    ):
        return {
            "status": "OK",
            "visible_ui": "new_game_setup",
            "recommended_control": None,
            "confidence": min(
                setup_back_windows["score"],
                setup_start_windows["score"],
            ),
            "dark_overlay_fraction": dark_overlay,
            "scores": scores,
        }
    start_mission_visible = (
        dark_overlay >= 0.60
        and start_mission.get("yellow", 0) >= 2000
        and start_mission.get("score", 0.0) >= 0.006
    )
    advisor_preview_visible = (
        dark_overlay >= 0.70
        and advisor_preview.get("score", 0.0) >= 0.70
        and advisor_preview.get("card", {}).get("red", 0) >= 1000
        and advisor_preview.get("card", {}).get("blue", 0) >= 7000
        and advisor_preview.get("dialogue", {}).get("blue", 0) >= 3500
        and advisor_preview.get("dialogue", {}).get("bright", 0) >= 2500
        and advisor_preview.get("dialogue", {}).get("dark_fraction", 0.0) >= 0.75
    )
    if (
        dark_overlay >= 0.70
        and options_header.get("score", 0.0) >= 1.0
        and options_header.get("bright", 0) >= 1500
        and options_header.get("border", 0) >= 4000
        and options_close.get("score", 0.0) >= 0.45
        and options_close.get("bright", 0) >= 1000
        and options_close.get("border", 0) >= 1000
        and setup_start.get("score", 0.0) < 0.60
        and setup_start_windows.get("score", 0.0) < 0.70
    ):
        return {
            "status": "OK",
            "visible_ui": "options_menu",
            "recommended_control": "options_close",
            "confidence": min(options_header["score"], options_close["score"]),
            "dark_overlay_fraction": dark_overlay,
            "scores": scores,
        }
    if (
        dark_overlay >= 0.60
        and not start_mission_visible
        and not advisor_preview_visible
        and setup_back.get("score", 0.0) >= 0.85
        and setup_start.get("score", 0.0) >= 0.85
        and setup_back.get("bright", 0) >= 700
        and setup_start.get("bright", 0) >= 700
    ):
        return {
            "status": "OK",
            "visible_ui": "new_game_setup",
            "recommended_control": None,
            "confidence": min(setup_back["score"], setup_start["score"]),
            "dark_overlay_fraction": dark_overlay,
            "scores": scores,
        }
    bottom_continue = scores.get("bottom_continue_panel", {})
    if os.name == "nt":
        # Windows' full-screen layout puts the post-mission Continue button
        # much farther left/up than the old 1280x748 crop. Without this
        # override, Region Secured dialogue can look like the dim pause menu.
        windows_bottom_continue = _lightning_button_like_score(
            image,
            center=(810, 510),
            size=(150, 42),
        )
        scores["bottom_continue_panel_windows"] = windows_bottom_continue
        if (
            dark_overlay >= 0.70
            and windows_bottom_continue.get("score", 0.0) >= 0.70
            and windows_bottom_continue.get("bright", 0) >= 800
            and windows_bottom_continue.get("border", 0) >= 900
        ):
            return {
                "status": "OK",
                "visible_ui": "bottom_continue_panel",
                "recommended_control": "reward_continue",
                "confidence": windows_bottom_continue["score"],
                "dark_overlay_fraction": dark_overlay,
                "scores": scores,
            }
    if (
        dark_overlay >= 0.70
        and bottom_continue.get("score", 0.0) >= 0.70
        and bottom_continue.get("bright", 0) >= 1000
        and bottom_continue.get("border", 0) >= 1000
    ):
        return {
            "status": "OK",
            "visible_ui": "reward_panel",
            "recommended_control": "reward_continue",
            "confidence": bottom_continue["score"],
            "dark_overlay_fraction": dark_overlay,
            "scores": scores,
        }
    if (
        dark_overlay < 0.55
        and _lightning_score_is_actionable(
            title_continue,
            min_score=0.35,
            min_bright=80,
            min_border=0,
        )
        and _lightning_score_is_actionable(
            title_new_game,
            min_score=0.35,
            min_bright=80,
            min_border=0,
        )
    ):
        return {
            "status": "OK",
            "visible_ui": "title_screen",
            "recommended_control": "title_new_game",
            "confidence": min(
                float(title_continue["score"]),
                float(title_new_game["score"]),
            ),
            "dark_overlay_fraction": dark_overlay,
            "scores": scores,
        }
    if start_mission_visible:
        return {
            "status": "OK",
            "visible_ui": "mission_preview_panel",
            "recommended_control": "mission_preview_board",
            "confidence": start_mission["score"],
            "dark_overlay_fraction": dark_overlay,
            "scores": scores,
        }
    if advisor_preview_visible:
        return {
            "status": "OK",
            "visible_ui": "mission_preview_panel",
            "recommended_control": "dialogue_textbox",
            "confidence": advisor_preview["score"],
            "dark_overlay_fraction": dark_overlay,
            "scores": scores,
        }
    loadout = scores["mech_loadout_screen"]
    if (
        dark_overlay >= 0.72
        and float(loadout_header.get("score") or 0.0) >= 0.90
        and float(loadout_test_mech.get("score") or 0.0) >= 0.75
        and int(loadout_test_mech.get("border") or 0) >= 2500
        and (
            float(loadout_storage.get("score") or 0.0) >= 0.18
            or float(loadout_install.get("score") or 0.0) >= 0.45
        )
        and island_map.get("colored", 0) < 5000
    ):
        return {
            "status": "OK",
            "visible_ui": "mech_loadout_screen",
            "recommended_control": None,
            "confidence": loadout["score"],
            "dark_overlay_fraction": dark_overlay,
            "scores": scores,
        }
    if (
        dark_overlay >= 0.60
        and setup_back.get("score", 0.0) >= 0.85
        and setup_start.get("score", 0.0) >= 0.85
        and setup_back.get("bright", 0) >= 700
        and setup_start.get("bright", 0) >= 700
    ):
        return {
            "status": "OK",
            "visible_ui": "new_game_setup",
            "recommended_control": None,
            "confidence": min(setup_back["score"], setup_start["score"]),
            "dark_overlay_fraction": dark_overlay,
            "scores": scores,
        }
    if (
        dark_overlay < 0.60
        and deployment.get("yellow", 0) >= 12000
        and deployment.get("score", 0.0) >= 0.025
    ):
        return {
            "status": "OK",
            "visible_ui": "deployment_screen",
            "recommended_control": "deploy_confirm",
            "confidence": deployment["score"],
            "dark_overlay_fraction": dark_overlay,
            "scores": scores,
        }
    if (
        dark_overlay < 0.70
        and paused_deployment_underlay.get("visible")
        and int(paused_deployment_underlay.get("signal_count") or 0) >= 4
        and (
            int(island_map.get("colored") or 0) < 8000
            or float(island_map.get("score") or 0.0) < 0.035
        )
    ):
        return {
            "status": "OK",
            "visible_ui": "deployment_screen",
            "recommended_control": "deploy_confirm",
            "confidence": paused_deployment_underlay.get("score", 0.0),
            "dark_overlay_fraction": dark_overlay,
            "scores": scores,
        }
    pause_score = scores.get("pause_menu", {})
    pause_pixels = max(int(pause_score.get("pixels", 0) or 1), 1)
    pause_border_fraction = (
        pause_score.get("border", 0) / pause_pixels
    )
    pause_bright_fraction = (
        pause_score.get("bright", 0) / pause_pixels
    )
    if (
        dark_overlay >= 0.70
        and (
            (
                pause_score.get("score", 0.0) >= 0.34
                and pause_score.get("bright", 0) >= 120
                and pause_border_fraction >= 0.045
            )
            or (
                dark_overlay >= 0.90
                and pause_score.get("score", 0.0) >= 0.14
                and pause_score.get("bright", 0) >= 900
                and pause_score.get("border", 0) >= 1000
                and pause_border_fraction >= 0.010
                and pause_bright_fraction <= 0.03
            )
        )
    ):
        spec = _LIGHTNING_UI_BUTTON_CROPS["pause_menu"]
        return {
            "status": "OK",
            "visible_ui": "pause_menu",
            "recommended_control": spec["control"],
            "confidence": pause_score["score"],
            "dark_overlay_fraction": dark_overlay,
            "scores": scores,
        }

    leave_score = scores.get("island_complete_leave", {})
    if (
        dark_overlay >= 0.55
        and island_map.get("colored", 0) >= 12000
        and island_map.get("score", 0.0) >= 0.045
        and _lightning_score_is_actionable(
            leave_score,
            min_score=0.50,
            min_bright=250,
            min_border=250,
        )
    ):
        spec = _LIGHTNING_UI_BUTTON_CROPS["island_complete_leave"]
        return {
            "status": "OK",
            "visible_ui": "island_complete_leave",
            "recommended_control": spec["control"],
            "confidence": leave_score["score"],
            "dark_overlay_fraction": dark_overlay,
            "scores": scores,
        }

    # Perfect Island has two distinct states: a dialogue with a wide Continue
    # button, then a reward picker. The broad bottom-panel crops can score
    # higher on the dialogue art, so recognize these before generic reward
    # continuations.
    if dark_overlay >= 0.60:
        generic_continue = {
            name: scores.get(name, {})
            for name in ("bottom_continue_panel", "reward_panel")
        }
        reward_choice_probe = scores.get("perfect_reward_choice", {})
        generic_hits = [
            (name, score)
            for name, score in generic_continue.items()
            if (
                _lightning_score_is_actionable(score, min_score=0.70)
                and float(reward_choice_probe.get("score") or 0.0) < 0.80
            )
        ]
        if generic_hits:
            name, score = max(
                generic_hits,
                key=lambda item: float(item[1].get("score") or 0.0),
            )
            spec = _LIGHTNING_UI_BUTTON_CROPS[name]
            return {
                "status": "OK",
                "visible_ui": name,
                "recommended_control": spec["control"],
                "confidence": score["score"],
                "dark_overlay_fraction": dark_overlay,
                "scores": scores,
            }
        if (
            island_map.get("red", 0) >= 5000
            and island_map.get("colored", 0) >= 12000
            and island_map.get("score", 0.0) >= 0.05
        ):
            return {
                "status": "OK",
                "visible_ui": "island_map",
                "recommended_control": None,
                "confidence": island_map["score"],
                "dark_overlay_fraction": dark_overlay,
                "scores": scores,
            }
        reward_choice = scores.get("perfect_reward_choice", {})
        if _lightning_score_is_actionable(
            reward_choice,
            min_score=0.55,
            min_bright=350,
            min_border=350,
        ):
            spec = _LIGHTNING_UI_BUTTON_CROPS["perfect_reward_choice"]
            return {
                "status": "OK",
                "visible_ui": "perfect_reward_choice",
                "recommended_control": spec["control"],
                "confidence": reward_choice["score"],
                "dark_overlay_fraction": dark_overlay,
                "scores": scores,
            }
        perfect = scores.get("perfect_island_panel", {})
        strongest_generic_continue = max(
            float(scores.get(name, {}).get("score") or 0.0)
            for name in ("bottom_continue_panel", "reward_panel", "promotion_panel")
        )
        if _lightning_score_is_actionable(
            perfect,
            min_score=0.40,
            min_bright=350,
            min_border=350,
        ) and (
            strongest_generic_continue < 0.70
            or float(perfect.get("score") or 0.0) > strongest_generic_continue
        ):
            spec = _LIGHTNING_UI_BUTTON_CROPS["perfect_island_panel"]
            return {
                "status": "OK",
                "visible_ui": "perfect_island_panel",
                "recommended_control": spec["control"],
                "confidence": perfect["score"],
                "dark_overlay_fraction": dark_overlay,
                "scores": scores,
            }

    # Post-mission reward chains often draw several overlapping blue panels.
    # Prefer concrete bottom button/open-door controls over broad modal crops
    # so Region Secured and Pod Recovered contents do not look like promotions.
    if dark_overlay >= 0.60:
        for name in (
            "kia_panel",
            "pod_open_panel",
            "bottom_continue_panel",
            "reward_panel",
            "promotion_panel",
        ):
            score = scores.get(name, {})
            threshold = 0.60 if name == "pod_open_panel" else 0.70
            if _lightning_score_is_actionable(score, min_score=threshold):
                spec = _LIGHTNING_UI_BUTTON_CROPS[name]
                return {
                    "status": "OK",
                    "visible_ui": name,
                    "recommended_control": spec["control"],
                    "confidence": score["score"],
                    "dark_overlay_fraction": dark_overlay,
                    "scores": scores,
                }

    if (
        island_map.get("red", 0) >= 5000
        and island_map.get("colored", 0) >= 12000
        and island_map.get("score", 0.0) >= 0.05
    ):
        return {
            "status": "OK",
            "visible_ui": "island_map",
            "recommended_control": None,
            "confidence": island_map["score"],
            "dark_overlay_fraction": dark_overlay,
            "scores": scores,
        }

    best_name = max(_LIGHTNING_UI_BUTTON_CROPS, key=lambda name: scores[name]["score"])
    best = scores[best_name]
    if (
        island_map.get("colored", 0) >= 12000
        and best_name in _LIGHTNING_SAFE_CLEAR_UIS
        and best.get("score", 0.0) >= 0.70
        and best.get("bright", 0) >= 120
        and best.get("border", 0) >= 120
    ):
        spec = _LIGHTNING_UI_BUTTON_CROPS[best_name]
        return {
            "status": "OK",
            "visible_ui": best_name,
            "recommended_control": spec["control"],
            "confidence": best["score"],
            "dark_overlay_fraction": dark_overlay,
            "scores": scores,
        }

    if (
        island_map.get("colored", 0) >= 12000
        and island_map.get("score", 0.0) >= 0.05
    ):
        return {
            "status": "OK",
            "visible_ui": "island_map",
            "recommended_control": None,
            "confidence": island_map["score"],
            "dark_overlay_fraction": dark_overlay,
            "scores": scores,
        }

    best_name = max(scores, key=lambda name: scores[name]["score"])
    best = scores[best_name]
    if dark_overlay < 0.60:
        return {
            "status": "OK",
            "visible_ui": "island_map_or_unknown",
            "recommended_control": None,
            "confidence": best["score"],
            "dark_overlay_fraction": dark_overlay,
            "scores": scores,
        }
    if (
        best["score"] >= 0.34
        and best.get("bright", 0) >= 120
        and best.get("border", 0) >= 120
        and best_name in _LIGHTNING_UI_BUTTON_CROPS
        and (
            best_name != "pause_menu"
            or (
                best.get("border", 0)
                / max(int(best.get("pixels", 0) or 1), 1)
            )
            >= 0.045
        )
    ):
        spec = _LIGHTNING_UI_BUTTON_CROPS[best_name]
        return {
            "status": "OK",
            "visible_ui": best_name,
            "recommended_control": spec["control"],
            "confidence": best["score"],
            "dark_overlay_fraction": dark_overlay,
            "scores": scores,
        }
    return {
        "status": "OK",
        "visible_ui": "island_map_or_unknown",
        "recommended_control": None,
        "confidence": best["score"],
        "dark_overlay_fraction": dark_overlay,
        "scores": scores,
    }


def _lightning_refine_visible_ui_with_bridge(visible_ui: dict) -> dict:
    """Use bridge state to reject image-only live-combat false positives."""
    visible_name = visible_ui.get("visible_ui")
    map_like_ui = {"island_map", "island_map_or_unknown"}
    menu_like_false_positive_ui = {"title_screen", "new_game_setup"}
    if (
        visible_name != "deployment_screen"
        and visible_name not in _LIGHTNING_SAFE_CLEAR_UIS
            and visible_name not in map_like_ui
        and visible_name not in menu_like_false_positive_ui
    ):
        return visible_ui

    if not is_bridge_alive(max_stale_sec=5.0):
        visible_ui["bridge_refine_snapshot"] = {
            "status": "SKIPPED",
            "reason": "bridge_heartbeat_stale_or_missing",
        }
        return visible_ui

    snapshot = _lightning_live_snapshot()
    visible_ui["bridge_refine_snapshot"] = {
        key: snapshot.get(key)
        for key in (
            "status",
            "phase",
            "turn",
            "mission_id",
            "active_mechs",
            "mech_count",
            "deployment_zone_count",
            "in_active_mission",
            "bridge_heartbeat_alive",
            "bridge_heartbeat_stale",
        )
        if key in snapshot
    }
    if snapshot.get("status") != "OK":
        return visible_ui

    phase = snapshot.get("phase")
    turn_value = snapshot.get("turn")
    try:
        turn = int(turn_value)
    except (TypeError, ValueError):
        turn = -1
    is_deployment = turn == 0 and int(snapshot.get("deployment_zone_count") or 0) > 0
    if (
        visible_name in menu_like_false_positive_ui
        and _lightning_bridge_snapshot_fresh_enough(snapshot)
        and snapshot.get("in_active_mission") is True
        and (phase in _COMBAT_BRIDGE_PHASES or is_deployment)
    ):
        refined = dict(visible_ui)
        refined["visible_ui"] = "combat_screen"
        refined["recommended_control"] = None
        refined["menu_false_positive"] = visible_name
        return refined

    if visible_name in map_like_ui:
        if (
            _lightning_bridge_snapshot_fresh_enough(snapshot)
            and snapshot.get("in_active_mission") is True
            and (
                phase in _COMBAT_BRIDGE_PHASES
                or is_deployment
            )
        ):
            refined = dict(visible_ui)
            refined["visible_ui"] = "combat_screen"
            refined["recommended_control"] = None
            refined["island_map_false_positive"] = True
            return refined
        return visible_ui

    if visible_name == "deployment_screen" and is_deployment:
        if visible_ui.get("non_pauseable") is True:
            refined = dict(visible_ui)
            refined["non_pauseable"] = False
            return refined
        return visible_ui

    if (
        visible_name in {"reward_panel", "perfect_island_panel"}
        and is_deployment
        and snapshot.get("in_active_mission") is True
    ):
        refined = dict(visible_ui)
        refined["visible_ui"] = "bottom_continue_panel"
        refined["recommended_control"] = "bottom_continue"
        refined["intro_continue_from_deployment_snapshot"] = True
        refined["intro_continue_false_positive"] = visible_name
        return refined

    if (
        visible_name in _LIGHTNING_SAFE_CLEAR_UIS
        and snapshot.get("phase") in _COMBAT_BRIDGE_PHASES
        and snapshot.get("in_active_mission") is True
    ):
        refined = dict(visible_ui)
        refined["visible_ui"] = "combat_screen"
        refined["recommended_control"] = None
        refined["terminal_panel_false_positive"] = True
        return refined

    if visible_name != "deployment_screen":
        return visible_ui

    refined = dict(visible_ui)
    refined["visible_ui"] = "combat_screen"
    refined["recommended_control"] = None
    refined["non_pauseable"] = False
    refined["deployment_false_positive"] = True
    return refined


def _lightning_attach_visible_ocr(
    result: dict,
    image_path: str | Path,
    *,
    force: bool = False,
) -> dict:
    """Attach OCR text for visible panels where outcomes or pause text can hide."""
    if result.get("status") != "OK":
        return result
    visible_name = result.get("visible_ui")
    if (
        not force
        and
        visible_name not in _LIGHTNING_TERMINAL_OCR_AUDIT_UIS
        and visible_name != "pause_menu"
    ):
        return result
    ocr = _lightning_ocr_texts_from_image(image_path)
    result["ocr"] = ocr
    if ocr.get("status") != "OK":
        return result
    texts = [str(text) for text in (ocr.get("texts") or []) if str(text).strip()]
    result["ocr_texts"] = texts
    if texts:
        result["visible_text"] = "\n".join(texts)
    result = _lightning_apply_system_prompt_ocr_override(result)
    if _lightning_external_system_prompt_visible(result):
        return result
    result = _lightning_apply_deployment_screen_ocr_override(result)
    if result.get("visible_ui") == "deployment_screen":
        return result
    result = _lightning_apply_title_screen_ocr_override(result)
    if result.get("visible_ui") == "title_screen":
        return result
    result = _lightning_apply_setup_screen_ocr_override(result)
    if result.get("visible_ui") == "new_game_setup":
        return result
    return _lightning_apply_pause_menu_ocr_override(result)


def _lightning_audit_visible_ui_for_terminal_text(visible_ui: dict) -> dict:
    """Attach OCR to terminal-prone panels when a screenshot is available."""
    if not isinstance(visible_ui, dict) or visible_ui.get("status") != "OK":
        return visible_ui
    visible_ui = _lightning_apply_pause_menu_ocr_override(visible_ui)
    if visible_ui.get("visible_ui") == "pause_menu":
        return visible_ui
    if visible_ui.get("visible_ui") not in _LIGHTNING_TERMINAL_OCR_AUDIT_UIS:
        return visible_ui
    if any(key in visible_ui for key in ("ocr", "ocr_text", "ocr_texts", "visible_text")):
        return _lightning_apply_pause_menu_ocr_override(visible_ui)
    screenshot_path = visible_ui.get("screenshot_path")
    if not screenshot_path:
        return visible_ui
    return _lightning_attach_visible_ocr(visible_ui, screenshot_path)


def _lightning_terminal_outcome_evidence(
    value: Any,
    *,
    path: tuple[str, ...] = (),
    text_context: bool = False,
    lightning_speed_loss_policy: bool = False,
) -> dict | None:
    """Find explicit terminal/failure evidence before clearing Lightning UI."""
    if isinstance(value, dict):
        visual_kia = _lightning_terminal_visual_kia_evidence(value, path=path)
        if visual_kia is not None:
            return visual_kia
        structured_failure = _lightning_structured_objective_failure_evidence(
            value,
            path=path,
        )
        if structured_failure is not None:
            if not (
                lightning_speed_loss_policy
                and _lightning_speed_policy_accepts_terminal_evidence(
                    structured_failure,
                    source=value,
                )
            ):
                return structured_failure
        split_failure = _lightning_split_objective_failure_evidence(value, path=path)
        if split_failure is not None:
            if not (
                lightning_speed_loss_policy
                and _lightning_speed_policy_accepts_terminal_evidence(
                    split_failure,
                    source=value,
                )
            ):
                return split_failure
        for key in _LIGHTNING_TERMINAL_OUTCOME_FLAG_KEYS:
            flag_evidence = _lightning_terminal_flag_value_evidence(
                key,
                value.get(key),
                path=path + (key,),
            )
            if flag_evidence is not None:
                if not (
                    lightning_speed_loss_policy
                    and _lightning_speed_policy_accepts_terminal_evidence(
                        flag_evidence,
                        source=value,
                    )
                ):
                    return flag_evidence
        for key, nested in value.items():
            key_text = str(key)
            child_text_context = (
                text_context
                or key_text in _LIGHTNING_TERMINAL_OUTCOME_TEXT_KEYS
                or key_text.endswith("_text")
                or key_text.endswith("_texts")
                or _lightning_terminal_generic_text_key_has_context(
                    key_text,
                    path=path,
                    container=value,
                )
            )
            found = _lightning_terminal_outcome_evidence(
                nested,
                path=path + (key_text,),
                text_context=child_text_context,
                lightning_speed_loss_policy=lightning_speed_loss_policy,
            )
            if found is not None:
                if not (
                    lightning_speed_loss_policy
                    and _lightning_speed_policy_accepts_terminal_evidence(
                        found,
                        source=nested,
                    )
                ):
                    return found
        return _lightning_terminal_visible_ui_evidence(value, path=path)
    if isinstance(value, list):
        for index, nested in enumerate(value):
            found = _lightning_terminal_outcome_evidence(
                nested,
                path=path + (str(index),),
                text_context=text_context,
                lightning_speed_loss_policy=lightning_speed_loss_policy,
            )
            if found is not None:
                if not (
                    lightning_speed_loss_policy
                    and _lightning_speed_policy_accepts_terminal_evidence(
                        found,
                        source=nested,
                    )
                ):
                    return found
        return None
    if isinstance(value, str) and text_context:
        text = value.strip()
        match = _lightning_terminal_text_match(text)
        if match is not None:
            evidence = {
                "kind": "terminal_text",
                "path": ".".join(path),
                **match,
                "text": text[:240],
            }
            if not (
                lightning_speed_loss_policy
                and _lightning_speed_policy_accepts_terminal_evidence(
                    evidence,
                    source=value,
                )
            ):
                return evidence
    return None


def _lightning_terminal_text_haystack(value: Any, *, limit: int = 48) -> str:
    parts: list[str] = []

    def collect(nested: Any) -> None:
        if len(parts) >= limit:
            return
        if isinstance(nested, dict):
            for key, item in nested.items():
                if len(parts) >= limit:
                    break
                parts.append(str(key))
                collect(item)
            return
        if isinstance(nested, list):
            for item in nested:
                if len(parts) >= limit:
                    break
                collect(item)
            return
        if nested is None:
            return
        if isinstance(nested, (str, int, float, bool)):
            parts.append(str(nested))

    collect(value)
    return " ".join(parts)


def _lightning_terminal_text_time_pod_failure_only(text: str) -> bool:
    """True only when every failed-objective-looking row is a Time Pod row."""
    raw_text = str(text or "")
    if not raw_text.strip():
        return False
    lowered = raw_text.lower()
    hard_phrases = {
        phrase
        for phrase in _LIGHTNING_TERMINAL_OUTCOME_PHRASES
        if phrase not in {"failed", "(failed)"}
    }
    if any(phrase in lowered for phrase in hard_phrases):
        return False
    if re.search(r"(?<![a-z0-9])k\.?i\.?a\.?(?![a-z0-9])", lowered):
        return False

    marked_text = re.sub(
        r"(?i)(\(?failed\)?|failure)\s+(?=[A-Z])",
        r"\1\n",
        raw_text,
    )
    rows = [row.strip() for row in re.split(r"[\r\n]+", marked_text) if row.strip()]
    failure_rows = [
        row
        for row in rows
        if re.search(r"(?i)\bfailed\b|\bfailure\b|\(failed\)", row)
    ]
    if not failure_rows:
        return False
    return all("timepod" in re.sub(r"[^a-z0-9]+", "", row.lower()) for row in failure_rows)


def _lightning_speed_policy_source_has_forbidden_terminal(value: Any) -> bool:
    if isinstance(value, dict):
        for key in _LIGHTNING_TERMINAL_OUTCOME_FLAG_KEYS:
            flag_evidence = _lightning_terminal_flag_value_evidence(
                key,
                value.get(key),
                path=(str(key),),
            )
            if flag_evidence is not None and not _lightning_speed_policy_failure_is_time_pod(
                flag_evidence,
                source=value,
            ):
                return True
        for key, nested in value.items():
            key_lower = str(key).lower()
            if (
                key_lower in {"failed", "objective_failed"}
                or key_lower.endswith("_failed")
            ) and nested is True:
                compact = re.sub(
                    r"[^a-z0-9]+",
                    "",
                    _lightning_terminal_text_haystack(value).lower(),
                )
                if "timepod" not in compact:
                    return True
            if (
                key_lower in {"status", "state", "result", "outcome"}
                and isinstance(nested, str)
                and nested.strip().lower() in {"failed", "failure", "lost"}
            ):
                compact = re.sub(
                    r"[^a-z0-9]+",
                    "",
                    _lightning_terminal_text_haystack(value).lower(),
                )
                if "timepod" not in compact:
                    return True
            if _lightning_speed_policy_source_has_forbidden_terminal(nested):
                return True
        return False
    if isinstance(value, list):
        if all(isinstance(item, str) for item in value):
            text_rows = [str(item).strip() for item in value]
            for index, text in enumerate(text_rows):
                if _lightning_standalone_failure_marker(text):
                    context = _lightning_nearest_failure_context(text_rows, index)
                    context_text = context[1] if context is not None else ""
                    compact = re.sub(r"[^a-z0-9]+", "", context_text.lower())
                    if "timepod" not in compact:
                        return True
                    continue
                if _lightning_terminal_text_match(text) is not None and not (
                    _lightning_terminal_text_time_pod_failure_only(text)
                ):
                    return True
            return any(
                _lightning_speed_policy_source_has_forbidden_terminal(item)
                for item in value
                if not isinstance(item, str)
            )
        return any(_lightning_speed_policy_source_has_forbidden_terminal(item) for item in value)
    if isinstance(value, str):
        text = value.strip()
        if not text:
            return False
        match = _lightning_terminal_text_match(text)
        if match is None:
            return False
        return not _lightning_terminal_text_time_pod_failure_only(text)
    return False


def _lightning_speed_policy_failure_is_time_pod(
    evidence: dict,
    *,
    source: Any = None,
) -> bool:
    context_text = evidence.get("context_text")
    if isinstance(context_text, str):
        compact_context = re.sub(r"[^a-z0-9]+", "", context_text.lower())
        if "timepod" in compact_context:
            return True
    for key in ("text", "value"):
        value = evidence.get(key)
        if isinstance(value, str) and _lightning_terminal_text_time_pod_failure_only(value):
            return True
    if isinstance(source, str):
        return _lightning_terminal_text_time_pod_failure_only(source)
    compact = re.sub(
        r"[^a-z0-9]+",
        "",
        " ".join(
            part
            for part in (
                _lightning_terminal_text_haystack(evidence),
                _lightning_terminal_text_haystack(source),
            )
            if part
        ).lower(),
    )
    return "timepod" in compact and "fail" in compact


def _lightning_speed_policy_accepts_terminal_evidence(
    evidence: dict,
    *,
    source: Any = None,
) -> bool:
    """Allow only Time Pod failed evidence through the Lightning speed policy."""
    if not evidence:
        return False
    kind = str(evidence.get("kind") or "")
    phrase = str(evidence.get("phrase") or "").lower()
    flag = str(evidence.get("flag") or "").lower()
    failureish = (
        kind in {"objective_failure_field", "split_objective_failure_text"}
        or phrase in {"failed", "(failed)"}
        or ("fail" in flag and "objective" in flag)
    )
    if not failureish:
        return False
    if _lightning_speed_policy_source_has_forbidden_terminal(source):
        return False
    return _lightning_speed_policy_failure_is_time_pod(evidence, source=source)


def _lightning_terminal_visual_kia_evidence(
    value: dict,
    *,
    path: tuple[str, ...],
) -> dict | None:
    visible_name = value.get("visible_ui")
    if visible_name not in {
        "reward_panel",
        "bottom_continue_panel",
        "perfect_reward_choice",
        "perfect_island_panel",
    }:
        return None
    if _lightning_terminal_visible_ui_has_clean_text_audit(value):
        return None
    screenshot_path = value.get("screenshot_path")
    if not screenshot_path:
        return None
    try:
        from PIL import Image

        image = Image.open(screenshot_path).convert("RGB")
    except Exception:
        return None
    width, height = image.size
    base_w, base_h = _LIGHTNING_UI_BASE_SIZE
    scale_x = width / base_w if base_w else 1.0
    scale_y = height / base_h if base_h else 1.0
    # Region Secured KIA text appears under the middle pilot card. This narrow
    # crop avoids the red island map behind the dark modal.
    left = int(650 * scale_x)
    top = int(455 * scale_y)
    right = int(735 * scale_x)
    bottom = int(530 * scale_y)
    if right <= left or bottom <= top:
        return None
    crop = image.crop((left, top, right, bottom)).convert("RGB")
    pixels = list(crop.getdata())
    total = len(pixels) or 1
    red = sum(
        1
        for r, g, b in pixels
        if r > 145 and 20 < g < 130 and b < 140 and r > g + 45 and r > b + 45
    )
    red_fraction = red / total
    if red < 180 or red_fraction < 0.006:
        return None
    return {
        "kind": "terminal_visual_kia",
        "path": ".".join(path + ("screenshot_path",)),
        "phrase": "kia",
        "red_pixels": red,
        "red_fraction": round(red_fraction, 4),
        "crop": [left, top, right, bottom],
    }


def _lightning_terminal_visible_ui_evidence(
    value: dict,
    *,
    path: tuple[str, ...],
) -> dict | None:
    visible_name = value.get("visible_ui")
    if not isinstance(visible_name, str) or visible_name not in _LIGHTNING_TERMINAL_UIS:
        return None
    if value.get("terminal_panel_false_positive") is True:
        return None
    if _lightning_terminal_visible_ui_has_clean_text_audit(value):
        return None
    return {
        "kind": "terminal_visible_ui",
        "path": ".".join(path + ("visible_ui",)),
        "visible_ui": visible_name,
    }


def _lightning_terminal_visible_ui_has_clean_text_audit(value: dict) -> bool:
    ocr = value.get("ocr")
    if isinstance(ocr, dict):
        return ocr.get("status") == "OK"
    if "ocr" in value:
        return True
    return any(
        key in value
        for key in (
            "ocr_text",
            "ocr_texts",
            "panel_text",
            "reward_text",
            "screen_text",
            "text",
            "visible_text",
        )
    )


def _lightning_terminal_generic_text_key_has_context(
    key_text: str,
    *,
    path: tuple[str, ...],
    container: dict,
) -> bool:
    if key_text.lower() not in {"texts", "lines"}:
        return False
    parent_hints = {"ocr", "vision", "visible_text", "screen_text", "panel_text"}
    if any(str(part).lower() in parent_hints for part in path):
        return True
    visible_name = container.get("visible_ui")
    if isinstance(visible_name, str) and visible_name in _LIGHTNING_TERMINAL_OCR_AUDIT_UIS:
        return True
    return False


def _lightning_split_objective_failure_evidence(
    value: dict,
    *,
    path: tuple[str, ...],
) -> dict | None:
    for key, nested in value.items():
        key_text = str(key)
        if not isinstance(nested, list):
            continue
        if not (
            key_text in _LIGHTNING_TERMINAL_OUTCOME_TEXT_KEYS
            or key_text.endswith("_texts")
            or "objective" in key_text.lower()
            or _lightning_terminal_generic_text_key_has_context(
                key_text,
                path=path,
                container=value,
            )
        ):
            continue
        text_rows = [str(item).strip() if isinstance(item, str) else "" for item in nested]
        for index, text in enumerate(text_rows):
            if not _lightning_standalone_failure_marker(text):
                continue
            context = _lightning_nearest_failure_context(text_rows, index)
            if context is None:
                continue
            context_index, context_text = context
            if "objective" not in key_text.lower() and not _lightning_objective_context_text(
                context_text
            ):
                continue
            return {
                "kind": "split_objective_failure_text",
                "path": ".".join(path + (key_text, str(index))),
                "phrase": "failed",
                "context": "split_objective_text",
                "context_path": ".".join(path + (key_text, str(context_index))),
                "context_text": context_text[:240],
                "text": text[:240],
            }
    return None


def _lightning_standalone_failure_marker(text: str) -> bool:
    normalized = re.sub(r"\s+", " ", str(text or "").strip()).lower()
    normalized = normalized.strip(" \t\r\n:;,.![]{}")
    return normalized in {"failed", "(failed)", "failure", "(failure)"}


def _lightning_nearest_failure_context(
    text_rows: list[str],
    index: int,
) -> tuple[int, str] | None:
    for offset in (1, 2):
        for context_index in (index - offset, index + offset):
            if context_index < 0 or context_index >= len(text_rows):
                continue
            context_text = text_rows[context_index].strip()
            if not context_text or _lightning_standalone_failure_marker(context_text):
                continue
            return context_index, context_text
    return None


def _lightning_objective_context_text(text: str) -> bool:
    lowered = str(text or "").lower()
    return any(word in lowered for word in _LIGHTNING_TERMINAL_FAILED_CONTEXT_WORDS)


def _lightning_structured_objective_failure_evidence(
    value: dict,
    *,
    path: tuple[str, ...],
) -> dict | None:
    if not _lightning_objective_path_context(path):
        return None
    for key, nested in value.items():
        key_text = str(key)
        key_lower = key_text.lower()
        if (
            key_lower in {"failed", "objective_failed"}
            or key_lower.endswith("_failed")
        ) and nested is True:
            return {
                "kind": "objective_failure_field",
                "path": ".".join(path + (key_text,)),
                "field": key_text,
            }
        if (
            key_lower in {"status", "state", "result", "outcome"}
            and isinstance(nested, str)
            and nested.strip().lower() in {"failed", "failure", "lost"}
        ):
            return {
                "kind": "objective_failure_field",
                "path": ".".join(path + (key_text,)),
                "field": key_text,
                "value": nested,
            }
    return None


def _lightning_objective_path_context(path: tuple[str, ...]) -> bool:
    return any(
        "objective" in part.lower() or part.lower() == "objectives"
        for part in path
    )


def _lightning_terminal_flag_value_evidence(
    key: str,
    value: Any,
    *,
    path: tuple[str, ...],
) -> dict | None:
    if value is True:
        return {
            "kind": "terminal_flag",
            "path": ".".join(path),
            "flag": key,
        }
    if value is False or value is None:
        return None
    if isinstance(value, (int, float)) and not isinstance(value, bool):
        if value == 0:
            return None
        return {
            "kind": "terminal_flag",
            "path": ".".join(path),
            "flag": key,
            "value": value,
        }
    if not isinstance(value, str):
        return None
    text = value.strip()
    normalized = re.sub(r"[^a-z0-9]+", "_", text.lower()).strip("_")
    if normalized in _LIGHTNING_NEGATIVE_TERMINAL_FLAG_VALUES:
        return None
    match = _lightning_terminal_text_match(text) or _lightning_terminal_text_match(
        normalized.replace("_", " ")
    )
    evidence: dict = {
        "kind": "terminal_flag",
        "path": ".".join(path),
        "flag": key,
        "value": text[:240],
    }
    if match is not None:
        evidence.update(match)
        return evidence
    if normalized in _LIGHTNING_AFFIRMATIVE_TERMINAL_FLAG_VALUES or key == "terminal_outcome":
        return evidence
    return None


_LIGHTNING_NEGATIVE_TERMINAL_FLAG_VALUES = {
    "",
    "0",
    "false",
    "none",
    "no",
    "not_visible",
    "ok",
    "clean",
    "clear",
}

_LIGHTNING_AFFIRMATIVE_TERMINAL_FLAG_VALUES = {
    "1",
    "true",
    "yes",
    "visible",
    "detected",
    "present",
    "blocked",
}


def _lightning_terminal_text_match(text: str) -> dict | None:
    lowered = text.lower()
    for phrase in _LIGHTNING_TERMINAL_OUTCOME_PHRASES:
        if phrase in lowered:
            return {"phrase": phrase}
    if re.search(r"(?<![a-z0-9])k\.?i\.?a\.?(?![a-z0-9])", lowered):
        return {"phrase": "kia"}
    if "failed" not in lowered:
        return None
    if any(word in lowered for word in _LIGHTNING_TERMINAL_FAILED_CONTEXT_WORDS):
        return {"phrase": "failed", "context": "objective_text"}
    return None


def _lightning_terminal_panel_block(
    visible_ui: dict,
    *,
    reason: str = "terminal_outcome_visible",
    steps: list[dict] | None = None,
    lightning_speed_loss_policy: bool = False,
) -> dict | None:
    evidence = _lightning_terminal_outcome_evidence(
        visible_ui,
        lightning_speed_loss_policy=lightning_speed_loss_policy,
    )
    if evidence is None:
        return None
    result = {
        "status": "BLOCKED",
        "reason": reason,
        "visible_ui": visible_ui,
        "terminal_evidence": evidence,
        "next_step": (
            "Stop before clearing this panel. Inspect the visible terminal, "
            "KIA, timeline-lost, or failed-objective evidence first."
        ),
    }
    if steps is not None:
        result["steps"] = steps
    return result


def _lightning_visible_ui_snapshot(
    *,
    include_ocr: bool = False,
    bridge_refine: bool = True,
) -> dict:
    """Capture and classify visible non-combat UI panels."""
    from src.capture.window import take_screenshot

    if bridge_refine and not include_ocr and is_bridge_alive(max_stale_sec=5.0):
        try:
            snapshot = _lightning_live_snapshot()
        except Exception:
            snapshot = None
        if (
            isinstance(snapshot, dict)
            and snapshot.get("status") == "OK"
            and _lightning_bridge_snapshot_fresh_enough(snapshot)
            and snapshot.get("in_active_mission") is True
            and snapshot.get("phase") in _COMBAT_BRIDGE_PHASES
            and not _lightning_turn_zero_deployment_snapshot(snapshot)
        ):
            return {
                "status": "OK",
                "visible_ui": "combat_screen",
                "recommended_control": None,
                "confidence": 1.0,
                "bridge_fast_path": True,
                "game_focus_proof": _lightning_game_focus_proof(None),
                "bridge_refine_snapshot": {
                    key: snapshot.get(key)
                    for key in (
                        "status",
                        "phase",
                        "turn",
                        "mission_id",
                        "active_mechs",
                        "mech_count",
                        "deployment_zone_count",
                        "in_active_mission",
                        "bridge_heartbeat_alive",
                        "bridge_heartbeat_stale",
                    )
                    if key in snapshot
                },
            }

    tmp_path = Path(tempfile.gettempdir()) / f"itb_lightning_ui_{os.getpid()}.png"
    screenshot_failure_recoveries: list[dict[str, Any]] = []
    initial_screenshot_error: str | None = None
    last_screenshot_error: str | None = None
    screenshot_captured = False
    for attempt in range(4):
        try:
            take_screenshot(tmp_path)
            screenshot_captured = True
            break
        except Exception as exc:
            last_screenshot_error = str(exc)
            if initial_screenshot_error is None:
                initial_screenshot_error = last_screenshot_error
            recovery = _lightning_recover_screenshot_privacy_prompt_failure(exc)
            screenshot_failure_recoveries.append(recovery)
            if recovery.get("status") != "OK":
                return {
                    "status": "ERROR",
                    "error": f"screenshot failed: {exc}",
                    "screenshot_failure_recovery": recovery,
                    "screenshot_failure_recoveries": screenshot_failure_recoveries,
                    "initial_screenshot_error": initial_screenshot_error,
                }
    if not screenshot_captured:
        return {
            "status": "ERROR",
            "reason": "screenshot_failed_after_privacy_prompt_recoveries",
            "error": f"screenshot failed: {last_screenshot_error}",
            "screenshot_failure_recoveries": screenshot_failure_recoveries,
            "initial_screenshot_error": initial_screenshot_error,
        }
    result = _classify_lightning_ui_image(tmp_path)
    if screenshot_failure_recoveries:
        result["screenshot_failure_recoveries"] = screenshot_failure_recoveries
        result["initial_screenshot_error"] = initial_screenshot_error
    if bridge_refine:
        result = _lightning_refine_visible_ui_with_bridge(result)
    else:
        result["bridge_refine_snapshot"] = {
            "status": "SKIPPED",
            "reason": "bridge_refine_disabled",
        }
    if include_ocr:
        result = _lightning_attach_visible_ocr(result, tmp_path, force=True)
        result = _lightning_apply_system_prompt_ocr_override(result)
    else:
        if _lightning_should_ocr_for_system_prompt(result):
            result = _lightning_attach_visible_ocr(result, tmp_path, force=True)
            result = _lightning_apply_system_prompt_ocr_override(result)
        result = _lightning_apply_pause_menu_ocr_override(result)
    result["screenshot_path"] = str(tmp_path)
    result["game_focus_proof"] = _lightning_game_focus_proof(tmp_path)
    return result


def _lightning_recover_screenshot_privacy_prompt_failure(exc: Exception) -> dict:
    """Click standing-approved macOS Allow when the prompt blocks screenshot capture."""
    if os.name == "nt":
        return {"status": "SKIPPED", "reason": "not_macos"}
    message = str(exc)
    if "could not create image from display" not in message.lower():
        return {
            "status": "SKIPPED",
            "reason": "screenshot_failure_not_privacy_prompt_like",
            "error": message,
        }
    fullscreen_drain = _lightning_drain_system_privacy_prompt_stack_fullscreen_ocr()
    if fullscreen_drain.get("status") == "OK":
        fullscreen_drain = dict(fullscreen_drain)
        fullscreen_drain["reason"] = (
            "clicked_standing_approved_privacy_prompt_allow_fullscreen_ocr"
        )
        fullscreen_drain["initial_error"] = message
        return fullscreen_drain
    from src.control.mac_click import click_window_point

    click = click_window_point(
        817,
        551,
        description="macOS privacy prompt Allow fallback",
        hold_seconds=0.08,
        settle_seconds=0.5,
    )
    return {
        "status": click.get("status", "ERROR"),
        "reason": "clicked_standing_approved_privacy_prompt_allow_fallback",
        "standing_permission": "user_granted_click_allow_on_macos_popups",
        "initial_error": message,
        "fullscreen_click": fullscreen_drain,
        "click_result": click,
    }


def _lightning_game_focus_proof(screenshot_path: str | Path | None = None) -> dict:
    """Return proof that the captured frame belongs to the ITB game window."""
    try:
        from src.capture.window import get_window_bounds, is_game_frontmost
    except Exception as exc:
        return {
            "status": "ERROR",
            "reason": "focus_probe_import_failed",
            "exception_type": type(exc).__name__,
            "error": str(exc),
        }

    try:
        bounds = get_window_bounds()
    except Exception as exc:
        return {
            "status": "ERROR",
            "reason": "window_bounds_probe_failed",
            "exception_type": type(exc).__name__,
            "error": str(exc),
        }
    try:
        frontmost = bool(is_game_frontmost())
    except Exception as exc:
        return {
            "status": "ERROR",
            "reason": "frontmost_probe_failed",
            "window_bounds": bounds,
            "exception_type": type(exc).__name__,
            "error": str(exc),
        }

    image_size = None
    if screenshot_path is not None:
        try:
            from PIL import Image

            with Image.open(screenshot_path) as image:
                image_size = [int(image.size[0]), int(image.size[1])]
        except Exception as exc:
            return {
                "status": "ERROR",
                "reason": "screenshot_identity_probe_failed",
                "frontmost": frontmost,
                "window_bounds": bounds,
                "screenshot_path": str(screenshot_path),
                "exception_type": type(exc).__name__,
                "error": str(exc),
            }

    reasons = []
    if not bounds:
        reasons.append("window_bounds_unavailable")
    if not frontmost:
        reasons.append("game_not_frontmost")
    if screenshot_path is not None and not image_size:
        reasons.append("screenshot_size_unavailable")
    status = "OK" if not reasons else "BLOCKED"
    result = {
        "status": status,
        "frontmost": frontmost,
        "window_bounds": bounds,
        "screenshot_path": str(screenshot_path) if screenshot_path is not None else None,
        "screenshot_image_size": image_size,
        "expected_app": "Into the Breach",
    }
    if reasons:
        result["reason"] = "game_focus_proof_failed"
        result["failures"] = reasons
    return result


def _lightning_guard_path(session: RunSession) -> Path:
    """Persist the current speed-run UI-resting-state hint with the run."""
    return _recording_dir(session) / "lightning_guard.json"


def _lightning_route_mismatch_path(session: RunSession) -> Path:
    """Persist route handoffs that started a different mission than intended."""
    return _recording_dir(session) / "lightning_route_mismatch.json"


def _lightning_write_route_mismatch_block(
    session: RunSession,
    *,
    expected_mission_id: str,
    actual_mission_id: str | None,
    snapshot: dict,
    reason: str = "route_mission_mismatch_before_deploy",
) -> dict:
    path = _lightning_route_mismatch_path(session)
    payload = {
        "status": "BLOCKED",
        "run_id": session.run_id,
        "created_at": datetime.now().isoformat(timespec="seconds"),
        "reason": reason,
        "expected_mission_id": expected_mission_id,
        "actual_mission_id": actual_mission_id,
        "turn": snapshot.get("turn"),
        "phase": snapshot.get("phase"),
        "deployment_zone_count": snapshot.get("deployment_zone_count"),
        "mech_count": snapshot.get("mech_count"),
        "in_active_mission": snapshot.get("in_active_mission"),
        "next_step": (
            "Abandon/restart this Lightning War timeline or return to a "
            "verified island map. Do not drop the expected mission guard and "
            "deploy the mismatched mission."
        ),
    }
    _atomic_json_write(path, payload)
    payload["path"] = str(path)
    return payload


def _lightning_snapshot_grid_power(snapshot: dict) -> int | None:
    raw = snapshot.get("grid_power")
    if raw is None:
        return None
    if isinstance(raw, int):
        return raw
    text = str(raw).strip()
    if not text:
        return None
    if "/" in text:
        text = text.split("/", 1)[0].strip()
    try:
        return int(text)
    except ValueError:
        return None


_LIGHTNING_ROUTE_MISSION_EQUIVALENCE_GROUPS = (
    frozenset({"Mission_GenericThreat", "Mission_Survive"}),
)


def _lightning_route_mission_ids_match(
    expected_mission_id: str | None,
    actual_mission_id: str | None,
) -> bool:
    """Return true for route identities that are equivalent in speed policy."""
    expected = str(expected_mission_id or "").strip()
    actual = str(actual_mission_id or "").strip()
    if not expected or not actual:
        return False
    if expected == actual:
        return True
    return any(
        expected in group and actual in group
        for group in _LIGHTNING_ROUTE_MISSION_EQUIVALENCE_GROUPS
    )


def _lightning_started_mismatch_is_playable(
    *,
    actual_mission_id: str,
    snapshot: dict,
) -> bool:
    """A post-Start mismatch can be played if it is already a live safe mission."""
    actual = str(actual_mission_id or "").strip()
    if not actual:
        return False
    if snapshot.get("status") != "OK" or not snapshot.get("in_active_mission"):
        return False
    grid_power = _lightning_snapshot_grid_power(snapshot)
    if grid_power is not None and grid_power <= 0:
        return False
    phase = str(snapshot.get("phase") or "").strip()
    deployment_zones = int(snapshot.get("deployment_zone_count") or 0)
    if deployment_zones > 0:
        return True
    return phase in _COMBAT_BRIDGE_PHASES


def _lightning_pause_needs_deploy_confirm(pause_result: dict) -> bool:
    visible = pause_result.get("visible_ui")
    if not isinstance(visible, dict):
        visible = {}
    recommended = (
        pause_result.get("recommended_control")
        or visible.get("recommended_control")
    )
    return (
        pause_result.get("reason") == "visible_ui_is_not_pauseable"
        and visible.get("visible_ui") == "deployment_screen"
        and recommended == "deploy_confirm"
    )


def _lightning_deployment_abandon_safety(
    snapshot: dict,
    *,
    require_active_mission: bool = True,
) -> dict:
    """Return whether a live deployment can be confirmed solely to abandon."""
    issues: list[str] = []
    if snapshot.get("status") != "OK":
        issues.append("snapshot_not_ok")
    if int(snapshot.get("turn") or 0) != 0:
        issues.append("not_turn_zero")
    if int(snapshot.get("deployment_zone_count") or 0) <= 0:
        issues.append("no_deployment_zone")
    if int(snapshot.get("active_mechs") or 0) > 0:
        issues.append("active_mechs_present")
    if require_active_mission and snapshot.get("in_active_mission") is not True:
        issues.append("not_active_mission")
    grid_power = _lightning_snapshot_grid_power(snapshot)
    if grid_power is not None and grid_power <= 0:
        issues.append("grid_power_empty")
    status = "OK" if not issues else "BLOCKED"
    return {
        "status": status,
        "issues": issues,
        "snapshot": snapshot,
    }


def _lightning_prepare_deployment_for_abandon(
    recovery: dict | None = None,
    *,
    profile: str,
    snapshot: dict,
    reason_prefix: str,
    ready_reason: str,
    quiet: bool = True,
    dry_run: bool = False,
    require_active_mission: bool = True,
) -> dict:
    """Deploy-confirm a turn-0 deployment screen so the pause menu can abandon."""
    from src.control.mac_click import click_known_window_control

    recovery = dict(recovery or {})
    recovery.setdefault("status", "STARTED")
    recovery.setdefault("initial_snapshot", snapshot)
    safety = _lightning_deployment_abandon_safety(
        snapshot,
        require_active_mission=require_active_mission,
    )
    recovery["deployment_abandon_safety"] = safety
    if safety.get("status") != "OK":
        recovery["status"] = "BLOCKED"
        recovery["reason"] = f"{reason_prefix}_unsafe_deployment_state"
        return recovery
    if dry_run:
        recovery["status"] = "DRY_RUN"
        recovery["reason"] = ready_reason
        recovery["planned_actions"] = [
            "cmd_deploy_recommended",
            "deploy_confirm",
            "pause",
            "abandon_timeline",
        ]
        return recovery

    deploy, deploy_output = _lightning_quiet_call(
        cmd_deploy_recommended,
        profile=profile,
        quiet=quiet,
    )
    if deploy_output:
        deploy["quiet_output"] = deploy_output
    recovery["deploy"] = deploy
    if deploy.get("status") not in ("OK", "WARN"):
        pause = _lightning_ensure_pause_state(
            reason=f"{reason_prefix}_deploy_failed",
        )
        recovery["pause_after_deploy_failure"] = pause
        recovery["status"] = "BLOCKED"
        recovery["reason"] = f"{reason_prefix}_deploy_failed"
        return recovery

    confirm = click_known_window_control("deploy_confirm")
    recovery["deploy_confirm"] = confirm
    if confirm.get("status") != "OK":
        pause = _lightning_ensure_pause_state(
            reason=f"{reason_prefix}_confirm_failed",
        )
        recovery["pause_after_confirm_failure"] = pause
        recovery["status"] = "BLOCKED"
        recovery["reason"] = f"{reason_prefix}_confirm_failed"
        return recovery

    time.sleep(1.0)
    pause = None
    confirm_retries: list[dict] = []
    pause_attempts: list[dict] = []
    for attempt in range(2):
        pause = _lightning_ensure_pause_state(
            reason=(
                f"{reason_prefix}_before_abandon"
                if attempt == 0
                else f"{reason_prefix}_after_confirm_retry"
            ),
        )
        pause_attempts.append(pause)
        pause_visible = (
            pause.get("pause_verify", {}).get("visible_ui")
            or pause.get("visible_ui", {}).get("visible_ui")
        )
        if pause.get("status") == "OK" and pause_visible == "pause_menu":
            break
        if attempt == 0 and _lightning_pause_needs_deploy_confirm(pause):
            retry = click_known_window_control("deploy_confirm")
            confirm_retries.append(retry)
            if retry.get("status") != "OK":
                recovery["pause"] = pause
                recovery["pause_attempts"] = pause_attempts
                recovery["deploy_confirm_retries"] = confirm_retries
                recovery["status"] = "BLOCKED"
                recovery["reason"] = f"{reason_prefix}_confirm_retry_failed"
                return recovery
            time.sleep(1.0)
            continue
        break

    if confirm_retries:
        recovery["deploy_confirm_retries"] = confirm_retries
    recovery["pause"] = pause or {}
    if len(pause_attempts) > 1:
        recovery["pause_attempts"] = pause_attempts
    pause_visible = (
        recovery["pause"].get("pause_verify", {}).get("visible_ui")
        or recovery["pause"].get("visible_ui", {}).get("visible_ui")
    )
    if recovery["pause"].get("status") != "OK" or pause_visible != "pause_menu":
        recovery["status"] = "BLOCKED"
        recovery["reason"] = f"{reason_prefix}_pause_failed"
        return recovery

    recovery["status"] = "OK"
    recovery["reason"] = ready_reason
    return recovery


def _lightning_recover_started_route_mismatch(
    session: RunSession,
    *,
    profile: str,
    expected_mission_id: str,
    actual_mission_id: str | None,
    snapshot: dict,
    quiet: bool = True,
) -> dict:
    """Abandon a just-started mismatched route without returning live to Codex."""
    recovery: dict = {
        "status": "STARTED",
        "reason": "started_route_mismatch_recovery",
        "expected_mission_id": expected_mission_id,
        "actual_mission_id": actual_mission_id,
        "initial_snapshot": snapshot,
    }
    recovery = _lightning_prepare_deployment_for_abandon(
        recovery,
        profile=profile,
        snapshot=snapshot,
        reason_prefix="route_mismatch_recovery",
        ready_reason="route_mismatch_recovery_ready_to_abandon",
        quiet=quiet,
        require_active_mission=False,
    )
    if recovery.get("status") != "OK":
        return recovery

    return _lightning_click_abandon_to_setup(
        recovery,
        reason_prefix="route_mismatch_recovery",
        success_reason="route_mismatch_abandoned_to_safe_state",
        accepted_final_uis={"new_game_setup", "pause_menu"},
    )


def _lightning_pause_visible_name(pause_result: dict) -> str | None:
    pause_verify = pause_result.get("pause_verify")
    if isinstance(pause_verify, dict) and pause_verify.get("visible_ui"):
        return str(pause_verify.get("visible_ui"))
    visible = pause_result.get("visible_ui")
    if isinstance(visible, dict) and visible.get("visible_ui"):
        return str(visible.get("visible_ui"))
    return None


def _lightning_clear_bridge_files_after_timeline_reset() -> dict:
    """Remove bridge files whose combat/deployment state belongs to the old run."""
    removed: list[str] = []
    missing: list[str] = []
    errors: list[dict] = []
    for path in (STATE_FILE, STATE_TMP, CMD_FILE, ACK_FILE):
        try:
            if path.exists():
                path.unlink()
                removed.append(str(path))
            else:
                missing.append(str(path))
        except Exception as exc:
            errors.append(
                {
                    "path": str(path),
                    "error": str(exc),
                }
            )
    status = "OK" if not errors else "ERROR"
    return {
        "status": status,
        "removed": removed,
        "missing": missing,
        "errors": errors,
    }


def _lightning_clear_stale_bridge_files_for_visible_map(
    *,
    reason: str,
    snapshot: dict | None = None,
    visible_ui: dict | None = None,
    dry_run: bool = False,
) -> dict:
    """Discard old combat bridge files before save-backed island-map routing."""
    visible_name = (
        str(visible_ui.get("visible_ui") or "")
        if isinstance(visible_ui, dict)
        else ""
    )
    if visible_name not in {"island_map", "island_map_or_unknown"}:
        return {
            "status": "SKIPPED",
            "reason": reason,
            "skip_reason": "visible_ui_not_island_map",
            "visible_ui": visible_name or None,
        }
    summary = {
        "reason": reason,
        "policy": "visible_map_route_discards_stale_combat_bridge_files",
        "visible_ui": visible_name,
    }
    if isinstance(snapshot, dict):
        summary["snapshot"] = {
            key: snapshot.get(key)
            for key in (
                "status",
                "phase",
                "turn",
                "mission_id",
                "deployment_zone_count",
                "active_mechs",
                "mech_count",
                "in_active_mission",
                "bridge_heartbeat_alive",
                "bridge_heartbeat_stale",
            )
            if key in snapshot
        }
    if dry_run:
        return {"status": "DRY_RUN", **summary}
    cleanup = _lightning_clear_bridge_files_after_timeline_reset()
    return {**cleanup, **summary}


def _lightning_click_abandon_to_setup(
    recovery: dict | None = None,
    *,
    reason_prefix: str,
    success_reason: str,
    accepted_final_uis: set[str] | None = None,
    dry_run: bool = False,
) -> dict:
    """Click the trusted abandon-flow controls and verify the returned setup UI."""
    from src.control.mac_click import click_known_window_control

    def final_ui_accepted(final_ui: dict) -> tuple[bool, dict]:
        if not isinstance(final_ui, dict):
            return False, final_ui
        visible_name = str(final_ui.get("visible_ui") or "")
        if visible_name not in accepted:
            return False, final_ui
        if visible_name != "new_game_setup":
            return True, final_ui
        audited = final_ui
        if not any(
            key in audited
            for key in ("ocr", "ocr_text", "ocr_texts", "visible_text")
        ):
            screenshot_path = audited.get("screenshot_path")
            if screenshot_path:
                audited = _lightning_attach_visible_ocr(
                    dict(audited),
                    screenshot_path,
                    force=True,
                )
        if _lightning_setup_screen_ocr_match(audited):
            return True, audited
        if not audited.get("screenshot_path") and not any(
            key in audited
            for key in ("ocr", "ocr_text", "ocr_texts", "visible_text")
        ):
            # Unit tests and older callers often provide only the classifier
            # label. Live screenshots must prove setup by OCR to avoid mistaking
            # the first-island picker for the new-run setup modal.
            return True, audited
        audited = dict(audited)
        audited["new_game_setup_rejected_reason"] = "setup_ocr_not_matched"
        return False, audited

    def clear_prompt_and_resample(final_ui: dict) -> dict:
        if not _lightning_external_system_prompt_visible(final_ui):
            return final_ui
        clears = recovery.setdefault("system_privacy_prompt_clears", [])
        if not isinstance(clears, list):
            clears = []
            recovery["system_privacy_prompt_clears"] = clears
        if len(clears) >= 3:
            return final_ui
        clear_result = _lightning_click_system_privacy_prompt_allow(final_ui)
        clears.append(clear_result)
        if clear_result.get("status") != "OK":
            return final_ui
        time.sleep(_LIGHTNING_FAST_UI_SETTLE_SECONDS)
        return _lightning_visible_ui_snapshot()

    recovery = dict(recovery or {})
    accepted = set(accepted_final_uis or {"new_game_setup"})
    if dry_run:
        recovery["status"] = "DRY_RUN"
        recovery["reason"] = success_reason
        recovery["accepted_final_uis"] = sorted(accepted)
        return recovery

    abandon = click_known_window_control("abandon_timeline")
    recovery["abandon_timeline"] = abandon
    if abandon.get("status") != "OK":
        recovery["status"] = "BLOCKED"
        recovery["reason"] = f"{reason_prefix}_abandon_click_failed"
        return recovery

    confirm_abandon = click_known_window_control("abandon_confirm_yes")
    recovery["abandon_confirm_yes"] = confirm_abandon
    if confirm_abandon.get("status") != "OK":
        recovery["status"] = "BLOCKED"
        recovery["reason"] = f"{reason_prefix}_abandon_confirm_failed"
        return recovery

    time.sleep(_LIGHTNING_FAST_UI_SETTLE_SECONDS)
    post_confirm_ui = _lightning_visible_ui_snapshot()
    post_confirm_ui = clear_prompt_and_resample(post_confirm_ui)
    recovery["post_confirm_ui"] = post_confirm_ui
    post_confirm_accepted, post_confirm_ui = final_ui_accepted(post_confirm_ui)
    recovery["post_confirm_ui"] = post_confirm_ui
    if post_confirm_ui.get("status") == "OK" and post_confirm_accepted:
        recovery["status"] = "OK"
        recovery["reason"] = success_reason
        if post_confirm_ui.get("visible_ui") == "new_game_setup":
            recovery["bridge_reset_cleanup"] = (
                _lightning_clear_bridge_files_after_timeline_reset()
            )
        return recovery

    final_ui = None
    for pilot_control in (
        "abandon_pilot_slot",
        "abandon_pilot_slot_wide",
        "abandon_pilot_slot_two_left",
        "abandon_pilot_slot_two_right",
        "abandon_pilot_slot_right",
    ):
        pilot = click_known_window_control(pilot_control)
        recovery[pilot_control] = pilot
        if pilot.get("status") != "OK":
            recovery["status"] = "BLOCKED"
            recovery["reason"] = f"{reason_prefix}_pilot_select_failed"
            recovery["pilot_control"] = pilot_control
            return recovery
        time.sleep(_LIGHTNING_FAST_UI_CONFIRM_SETTLE_SECONDS)
        final_ui = _lightning_visible_ui_snapshot()
        final_ui = clear_prompt_and_resample(final_ui)
        final_accepted, final_ui = final_ui_accepted(final_ui)
        if final_ui.get("status") == "OK" and final_accepted:
            break

    if final_ui is None:
        final_ui = _lightning_visible_ui_snapshot()
        final_ui = clear_prompt_and_resample(final_ui)
        _, final_ui = final_ui_accepted(final_ui)
    recovery["final_ui"] = final_ui
    final_accepted, final_ui = final_ui_accepted(final_ui)
    recovery["final_ui"] = final_ui
    if not (final_ui.get("status") == "OK" and final_accepted):
        final_ui_poll = []
        for _ in range(5):
            time.sleep(0.5)
            try:
                polled_ui = _lightning_visible_ui_snapshot()
                polled_ui = clear_prompt_and_resample(polled_ui)
            except Exception as exc:
                final_ui_poll.append({
                    "status": "ERROR",
                    "reason": "final_setup_poll_failed",
                    "error": repr(exc),
                })
                break
            polled_accepted, polled_ui = final_ui_accepted(polled_ui)
            final_ui_poll.append(polled_ui)
            if polled_ui.get("status") == "OK" and polled_accepted:
                final_ui = polled_ui
                final_accepted = True
                break
        recovery["final_ui_poll"] = final_ui_poll
        recovery["final_ui"] = final_ui
    if final_ui.get("status") == "OK" and final_accepted:
        recovery["status"] = "OK"
        recovery["reason"] = success_reason
        if final_ui.get("visible_ui") == "new_game_setup":
            recovery["bridge_reset_cleanup"] = (
                _lightning_clear_bridge_files_after_timeline_reset()
            )
    else:
        recovery["status"] = "BLOCKED"
        recovery["reason"] = f"{reason_prefix}_final_state_unverified"
    return recovery


def cmd_lightning_abandon_to_setup(
    profile: str = "Alpha",
    *,
    reason: str = "manual_or_runner_restart",
    dry_run: bool = False,
) -> dict:
    """Abandon the current Lightning timeline and verify the new-game setup."""
    visible = _lightning_visible_ui_snapshot()
    result: dict = {
        "status": "STARTED",
        "reason": "lightning_abandon_to_setup",
        "requested_reason": reason,
        "profile": profile,
        "initial_visible_ui": visible,
    }
    if visible.get("status") == "OK" and visible.get("visible_ui") == "new_game_setup":
        result["status"] = "OK"
        result["reason"] = "already_at_new_game_setup"
        _print_result(result)
        return result

    pause = _lightning_ensure_pause_state(reason=f"abandon_to_setup:{reason}")
    result["pause"] = pause
    if pause.get("status") != "OK" or _lightning_pause_visible_name(pause) != "pause_menu":
        live_snapshot = _lightning_live_snapshot()
        result["deployment_abandon_snapshot"] = live_snapshot
        deployment_recovery = _lightning_prepare_deployment_for_abandon(
            {
                "status": "STARTED",
                "reason": "abandon_to_setup_deployment_recovery",
                "initial_pause": pause,
            },
            profile=profile,
            snapshot=live_snapshot,
            reason_prefix="abandon_to_setup_deployment",
            ready_reason="abandon_to_setup_deployment_ready",
            quiet=True,
            dry_run=dry_run,
            require_active_mission=True,
        )
        result["deployment_abandon_recovery"] = deployment_recovery
        if deployment_recovery.get("status") in {"OK", "DRY_RUN"}:
            result = _lightning_click_abandon_to_setup(
                result,
                reason_prefix="abandon_to_setup",
                success_reason="abandoned_to_new_game_setup",
                accepted_final_uis={"new_game_setup"},
                dry_run=dry_run,
            )
            _print_result(result)
            return result
        result["status"] = "BLOCKED"
        result["reason"] = "abandon_to_setup_pause_failed"
        _print_result(result)
        return result

    result = _lightning_click_abandon_to_setup(
        result,
        reason_prefix="abandon_to_setup",
        success_reason="abandoned_to_new_game_setup",
        accepted_final_uis={"new_game_setup"},
        dry_run=dry_run,
    )
    _print_result(result)
    return result


def _lightning_active_route_mismatch_block(
    session: RunSession,
    snapshot: dict,
) -> dict | None:
    """Return an unresolved route mismatch that still describes deployment."""
    path = _lightning_route_mismatch_path(session)
    if not path.exists():
        return None
    try:
        block = json.loads(path.read_text())
    except Exception:
        return None
    if not isinstance(block, dict):
        return None
    actual = str(snapshot.get("mission_id") or "").strip()
    blocked_actual = str(block.get("actual_mission_id") or "").strip()
    if not actual or actual != blocked_actual:
        return None
    if int(snapshot.get("turn") or 0) != 0:
        return None
    if int(snapshot.get("deployment_zone_count") or 0) <= 0:
        return None
    if int(snapshot.get("mech_count") or 0) >= _LIGHTNING_EXPECTED_MECH_COUNT:
        return None
    result = dict(block)
    result["path"] = str(path)
    result["snapshot"] = snapshot
    return result


def _lightning_read_guard(session: RunSession | None = None) -> dict:
    session = session or _load_session()
    path = _lightning_guard_path(session)
    if not path.exists():
        return {"status": "MISSING", "path": str(path)}
    try:
        data = json.loads(path.read_text())
    except Exception as exc:
        return {"status": "ERROR", "path": str(path), "error": str(exc)}
    if isinstance(data, dict):
        data.setdefault("status", "OK")
        data["path"] = str(path)
        return data
    return {"status": "ERROR", "path": str(path), "error": "guard is not an object"}


def _lightning_write_guard(
    session: RunSession,
    *,
    guard_status: str,
    reason: str,
    visible_ui: dict | None = None,
    click_result: dict | None = None,
    metadata: dict | None = None,
) -> dict:
    path = _lightning_guard_path(session)
    payload = {
        "status": guard_status,
        "run_id": session.run_id,
        "updated_at": datetime.now().isoformat(timespec="seconds"),
        "desired_rest_state": "pause_menu",
        "reason": reason,
        "visible_ui": visible_ui,
        "click_result": click_result,
        "resume_hint": (
            "Stay in the pause menu while thinking. Use lightning_ui "
            "menu_continue only when the next UI click or combat command is "
            "ready, then return to pause as soon as the burst is done."
        ),
    }
    if isinstance(metadata, dict):
        payload.update(metadata)
    _atomic_json_write(path, payload)
    payload["path"] = str(path)
    return payload


def _lightning_recent_verified_pause_guard(
    *,
    max_age_seconds: float = 30.0,
    session: RunSession | None = None,
) -> dict:
    """Return a fresh, visually verified pause guard for fast Esc resume."""
    session = session or _load_session()
    guard = _lightning_read_guard(session)
    if guard.get("status") != "OK":
        return {
            "status": "SKIPPED",
            "reason": "guard_not_ok",
            "guard": guard,
        }
    if str(guard.get("run_id") or "") != str(session.run_id):
        return {
            "status": "SKIPPED",
            "reason": "guard_run_mismatch",
            "guard": guard,
            "session_run_id": session.run_id,
        }
    if guard.get("desired_rest_state") != "pause_menu":
        return {
            "status": "SKIPPED",
            "reason": "guard_not_pause_menu_rest",
            "guard": guard,
        }
    if not (guard.get("pause_verified") or guard.get("safe_to_think")):
        visible_ui = guard.get("visible_ui") if isinstance(guard, dict) else None
        if not _lightning_visible_ui_is_pause_menu(visible_ui):
            return {
                "status": "SKIPPED",
                "reason": "guard_lacks_pause_proof",
                "guard": guard,
            }

    updated_raw = str(guard.get("updated_at") or "").strip()
    age_seconds = None
    if updated_raw:
        try:
            age_seconds = (datetime.now() - datetime.fromisoformat(updated_raw)).total_seconds()
        except Exception:
            age_seconds = None
    if age_seconds is None:
        return {
            "status": "SKIPPED",
            "reason": "guard_timestamp_unreadable",
            "guard": guard,
        }
    if age_seconds > max(0.0, float(max_age_seconds or 0.0)):
        return {
            "status": "SKIPPED",
            "reason": "guard_too_old",
            "age_seconds": round(age_seconds, 3),
            "max_age_seconds": max_age_seconds,
            "guard": guard,
        }

    return {
        "status": "OK",
        "reason": "fresh_verified_pause_guard",
        "age_seconds": round(age_seconds, 3),
        "max_age_seconds": max_age_seconds,
        "guard": guard,
    }


def _lightning_ensure_pause_state(
    *,
    dry_run: bool = False,
    reason: str = "manual_pause_guard",
) -> dict:
    """Conservatively move the run into the pause menu when no panel is open."""
    session = _load_session()
    visible_ui = _lightning_audit_visible_ui_for_terminal_text(
        _lightning_visible_ui_snapshot()
    )
    status = visible_ui.get("status")
    visible_name = visible_ui.get("visible_ui")
    recommended = visible_ui.get("recommended_control")

    if status != "OK":
        result = {
            "status": "ERROR",
            "reason": "screen_classification_failed",
            "visible_ui": visible_ui,
            "planned_control": "pause",
        }
        if not dry_run:
            result["guard"] = _lightning_write_guard(
                session,
                guard_status=result["status"],
                reason=reason,
                visible_ui=visible_ui,
            )
        return result

    if visible_name == "system_privacy_prompt":
        prompt_result = _lightning_click_system_privacy_prompt_allow(
            visible_ui,
            dry_run=dry_run,
        )
        if dry_run or prompt_result.get("status") != "OK":
            return prompt_result
        retry = _lightning_ensure_pause_state(dry_run=False, reason=reason)
        retry["system_privacy_prompt_clear"] = prompt_result
        return retry

    if visible_name == "pause_menu":
        result = {
            "status": "OK",
            "reason": "already_paused",
            "already_paused": True,
            "visible_ui": visible_ui,
            "recommended_control": recommended,
        }
        if not dry_run:
            result["guard"] = _lightning_write_guard(
                session,
                guard_status=result["status"],
                reason=reason,
                visible_ui=visible_ui,
            )
        return result

    if visible_name == "new_game_setup":
        result = {
            "status": "OK",
            "reason": "new_game_setup_visible",
            "already_paused": False,
            "visible_ui": visible_ui,
            "recommended_control": recommended,
        }
        if not dry_run:
            result["guard"] = _lightning_write_guard(
                session,
                guard_status=result["status"],
                reason=reason,
                visible_ui=visible_ui,
            )
        return result

    if visible_name in _LIGHTNING_PAUSE_BLOCKING_UIS:
        result = {
            "status": "BLOCKED",
            "reason": "visible_panel_should_be_cleared_first",
            "visible_ui": visible_ui,
            "recommended_control": recommended,
            "next_step": (
                "Clear the visible panel with lightning_ui handle_screen or "
                f"lightning_ui {recommended}, then run lightning_ui ensure_pause."
            ),
        }
        if not dry_run:
            result["guard"] = _lightning_write_guard(
                session,
                guard_status=result["status"],
                reason=reason,
                visible_ui=visible_ui,
            )
        return result

    if visible_name in _LIGHTNING_NON_PAUSEABLE_UIS:
        result = {
            "status": "BLOCKED",
            "reason": "visible_ui_is_not_pauseable",
            "visible_ui": visible_ui,
            "recommended_control": recommended,
            "next_step": (
                "Do not spend live-clock time trying to pause here. Execute "
                "the required hot-path action immediately, usually "
                "`lightning_segment` from deployment."
            ),
        }
        if not dry_run:
            result["guard"] = _lightning_write_guard(
                session,
                guard_status=result["status"],
                reason=reason,
                visible_ui=visible_ui,
            )
        return result

    if dry_run:
        return {
            "status": "DRY_RUN",
            "reason": "would_click_pause",
            "planned_control": "pause",
            "already_paused": False,
            "visible_ui": visible_ui,
        }

    pause_attempts = []
    pauseable_after_escape = {
        "deployment_screen",
        "island_map",
        "island_map_or_unknown",
        "mission_preview_panel",
    }
    max_pause_attempts = 2
    click_result = {}
    pause_verify = None
    pause_verified = False
    for attempt in range(max_pause_attempts):
        click_result = _lightning_press_pause_escape(settle_seconds=0.35)
        pause_attempt = {
            "attempt": attempt + 1,
            "click_result": click_result,
        }
        if click_result.get("status") == "OK":
            pause_verify = _lightning_visible_ui_snapshot(include_ocr=True)
            pause_attempt["pause_verify"] = pause_verify
            pause_verified = (
                pause_verify.get("status") == "OK"
                and pause_verify.get("visible_ui") == "pause_menu"
            )
            pause_attempt["pause_verified"] = pause_verified
        pause_attempts.append(pause_attempt)
        if pause_verified:
            break
        if click_result.get("status") != "OK":
            break
        after_visible = (
            pause_verify.get("visible_ui")
            if isinstance(pause_verify, dict)
            else None
        )
        if after_visible not in pauseable_after_escape:
            break
    result = {
        "status": click_result.get("status", "ERROR"),
        "reason": "pause_clicked",
        "planned_control": "pause",
        "already_paused": False,
        "visible_ui": visible_ui,
        "click_result": click_result,
        "pause_verified": pause_verified,
        "pause_verify": pause_verify,
    }
    if len(pause_attempts) > 1:
        result["pause_attempts"] = pause_attempts
    if click_result.get("status") != "OK":
        result["reason"] = "pause_click_failed"
        result["error"] = click_result.get("error")
    elif not pause_verified:
        result["status"] = "BLOCKED"
        result["reason"] = "pause_not_verified"
        result["next_step"] = (
            "Inspect the screen before running a timed Lightning combat burst; "
            "the pause click did not visibly reach the pause menu."
        )
    result["guard"] = _lightning_write_guard(
        session,
        guard_status=result["status"],
        reason=reason,
        visible_ui=pause_verify or visible_ui,
        click_result=click_result,
    )
    return result


def _lightning_pause_guard_decision(
    visible_ui: dict,
    live_snapshot: dict | None = None,
    *,
    lightning_speed_loss_policy: bool = False,
) -> dict:
    """Decide whether the timer pause guard may click Pause on this screen."""
    visible_name = visible_ui.get("visible_ui") if isinstance(visible_ui, dict) else None
    if not isinstance(visible_ui, dict) or visible_ui.get("status") != "OK":
        return {
            "status": "ERROR",
            "reason": "screen_classification_failed",
            "pause_allowed": False,
        }
    focus_proof = visible_ui.get("game_focus_proof")
    if (
        visible_name != "system_privacy_prompt"
        and isinstance(focus_proof, dict)
        and focus_proof.get("status") != "OK"
    ):
        return {
            "status": "BLOCKED",
            "reason": "game_focus_proof_failed",
            "pause_allowed": False,
            "game_focus_proof": focus_proof,
            "next_step": (
                "The screenshot/focus proof does not show Into the Breach as "
                "the frontmost bounded game window. Do not click game UI; "
                "restore focus and resample before continuing."
            ),
        }
    if visible_name == "pause_menu":
        return {
            "status": "OK",
            "reason": "already_paused",
            "pause_allowed": False,
            "already_paused": True,
        }
    live_snapshot = live_snapshot or {}
    live_phase = live_snapshot.get("phase") if isinstance(live_snapshot, dict) else None
    if (
        visible_name in {"new_game_setup", "title_screen"}
        and isinstance(live_snapshot, dict)
        and live_snapshot.get("status") == "OK"
        and live_snapshot.get("bridge_heartbeat_alive") is True
        and live_snapshot.get("in_active_mission") is True
        and live_phase in _COMBAT_BRIDGE_PHASES
    ):
        return {
            "status": "OK",
            "reason": "live_combat_classifier_conflict_pause_available",
            "pause_allowed": True,
            "visible_ui": visible_name,
            "phase": live_phase,
        }
    if visible_name == "new_game_setup":
        return {
            "status": "OK",
            "reason": "new_game_setup_visible",
            "pause_allowed": False,
        }
    if visible_name == "title_screen":
        return {
            "status": "OK",
            "reason": "title_screen_visible",
            "pause_allowed": False,
        }
    if visible_name == "system_privacy_prompt":
        return {
            "status": "BLOCKED",
            "reason": "external_system_prompt_visible",
            "pause_allowed": False,
            "next_step": (
                "A macOS privacy prompt is covering the game. The autonomous "
                "runner has standing approval to click Allow and resample."
            ),
        }
    terminal_evidence = _lightning_terminal_outcome_evidence(
        visible_ui,
        lightning_speed_loss_policy=lightning_speed_loss_policy,
    )
    if terminal_evidence is not None:
        return {
            "status": "BLOCKED",
            "reason": "terminal_outcome_visible",
            "pause_allowed": False,
            "terminal_evidence": terminal_evidence,
            "next_step": (
                "Stop before pausing or clearing this panel. Inspect the "
                "visible terminal, KIA, timeline-lost, or failed-objective "
                "evidence first."
            ),
        }
    if visible_name == "kia_panel":
        return {
            "status": "BLOCKED",
            "reason": "kia_panel_visible",
            "pause_allowed": False,
            "next_step": "Inspect the terminal outcome before more Lightning UI clicks.",
        }
    if visible_name == "pod_open_panel":
        return {
            "status": "BLOCKED",
            "reason": "visible_panel_should_be_cleared_first",
            "pause_allowed": False,
            "next_step": "Clear the visible pod panel before trying to pause.",
        }
    if (
        visible_name in _LIGHTNING_NON_PAUSEABLE_UIS
        or visible_ui.get("non_pauseable") is True
    ):
        return {
            "status": "BLOCKED",
            "reason": "visible_ui_is_not_pauseable",
            "pause_allowed": False,
        }

    visible_island_map = visible_name == "island_map"
    if live_snapshot.get("status") == "OK":
        try:
            turn = int(live_snapshot.get("turn") or 0)
        except (TypeError, ValueError):
            turn = 0
        try:
            deployment_zone_count = int(
                live_snapshot.get("deployment_zone_count") or 0
            )
        except (TypeError, ValueError):
            deployment_zone_count = 0
        phase = live_snapshot.get("phase")
        if (
            not visible_island_map
            and
            live_snapshot.get("in_active_mission") is True
            and phase in _COMBAT_BRIDGE_PHASES
        ):
            return {
                "status": "OK",
                "reason": "live_combat_phase",
                "pause_allowed": True,
                "phase": phase,
            }
        if not visible_island_map and turn == 0 and deployment_zone_count > 0:
            return {
                "status": "OK",
                "reason": "deployment_phase",
                "pause_allowed": True,
            }
        if (
            visible_name == "island_map_or_unknown"
            and int(live_snapshot.get("island_map_count") or 0) <= 0
            and live_snapshot.get("in_active_mission") is not False
        ):
            return {
                "status": "SKIPPED",
                "reason": "unknown_screen_without_map_context",
                "pause_allowed": False,
            }
    elif (
        visible_name == "island_map_or_unknown"
        and not _lightning_visible_ui_has_preview_commit_context(visible_ui)
    ):
        return {
            "status": "SKIPPED",
            "reason": "unknown_screen_without_bridge",
            "pause_allowed": False,
        }

    if visible_name in _LIGHTNING_PAUSE_GUARD_UIS:
        return {
            "status": "OK",
            "reason": "safe_ui_pause_available",
            "pause_allowed": True,
            "visible_ui": visible_name,
        }

    return {
        "status": "SKIPPED",
        "reason": "visible_ui_not_pause_guard_eligible",
        "pause_allowed": False,
        "visible_ui": visible_name,
    }


def _lightning_timer_growth_probe(
    profile: str = "Alpha",
    *,
    sample_seconds: float = 0.25,
    first_timer: dict | None = None,
) -> dict:
    """Sample save/profile current.time twice to detect an advancing run clock."""
    first = first_timer or _lightning_read_save_game_timer(profile)
    wait = max(0.0, float(sample_seconds or 0.0))
    if wait > 0:
        time.sleep(wait)
    second = _lightning_read_save_game_timer(profile)
    result = {
        "status": "UNKNOWN",
        "sample_seconds": round(wait, 3),
        "first_timer": first,
        "second_timer": second,
        "running": None,
        "delta_seconds": None,
    }
    if (
        first.get("status") == "OK"
        and second.get("status") == "OK"
        and first.get("game_seconds") is not None
        and second.get("game_seconds") is not None
    ):
        delta = float(second["game_seconds"]) - float(first["game_seconds"])
        result.update(
            {
                "status": "OK",
                "delta_seconds": round(delta, 3),
                "running": delta > 0.05,
            }
        )
    return result


def _lightning_timer_pause_guard_once(
    profile: str = "Alpha",
    *,
    dry_run: bool = False,
    click_ui: bool = True,
    require_timer_growth: bool = False,
    sample_seconds: float = 0.25,
    verify_sample_seconds: float = 0.25,
    reason: str = "lightning_pause_guard",
    bridge_refine_before_pause: bool = True,
    lightning_speed_loss_policy: bool = False,
) -> dict:
    """Click Pause from timer-bearing safe screens, including reward panels."""
    session = _load_session()
    visible_ui = _lightning_audit_visible_ui_for_terminal_text(
        _lightning_visible_ui_snapshot(bridge_refine=bridge_refine_before_pause)
    )
    if visible_ui.get("visible_ui") == "island_map":
        live_snapshot = {
            "status": "SKIPPED",
            "reason": "visible_island_map_authoritative",
        }
    elif not bridge_refine_before_pause:
        live_snapshot = {
            "status": "SKIPPED",
            "reason": "pre_pause_bridge_io_disabled",
        }
    else:
        bridge_refine = visible_ui.get("bridge_refine_snapshot")
        live_snapshot = (
            bridge_refine
            if isinstance(bridge_refine, dict)
            and bridge_refine.get("status") == "OK"
            else _lightning_live_snapshot()
        )
    decision = _lightning_pause_guard_decision(
        visible_ui,
        live_snapshot,
        lightning_speed_loss_policy=lightning_speed_loss_policy,
    )
    base = {
        "visible_ui": visible_ui,
        "live_snapshot": live_snapshot,
        "decision": decision,
    }

    if not decision.get("pause_allowed"):
        if visible_ui.get("visible_ui") == "system_privacy_prompt":
            prompt_result = _lightning_click_system_privacy_prompt_allow(
                visible_ui,
                dry_run=dry_run,
            )
            if dry_run or prompt_result.get("status") != "OK":
                return {
                    **prompt_result,
                    **base,
                }
            retry = _lightning_timer_pause_guard_once(
                profile=profile,
                dry_run=False,
                click_ui=click_ui,
                require_timer_growth=require_timer_growth,
                sample_seconds=sample_seconds,
                verify_sample_seconds=verify_sample_seconds,
                reason=reason,
                lightning_speed_loss_policy=lightning_speed_loss_policy,
            )
            retry["system_privacy_prompt_clear"] = prompt_result
            return retry
        result = {
            "status": decision.get("status", "SKIPPED"),
            "reason": decision.get("reason", "pause_not_allowed"),
            **base,
        }
        if decision.get("already_paused") and not dry_run:
            result["guard"] = _lightning_write_guard(
                session,
                guard_status="OK",
                reason=reason,
                visible_ui=visible_ui,
                metadata={
                    "pause_verified": True,
                    "safe_to_think": True,
                    "timer_stop_verified": False,
                },
            )
        return result

    timer_probe = None
    if require_timer_growth:
        timer_probe = _lightning_timer_growth_probe(
            profile,
            sample_seconds=sample_seconds,
        )
        if timer_probe.get("running") is not True:
            return {
                "status": "SKIPPED",
                "reason": "timer_not_observed_running",
                "timer_probe": timer_probe,
                **base,
            }

    if dry_run or not click_ui:
        return {
            "status": "DRY_RUN" if dry_run else "NO_CLICK",
            "reason": "would_click_pause",
            "planned_control": "pause",
            "timer_probe": timer_probe,
            **base,
        }

    pause_attempts = []
    pauseable_after_escape = {
        "island_map",
        "island_map_or_unknown",
        "mission_preview_panel",
    }
    max_pause_attempts = 2
    click_result = {}
    pause_verify = None
    pause_verified = False
    timer_stop_verified = False
    stop_probe = None
    for attempt in range(max_pause_attempts):
        click_result = _lightning_press_pause_escape(settle_seconds=0.35)
        pause_attempt = {
            "attempt": attempt + 1,
            "click_result": click_result,
        }
        if click_result.get("status") == "OK":
            pause_verify = _lightning_visible_ui_snapshot(include_ocr=True)
            pause_attempt["pause_verify"] = pause_verify
            pause_verified = (
                pause_verify.get("status") == "OK"
                and pause_verify.get("visible_ui") == "pause_menu"
            )
            pause_attempt["pause_verified"] = pause_verified
            can_probe_timer_stop = attempt == max_pause_attempts - 1
            if (
                not pause_verified
                and can_probe_timer_stop
                and verify_sample_seconds > 0
            ):
                stop_probe = _lightning_timer_growth_probe(
                    profile,
                    sample_seconds=verify_sample_seconds,
                )
                timer_stop_verified = (
                    stop_probe.get("status") == "OK"
                    and stop_probe.get("running") is False
                )
                pause_verified = timer_stop_verified
                pause_attempt["stop_probe"] = stop_probe
                pause_attempt["timer_stop_verified"] = timer_stop_verified
        pause_attempts.append(pause_attempt)
        if pause_verified:
            break
        if click_result.get("status") != "OK":
            break
        after_visible = (
            pause_verify.get("visible_ui")
            if isinstance(pause_verify, dict)
            else None
        )
        if after_visible not in pauseable_after_escape:
            break

    result = {
        "status": click_result.get("status", "ERROR"),
        "reason": "pause_clicked",
        "planned_control": "pause",
        "timer_probe": timer_probe,
        "visible_ui": visible_ui,
        "live_snapshot": live_snapshot,
        "decision": decision,
        "click_result": click_result,
        "pause_verified": pause_verified,
        "timer_stop_verified": timer_stop_verified,
        "pause_verify": pause_verify,
        "stop_probe": stop_probe,
    }
    if len(pause_attempts) > 1:
        result["pause_attempts"] = pause_attempts
    if click_result.get("status") != "OK":
        result["reason"] = "pause_click_failed"
        result["error"] = click_result.get("error")
    elif timer_stop_verified:
        result["reason"] = "pause_clicked_timer_stopped"
    elif not pause_verified:
        result["status"] = "BLOCKED"
        result["reason"] = "pause_not_verified"
        result["next_step"] = (
            "Pause was clicked from a safe timer screen, but the pause menu "
            "or stopped timer was not verified. Inspect before more timed UI."
        )
    result["guard"] = _lightning_write_guard(
        session,
        guard_status=result["status"],
        reason=reason,
        visible_ui=pause_verify or visible_ui,
        click_result=click_result,
        metadata={
            "pause_verified": bool(pause_verified),
            "safe_to_think": bool(pause_verified),
            "timer_stop_verified": bool(timer_stop_verified),
        },
    )
    return result


def cmd_lightning_pause_guard(
    profile: str = "Alpha",
    *,
    seconds: float = 5.0,
    interval: float = 0.25,
    sample_seconds: float = 0.25,
    require_timer_growth: bool = False,
    dry_run: bool = False,
    click_ui: bool = True,
    once: bool = False,
    lightning_speed_loss_policy: bool = False,
) -> dict:
    """Cooperatively watch for safe timer screens and pause immediately."""
    started = time.monotonic()
    deadline = started + max(0.0, float(seconds or 0.0))
    polls: list[dict] = []
    while True:
        poll = _lightning_timer_pause_guard_once(
            profile,
            dry_run=dry_run,
            click_ui=click_ui,
            require_timer_growth=require_timer_growth,
            sample_seconds=sample_seconds,
            reason="lightning_pause_guard_watch",
            lightning_speed_loss_policy=lightning_speed_loss_policy,
        )
        polls.append(poll)
        poll_status = poll.get("status")
        poll_reason = poll.get("reason")
        if (
            poll_status in {"OK", "DRY_RUN", "NO_CLICK", "BLOCKED", "ERROR"}
            or poll_reason in {
                "already_paused",
                "pause_clicked",
                "pause_clicked_timer_stopped",
                "would_click_pause",
            }
        ):
            break
        if once or time.monotonic() >= deadline:
            break
        time.sleep(max(0.0, float(interval or 0.0)))

    elapsed = time.monotonic() - started
    last_poll = polls[-1] if polls else {}
    status = last_poll.get("status", "NO_ACTION")
    reason = last_poll.get("reason", "no_pauseable_timer_screen_seen")
    if status == "SKIPPED":
        status = "NO_ACTION"
        reason = "no_pauseable_timer_screen_seen"
    result = {
        "status": status,
        "reason": reason,
        "poll_count": len(polls),
        "elapsed_wall_seconds": round(elapsed, 3),
        "last_poll": last_poll,
        "require_timer_growth": require_timer_growth,
        "sample_seconds": sample_seconds,
    }
    if len(polls) > 1:
        result["poll_reasons"] = [poll.get("reason") for poll in polls]

    print("\n=== LIGHTNING PAUSE GUARD ===")
    print(f"  status:  {result.get('status')}")
    print(f"  reason:  {result.get('reason')}")
    print(f"  polls:   {result.get('poll_count')}")
    print(
        "  visible: "
        f"{last_poll.get('visible_ui', {}).get('visible_ui')}"
    )
    _print_result(result)
    return result


def _lightning_handle_visible_screen(
    *,
    dry_run: bool = False,
    lightning_speed_loss_policy: bool = False,
) -> dict:
    """Click the obvious continuation button for supported non-combat panels."""
    visible_ui = _lightning_audit_visible_ui_for_terminal_text(
        _lightning_visible_ui_snapshot()
    )
    if visible_ui.get("status") != "OK":
        return {
            "status": "ERROR",
            "reason": "screen_classification_failed",
            "visible_ui": visible_ui,
        }
    terminal_block = _lightning_terminal_panel_block(
        visible_ui,
        lightning_speed_loss_policy=lightning_speed_loss_policy,
    )
    if terminal_block is not None:
        return terminal_block

    visible_name = visible_ui.get("visible_ui")
    if visible_name == "pause_menu":
        ocr_visible_ui = _lightning_audit_visible_ui_for_terminal_text(
            _lightning_visible_ui_snapshot(include_ocr=True)
        )
        if _lightning_external_system_prompt_visible(ocr_visible_ui):
            visible_ui = ocr_visible_ui
            visible_name = visible_ui.get("visible_ui")
    control = _lightning_preferred_visible_control(
        visible_name,
        visible_ui.get("recommended_control"),
        visible_ui,
    )
    if visible_name == "pause_menu":
        return {
            "status": "PAUSED",
            "reason": "pause_menu_is_resting_state",
            "visible_ui": visible_ui,
            "recommended_control": control,
            "next_step": (
                "Stay paused while planning. Use lightning_ui menu_continue "
                "only when the next action is ready."
            ),
        }
    if visible_name == "system_privacy_prompt":
        return _lightning_click_system_privacy_prompt_allow(
            visible_ui,
            dry_run=dry_run,
        )
    if visible_name == "mission_preview_panel" and control != "dialogue_textbox":
        return {
            "status": "BLOCKED",
            "reason": "mission_preview_requires_route_validation",
            "visible_ui": visible_ui,
            "recommended_control": control,
            "next_step": (
                "Do not click Start Mission from a generic screen-clear helper. "
                "Use the route-start path after mission identity is verified, or "
                "call an explicit visible-start command after reviewing evidence."
            ),
        }
    if visible_name not in _LIGHTNING_AUTO_HANDLE_UIS or not control:
        return {
            "status": "NO_KNOWN_SCREEN_ACTION",
            "visible_ui": visible_ui,
            "next_step": "Inspect the screen before clicking an uncalibrated target.",
        }

    from src.control.mac_click import click_known_window_control

    click_result = click_known_window_control(control, dry_run=dry_run)
    fallback_result = None
    fallback_control = None
    fallback_visible_ui = None
    dialogue_result = None
    if control == "reward_continue" and not dry_run and click_result.get("status") == "OK":
        fallback_visible_ui = _lightning_audit_visible_ui_for_terminal_text(
            _lightning_visible_ui_snapshot()
        )
        terminal_block = _lightning_terminal_panel_block(
            fallback_visible_ui,
            reason="terminal_outcome_visible_after_reward_continue",
            lightning_speed_loss_policy=lightning_speed_loss_policy,
        )
        if terminal_block is not None:
            terminal_block["control"] = control
            terminal_block["click_result"] = click_result
            return terminal_block
        if fallback_visible_ui.get("visible_ui") in {"reward_panel", "bottom_continue_panel"}:
            fallback_control = "bottom_continue"
            fallback_result = click_known_window_control("bottom_continue", dry_run=dry_run)
        elif _lightning_visible_ui_is_perfect_reward_continue_dialogue(fallback_visible_ui):
            fallback_control = "dialogue_textbox"
            dialogue_result = click_known_window_control(
                "dialogue_textbox",
                dry_run=dry_run,
            )
            if dialogue_result.get("status") == "OK":
                fallback_control = "reward_continue"
                fallback_result = click_known_window_control(
                    "reward_continue",
                    dry_run=dry_run,
                )
            else:
                fallback_result = dialogue_result
    if (
        visible_name == "perfect_reward_choice"
        and control == "dialogue_textbox"
        and not dry_run
        and click_result.get("status") == "OK"
        and _lightning_visible_ui_is_perfect_reward_continue_dialogue(visible_ui)
    ):
        fallback_control = "reward_continue"
        fallback_result = click_known_window_control("reward_continue", dry_run=dry_run)
    if control == "perfect_reward_grid" and not dry_run and click_result.get("status") == "OK":
        fallback_visible_ui = _lightning_audit_visible_ui_for_terminal_text(
            _lightning_visible_ui_snapshot()
        )
        terminal_block = _lightning_terminal_panel_block(
            fallback_visible_ui,
            reason="terminal_outcome_visible_after_perfect_reward_grid",
            lightning_speed_loss_policy=lightning_speed_loss_policy,
        )
        if terminal_block is not None:
            terminal_block["control"] = control
            terminal_block["click_result"] = click_result
            return terminal_block
        if _lightning_visible_ui_is_perfect_reward_continue_after_grid_click(
            fallback_visible_ui
        ):
            fallback_control = "dialogue_textbox"
            dialogue_result = click_known_window_control(
                "dialogue_textbox",
                dry_run=dry_run,
            )
            if dialogue_result.get("status") == "OK":
                fallback_control = "reward_continue"
                fallback_result = click_known_window_control(
                    "reward_continue",
                    dry_run=dry_run,
                )
            else:
                fallback_result = dialogue_result
    if control == "leave_island" and not dry_run and click_result.get("status") == "OK":
        fallback_control = "leave_confirm_yes"
        fallback_result = click_known_window_control("leave_confirm_yes", dry_run=dry_run)
    result = {
        "status": click_result.get("status", "ERROR"),
        "visible_ui": visible_ui,
        "control": control,
        "click_result": click_result,
        "next_step": (
            "Rerun lightning_ui handle_screen if another panel appears; "
            "otherwise run lightning_ui ensure_pause or lightning_attempt."
        ),
    }
    if fallback_result is not None:
        result["fallback_visible_ui"] = fallback_visible_ui
        result["fallback_control"] = fallback_control
        if dialogue_result is not None:
            result["dialogue_click_result"] = dialogue_result
        result["fallback_click_result"] = fallback_result
        if fallback_result.get("status") != "OK":
            result["status"] = fallback_result.get("status", "ERROR")
    return result


def _lightning_recover_timeline_lost_to_setup(*, dry_run: bool = False) -> dict:
    """Recover a terminal Timeline Lost panel by selecting a carry-forward pilot."""
    from src.control.mac_click import click_known_window_control

    visible_ui = _lightning_visible_ui_snapshot(include_ocr=True)
    audited = _lightning_audit_visible_ui_for_terminal_text(visible_ui)
    evidence = _lightning_terminal_outcome_evidence(audited)
    result: dict = {
        "status": "STARTED",
        "reason": "timeline_lost_recovery",
        "visible_ui": audited,
        "terminal_evidence": evidence,
        "accepted_final_uis": ["new_game_setup", "title_screen"],
    }
    if not isinstance(evidence, dict) or evidence.get("phrase") != "timeline lost":
        result["status"] = "BLOCKED"
        result["reason"] = "timeline_lost_not_verified"
        result["next_step"] = (
            "Do not use terminal recovery unless OCR or terminal audit proves "
            "Timeline Lost on the visible screen."
        )
        return result

    pilot_controls = (
        "abandon_pilot_slot",
        "abandon_pilot_slot_wide",
        "abandon_pilot_slot_two_left",
        "abandon_pilot_slot_two_right",
        "abandon_pilot_slot_right",
    )
    result["pilot_controls"] = list(pilot_controls)
    if dry_run:
        result["status"] = "DRY_RUN"
        result["reason"] = "timeline_lost_recovery_planned"
        result["next_step"] = (
            "Run without --dry-run to select the first calibrated carry-forward "
            "pilot slot, verifying setup/title after each click."
        )
        return result

    attempts: list[dict] = []
    for control in pilot_controls:
        click_result = click_known_window_control(control)
        attempt = {
            "control": control,
            "click_result": click_result,
        }
        attempts.append(attempt)
        if click_result.get("status") != "OK":
            result["status"] = "BLOCKED"
            result["reason"] = "timeline_lost_pilot_click_failed"
            result["attempts"] = attempts
            result["next_step"] = "Inspect the terminal screen before another click."
            return result
        time.sleep(_LIGHTNING_FAST_UI_CONFIRM_SETTLE_SECONDS)
        final_ui = _lightning_visible_ui_snapshot(include_ocr=True)
        final_audited = _lightning_audit_visible_ui_for_terminal_text(final_ui)
        attempt["post_click_visible_ui"] = final_audited
        final_name = final_audited.get("visible_ui")
        if final_audited.get("status") == "OK" and final_name in {
            "new_game_setup",
            "title_screen",
        }:
            result["status"] = "OK"
            result["reason"] = (
                "timeline_lost_recovered_to_setup"
                if final_name == "new_game_setup"
                else "timeline_lost_recovered_to_title"
            )
            result["attempts"] = attempts
            result["final_ui"] = final_audited
            if final_name == "new_game_setup":
                result["bridge_reset_cleanup"] = (
                    _lightning_clear_bridge_files_after_timeline_reset()
                )
            result["next_step"] = (
                "Capture setup/title proof before starting the next Lightning run."
            )
            return result
        terminal_after = _lightning_terminal_outcome_evidence(final_audited)
        attempt["terminal_evidence"] = terminal_after
        if not (
            isinstance(terminal_after, dict)
            and terminal_after.get("phrase") == "timeline lost"
        ):
            result["status"] = "BLOCKED"
            result["reason"] = "timeline_lost_recovery_unexpected_screen"
            result["attempts"] = attempts
            result["final_ui"] = final_audited
            result["next_step"] = (
                "The screen changed but setup/title was not verified. Inspect "
                "before any more recovery clicks."
            )
            return result

    result["status"] = "BLOCKED"
    result["reason"] = "timeline_lost_recovery_exhausted"
    result["attempts"] = attempts
    result["next_step"] = (
        "All calibrated carry-forward slots were tried and Timeline Lost "
        "remained visible. Use hover/screenshot/manual review before clicking."
    )
    return result


def _lightning_clear_visible_panel_chain(
    *,
    dry_run: bool = False,
    max_steps: int = 8,
    lightning_speed_loss_policy: bool = False,
    allow_mission_preview_dialogue: bool = True,
) -> dict:
    """Clear chained safe post-mission panels, reclassifying after each click."""
    from src.control.mac_click import click_known_window_control

    steps: list[dict] = []
    visible_ui: dict = {}
    for step_index in range(max_steps):
        visible_ui = _lightning_audit_visible_ui_for_terminal_text(
            _lightning_visible_ui_snapshot()
        )
        if visible_ui.get("status") != "OK":
            return {
                "status": "ERROR",
                "reason": "screen_classification_failed",
                "steps": steps,
                "visible_ui": visible_ui,
            }
        terminal_block = _lightning_terminal_panel_block(
            visible_ui,
            steps=steps,
            lightning_speed_loss_policy=lightning_speed_loss_policy,
        )
        if terminal_block is not None:
            return terminal_block

        visible_name = visible_ui.get("visible_ui")
        control = _lightning_preferred_visible_control(
            visible_name,
            visible_ui.get("recommended_control"),
            visible_ui,
        )

        if (
            visible_name == "mission_preview_panel"
            and control == "dialogue_textbox"
            and not allow_mission_preview_dialogue
        ):
            return {
                "status": "OK" if steps else "NO_ACTION",
                "reason": (
                    "panel_chain_cleared"
                    if steps
                    else "mission_preview_dialogue_requires_route_validation"
                ),
                "steps": steps,
                "visible_ui": visible_ui,
            }

        if not control or not _lightning_is_safe_clear_ui(
            visible_name,
            control,
            visible_ui,
        ):
            return {
                "status": "OK" if steps else "NO_ACTION",
                "reason": "panel_chain_cleared" if steps else "no_safe_panel_visible",
                "steps": steps,
                "visible_ui": visible_ui,
            }

        step = {
            "step": step_index,
            "visible_ui": visible_ui,
            "control": control,
        }
        if dry_run:
            step["click_result"] = {"status": "DRY_RUN", "control": control}
            steps.append(step)
            return {
                "status": "DRY_RUN",
                "reason": "would_clear_panel",
                "steps": steps,
                "visible_ui": visible_ui,
            }

        click_result = click_known_window_control(str(control))
        step["click_result"] = click_result
        if (
            visible_name == "perfect_reward_choice"
            and control == "dialogue_textbox"
            and click_result.get("status") == "OK"
            and _lightning_visible_ui_is_perfect_reward_continue_dialogue(visible_ui)
        ):
            fallback_result = click_known_window_control("reward_continue")
            step["fallback_control"] = "reward_continue"
            step["fallback_click_result"] = fallback_result
            if fallback_result.get("status") != "OK":
                click_result = fallback_result
        if control == "reward_continue" and click_result.get("status") == "OK":
            fallback_visible_ui = _lightning_audit_visible_ui_for_terminal_text(
                _lightning_visible_ui_snapshot()
            )
            terminal_block = _lightning_terminal_panel_block(
                fallback_visible_ui,
                reason="terminal_outcome_visible_after_reward_continue",
                steps=steps + [step],
                lightning_speed_loss_policy=lightning_speed_loss_policy,
            )
            if terminal_block is not None:
                return terminal_block
            if fallback_visible_ui.get("visible_ui") in {"reward_panel", "bottom_continue_panel"}:
                fallback_result = click_known_window_control("bottom_continue")
                step["fallback_visible_ui"] = fallback_visible_ui
                step["fallback_control"] = "bottom_continue"
                step["fallback_click_result"] = fallback_result
                if fallback_result.get("status") != "OK":
                    click_result = fallback_result
            elif _lightning_visible_ui_is_perfect_reward_continue_dialogue(fallback_visible_ui):
                dialogue_result = click_known_window_control("dialogue_textbox")
                step["fallback_visible_ui"] = fallback_visible_ui
                step["fallback_control"] = "dialogue_textbox"
                step["dialogue_click_result"] = dialogue_result
                if dialogue_result.get("status") == "OK":
                    fallback_result = click_known_window_control("reward_continue")
                    step["fallback_control"] = "reward_continue"
                    step["fallback_click_result"] = fallback_result
                else:
                    fallback_result = dialogue_result
                    step["fallback_click_result"] = fallback_result
                if fallback_result.get("status") != "OK":
                    click_result = fallback_result
        if control == "perfect_reward_grid" and click_result.get("status") == "OK":
            fallback_visible_ui = _lightning_audit_visible_ui_for_terminal_text(
                _lightning_visible_ui_snapshot()
            )
            terminal_block = _lightning_terminal_panel_block(
                fallback_visible_ui,
                reason="terminal_outcome_visible_after_perfect_reward_grid",
                steps=steps + [step],
                lightning_speed_loss_policy=lightning_speed_loss_policy,
            )
            if terminal_block is not None:
                return terminal_block
            if _lightning_visible_ui_is_perfect_reward_continue_after_grid_click(
                fallback_visible_ui
            ):
                dialogue_result = click_known_window_control("dialogue_textbox")
                step["fallback_visible_ui"] = fallback_visible_ui
                step["fallback_control"] = "dialogue_textbox"
                step["dialogue_click_result"] = dialogue_result
                if dialogue_result.get("status") == "OK":
                    fallback_result = click_known_window_control("reward_continue")
                    step["fallback_control"] = "reward_continue"
                    step["fallback_click_result"] = fallback_result
                else:
                    fallback_result = dialogue_result
                    step["fallback_click_result"] = fallback_result
                if fallback_result.get("status") != "OK":
                    click_result = fallback_result
        if control == "leave_island" and click_result.get("status") == "OK":
            fallback_result = click_known_window_control("leave_confirm_yes")
            step["fallback_control"] = "leave_confirm_yes"
            step["fallback_click_result"] = fallback_result
            if fallback_result.get("status") != "OK":
                click_result = fallback_result
        steps.append(step)
        if click_result.get("status") != "OK":
            return {
                "status": "ERROR",
                "reason": "panel_clear_click_failed",
                "steps": steps,
                "visible_ui": visible_ui,
                "control": control,
                "click_result": click_result,
            }

    final_ui = _lightning_visible_ui_snapshot()
    return {
        "status": "MAX_STEPS_REACHED",
        "reason": "safe_panel_chain_still_visible",
        "steps": steps,
        "visible_ui": final_ui,
        "next_step": "Inspect the screen before clearing more panels.",
    }


def _lightning_clear_tail_to_pause(
    *,
    dry_run: bool = False,
    max_steps: int = 8,
    lightning_speed_loss_policy: bool = False,
    allow_mission_preview_dialogue: bool = True,
) -> dict:
    """Resume if needed, clear safe UI-tail panels, then return to pause."""
    initial_ui = _lightning_visible_ui_snapshot()
    if initial_ui.get("status") != "OK":
        return {
            "status": "ERROR",
            "reason": "screen_classification_failed",
            "initial_ui": initial_ui,
        }

    planned = ["clear_visible_panel_chain", "ensure_pause"]
    resumed = None
    if _lightning_visible_ui_is_pause_menu(initial_ui):
        resume_control = "menu_continue" if os.name == "nt" else "pause_menu_escape"
        planned.insert(0, resume_control)
        if dry_run:
            return {
                "status": "DRY_RUN",
                "reason": "would_resume_clear_tail_and_pause",
                "initial_ui": initial_ui,
                "planned_controls": planned,
            }
        resumed = _lightning_resume_if_paused(dry_run=False, click_ui=True)
        if resumed is not None and resumed.get("status") != "OK":
            return {
                "status": resumed.get("status", "ERROR"),
                "reason": resumed.get("reason", "resume_from_pause_failed"),
                "initial_ui": initial_ui,
                "resume_result": resumed,
                "next_step": resumed.get(
                    "next_step",
                    "Verify the game window focus before clearing live panels.",
                ),
            }
    elif dry_run:
        return {
            "status": "DRY_RUN",
            "reason": "would_clear_tail_and_pause",
            "initial_ui": initial_ui,
            "planned_controls": planned,
        }

    clear_result = _lightning_clear_visible_panel_chain(
        dry_run=False,
        max_steps=max_steps,
        lightning_speed_loss_policy=lightning_speed_loss_policy,
        allow_mission_preview_dialogue=allow_mission_preview_dialogue,
    )
    clear_still_intro = (
        clear_result.get("status") == "NO_ACTION"
        and _lightning_visible_ui_is_intro_continue_panel(
            clear_result.get("visible_ui")
        )
    )
    pause_result = _lightning_ensure_pause_state(
        dry_run=False,
        reason="lightning_ui_clear_tail_to_pause",
    )
    clear_ok = (
        clear_result.get("status") in {"OK", "NO_ACTION"}
        and not clear_still_intro
    )
    pause_ok = pause_result.get("status") == "OK"
    status = "OK" if clear_ok and pause_ok else "BLOCKED"
    reason = (
        "tail_cleared_and_paused"
        if status == "OK"
        else (
            "intro_continue_still_visible"
            if clear_still_intro
            else "tail_clear_or_pause_incomplete"
        )
    )
    return {
        "status": status,
        "reason": reason,
        "initial_ui": initial_ui,
        "resume_result": resumed,
        "clear_result": clear_result,
        "pause_result": pause_result,
        "next_step": (
            "Stay in pause while planning. If pause_result is blocked on "
            "deployment_screen, run lightning_segment immediately."
        ),
    }


def _lightning_dialogue_box_score(image_path: str | Path) -> dict:
    """Detect the wide advisor dialogue box before clicking its hot zone."""
    try:
        from PIL import Image
    except Exception as exc:
        return {"status": "UNAVAILABLE", "error": f"PIL unavailable: {exc}"}
    try:
        image = Image.open(image_path)
    except Exception as exc:
        return {"status": "ERROR", "error": f"failed to open screenshot: {exc}"}

    score = _lightning_button_like_score(
        image,
        center=(640, 175),
        size=(920, 115),
    )
    portrait_score = _lightning_button_like_score(
        image,
        center=(990, 205),
        size=(160, 160),
    )
    windows_map_score = _lightning_button_like_score(
        image,
        center=(560, 260),
        size=(500, 80),
    )
    windows_compact_card_score = _lightning_button_like_score(
        image,
        center=(700, 392),
        size=(380, 150),
    )
    portrait_min_score = 0.15 if os.name != "nt" else 0.24
    visible = (
        score.get("score", 0.0) >= 0.20
        and score.get("bright", 0) >= 3500
        and score.get("border", 0) >= 1500
        and portrait_score.get("score", 0.0) >= portrait_min_score
        and portrait_score.get("border", 0) >= 800
    )
    if os.name == "nt" and not visible:
        visible = (
            windows_map_score.get("score", 0.0) >= 0.16
            and windows_map_score.get("bright", 0) >= 700
            and windows_map_score.get("border", 0) >= 1500
            and (
                windows_compact_card_score.get("score", 0.0) >= 0.20
                or portrait_score.get("border", 0) >= 250
            )
        )
    return {
        "status": "OK",
        "visible": visible,
        "portrait_score": portrait_score,
        "windows_map_score": windows_map_score,
        "windows_compact_card_score": windows_compact_card_score,
        **score,
    }


def _lightning_click_visible_start_mission(
    *,
    dry_run: bool = False,
    dismiss_dialogue: bool = False,
) -> dict:
    """Click detected Start Mission text after optional dialogue dismissal."""
    from src.capture.window import take_screenshot
    from src.control.mac_click import click_known_window_control, click_window_point

    dialogue_click = None
    tmp_path = Path(tempfile.gettempdir()) / f"itb_lightning_start_{os.getpid()}.png"
    reuse_screenshot = False
    try:
        take_screenshot(tmp_path)
    except Exception as exc:
        return {"status": "ERROR", "error": f"screenshot failed: {exc}"}
    corp_info_panel = _lightning_first_island_corp_info_panel_evidence_from_image(
        tmp_path,
    )
    if corp_info_panel is not None:
        return {
            "status": "BLOCKED",
            "reason": "first_island_corp_info_panel_visible_before_start",
            "corp_info_panel_evidence": corp_info_panel,
            "screenshot_path": str(tmp_path),
            "next_step": (
                "The first-island corporation info panel is still visible. "
                "Confirm the requested island before attempting route start."
            ),
        }
    dialogue_probe = _lightning_dialogue_box_score(tmp_path)
    should_dismiss_dialogue = bool(
        dialogue_probe.get("visible") and (dismiss_dialogue or not dry_run)
    )
    if should_dismiss_dialogue:
        dialogue_clicks = []
        dismiss_steps = _lightning_dialogue_dismiss_control_steps()[:1]
        for index, step in enumerate(dismiss_steps):
            if step.get("kind") == "ui_key":
                click = _lightning_press_ui_key(
                    str(step["key"]),
                    description=str(
                        step.get("description")
                        or "Dismiss mission preview dialogue",
                    ),
                    dry_run=dry_run,
                    settle_seconds=float(step["settle_seconds"]),
                )
            else:
                click = click_known_window_control(
                    step["control"],
                    dry_run=dry_run,
                    settle_seconds=step["settle_seconds"],
                    hold_seconds=step["hold_seconds"],
                )
            click["dialogue_probe"] = dialogue_probe
            click["dialogue_click_index"] = index
            dialogue_clicks.append(click)
            if click.get("status") not in {"OK", "DRY_RUN"}:
                return {
                    "status": "ERROR",
                    "reason": "dialogue_dismiss_failed",
                    "dialogue_probe": dialogue_probe,
                    "dialogue_click": click,
                    "dialogue_clicks": dialogue_clicks,
                }
        dialogue_click = dict(dialogue_clicks[-1])
        dialogue_click["dialogue_clicks"] = [dict(item) for item in dialogue_clicks]
    else:
        dialogue_click = {
            "status": "SKIPPED",
            "reason": "dialogue_not_visible",
            "dialogue_probe": dialogue_probe,
        }
        reuse_screenshot = True
    if dry_run and dismiss_dialogue:
        return {
            "status": "DRY_RUN",
            "planned_control": (
                _lightning_dialogue_dismiss_control_steps()[0].get("control")
                or _lightning_dialogue_dismiss_control_steps()[0].get("key")
                if dialogue_probe.get("visible")
                else "skip_mission_preview_dialogue"
            ),
            "planned_dialogue_clicks": (
                1
                if dialogue_probe.get("visible")
                else 0
            ),
            "dialogue_probe": dialogue_probe,
            "next_step": (
                "Dry-run only evaluated the dialogue dismissal plan; rerun "
                "without --dry-run to detect and click Start Mission."
            ),
        }

    if not reuse_screenshot:
        try:
            take_screenshot(tmp_path)
        except Exception as exc:
            return {"status": "ERROR", "error": f"screenshot failed: {exc}"}
    corp_info_panel = _lightning_first_island_corp_info_panel_evidence_from_image(
        tmp_path,
    )
    if corp_info_panel is not None:
        result = {
            "status": "BLOCKED",
            "reason": "first_island_corp_info_panel_visible_before_start",
            "corp_info_panel_evidence": corp_info_panel,
            "screenshot_path": str(tmp_path),
            "next_step": (
                "The first-island corporation info panel is still visible. "
                "Confirm the requested island before attempting route start."
            ),
        }
        if dialogue_click is not None:
            result["dialogue_click"] = dialogue_click
        return result
    target = _lightning_start_mission_target(tmp_path)
    target["screenshot_path"] = str(tmp_path)
    if target.get("status") != "OK":
        result = {
            "status": target.get("status", "ERROR"),
            "reason": "start_mission_text_not_found",
            "target": target,
        }
        if dialogue_click is not None:
            result["dialogue_click"] = dialogue_click
        return result

    click_result = click_window_point(
        int(target["window_x"]),
        int(target["window_y"]),
        description="Detected Start Mission",
        dry_run=dry_run,
        settle_seconds=0.8,
    )
    result = {
        "status": click_result.get("status", "ERROR"),
        "target": target,
        "click_result": click_result,
    }
    if dialogue_click is not None:
        result["dialogue_click"] = dialogue_click
    return result


def _lightning_dismiss_visible_dialogue(*, dry_run: bool = False) -> dict:
    """Dismiss a visible advisor dialogue box without clicking Start Mission."""
    from src.capture.window import take_screenshot
    from src.control.mac_click import click_known_window_control

    tmp_path = Path(tempfile.gettempdir()) / f"itb_lightning_dialogue_{os.getpid()}.png"
    try:
        take_screenshot(tmp_path)
    except Exception as exc:
        return {"status": "ERROR", "error": f"screenshot failed: {exc}"}
    dialogue_probe = _lightning_dialogue_box_score(tmp_path)
    if not dialogue_probe.get("visible"):
        return {
            "status": "NO_ACTION",
            "reason": "dialogue_not_visible",
            "dialogue_probe": dialogue_probe,
            "screenshot_path": str(tmp_path),
        }
    dialogue_clicks = []
    dialogue_click = None
    for index, step in enumerate(_lightning_dialogue_dismiss_control_steps()):
        if step.get("kind") == "ui_key":
            click = _lightning_press_ui_key(
                str(step["key"]),
                description=str(
                    step.get("description")
                    or "Dismiss mission preview dialogue",
                ),
                dry_run=dry_run,
                settle_seconds=float(step["settle_seconds"]),
            )
        else:
            click = click_known_window_control(
                step["control"],
                dry_run=dry_run,
                settle_seconds=step["settle_seconds"],
                hold_seconds=step["hold_seconds"],
            )
        click["dialogue_click_index"] = index
        dialogue_clicks.append(click)
        dialogue_click = click
        if click.get("status") not in {"OK", "DRY_RUN"}:
            break
    result = {
        "status": (dialogue_click or {}).get("status", "ERROR"),
        "dialogue_probe": dialogue_probe,
        "dialogue_click": dialogue_click,
        "dialogue_clicks": dialogue_clicks,
        "screenshot_path": str(tmp_path),
    }
    if (dialogue_click or {}).get("status") not in {"OK", "DRY_RUN"}:
        result["reason"] = "dialogue_dismiss_failed"
    return result


def _lightning_click_atomic_visible_start_mission(
    *,
    profile: str,
    route_routing: str,
    expected_preview_mission: str,
    trusted_visible_preview_ocr: dict | None = None,
    region_window_x: int | None = None,
    region_window_y: int | None = None,
    allow_unverified_preview_start: bool = False,
) -> dict:
    """Click only visible Start Mission text, re-proving after dialogue clears."""
    initial_start = _lightning_click_visible_start_mission(
        dry_run=False,
        dismiss_dialogue=False,
    )
    if initial_start.get("status") == "OK":
        return {
            **initial_start,
            "reason": "lightning_war_visible_start_clicked",
            "atomic_start_text_only": True,
        }

    dialogue_dismiss = _lightning_dismiss_visible_dialogue(dry_run=False)
    if dialogue_dismiss.get("status") == "NO_ACTION":
        trusted_ocr_authorized = _lightning_visible_preview_ocr_start_authorized(
            trusted_visible_preview_ocr,
            expected_preview_mission,
            routing=route_routing,
        )
        if (
            trusted_ocr_authorized
            and region_window_x is not None
            and region_window_y is not None
        ):
            region_retry = _lightning_execute_route_start_sequence(
                [
                    {
                        "kind": "point",
                        "window_x": int(region_window_x),
                        "window_y": int(region_window_y),
                        "description": (
                            "Lightning trusted OCR region reopen before start"
                        ),
                        "settle_seconds": 0.25,
                        "hold_seconds": 0.10,
                    }
                ],
                dry_run=False,
            )
            retry_start = None
            if region_retry.get("status") == "OK":
                retry_start = _lightning_click_visible_start_mission(
                    dry_run=False,
                    dismiss_dialogue=True,
                )
                if retry_start.get("status") == "OK":
                    return {
                        **retry_start,
                        "reason": "trusted_ocr_region_reopen_start_clicked",
                        "initial_visible_start": initial_start,
                        "dialogue_dismiss": dialogue_dismiss,
                        "trusted_region_retry": region_retry,
                        "atomic_start_text_only": True,
                    }
            return {
                "status": "BLOCKED",
                "reason": (
                    (retry_start or {}).get("reason")
                    or region_retry.get("reason")
                    or "trusted_ocr_region_reopen_start_failed"
                ),
                "start_result": initial_start,
                "dialogue_dismiss": dialogue_dismiss,
                "trusted_region_retry": region_retry,
                "trusted_region_retry_start": retry_start,
                "atomic_start_text_only": True,
            }
        return {
            "status": "BLOCKED",
            "reason": "route_preview_start_text_missing_before_start",
            "start_result": initial_start,
            "dialogue_dismiss": dialogue_dismiss,
            "atomic_start_text_only": True,
        }
    if dialogue_dismiss.get("status") != "OK":
        return {
            "status": "BLOCKED",
            "reason": dialogue_dismiss.get(
                "reason",
                "dialogue_dismiss_failed_before_start",
            ),
            "initial_visible_start": initial_start,
            "dialogue_dismiss": dialogue_dismiss,
            "atomic_start_text_only": True,
        }

    trusted_ocr_authorized = _lightning_visible_preview_ocr_start_authorized(
        trusted_visible_preview_ocr,
        expected_preview_mission,
        routing=route_routing,
    )
    if trusted_ocr_authorized:
        post_dialogue_actual_mission = str(expected_preview_mission or "").strip()
        post_dialogue_recommendation = {
            "status": "OK",
            "source": "visible_preview_ocr",
            "visible_preview_ocr": trusted_visible_preview_ocr,
            "visible_preview_ocr_start_authorized": True,
            "post_dialogue_recommendation_skipped": (
                "trusted_visible_preview_ocr"
            ),
            "top3": [{"mission_id": post_dialogue_actual_mission}],
        }
    else:
        post_dialogue_recommendation = cmd_recommend_mission(
            profile=profile,
            routing=route_routing,
            use_save_region_filter=False,
            pause_map_peek=False,
        )
        post_top3 = post_dialogue_recommendation.get("top3")
        post_dialogue_actual_mission = None
        if isinstance(post_top3, list) and post_top3 and isinstance(post_top3[0], dict):
            post_dialogue_actual_mission = str(
                post_top3[0].get("mission_id") or "",
            ).strip()
    post_dialogue_bridge_stale = _lightning_bridge_preview_recommendation_stale(
        post_dialogue_recommendation,
    )
    post_dialogue_verified = _lightning_route_preview_source_verified(
        post_dialogue_recommendation,
        post_dialogue_actual_mission,
        routing=route_routing,
    )
    post_dialogue_unverified = (
        not post_dialogue_verified or not post_dialogue_actual_mission
    )
    expected_unverified_start_authorized = (
        allow_unverified_preview_start
        and bool(expected_preview_mission)
        and not post_dialogue_bridge_stale
        and (
            not post_dialogue_actual_mission
            or post_dialogue_actual_mission == expected_preview_mission
        )
    )
    if post_dialogue_unverified and expected_unverified_start_authorized:
        post_dialogue_actual_mission = str(expected_preview_mission or "").strip()
        if isinstance(post_dialogue_recommendation, dict):
            post_dialogue_recommendation = {
                **post_dialogue_recommendation,
                "expected_unverified_preview_start_authorized": True,
            }
    if post_dialogue_unverified and not expected_unverified_start_authorized:
        return {
            "status": "BLOCKED",
            "reason": (
                "route_preview_bridge_stale_after_dialogue"
                if post_dialogue_bridge_stale
                else "route_preview_mission_unverified_after_dialogue"
            ),
            "expected_route_mission_id": expected_preview_mission or None,
            "actual_preview_mission_id": post_dialogue_actual_mission or None,
            "initial_visible_start": initial_start,
            "dialogue_dismiss": dialogue_dismiss,
            "post_dialogue_recommendation": post_dialogue_recommendation,
            "post_dialogue_actual_mission_id": post_dialogue_actual_mission,
            "atomic_start_text_only": True,
        }
    if expected_preview_mission and post_dialogue_actual_mission != expected_preview_mission:
        return {
            "status": "BLOCKED",
            "reason": "route_preview_mission_mismatch_after_dialogue",
            "expected_route_mission_id": expected_preview_mission,
            "actual_preview_mission_id": post_dialogue_actual_mission,
            "initial_visible_start": initial_start,
            "dialogue_dismiss": dialogue_dismiss,
            "post_dialogue_recommendation": post_dialogue_recommendation,
            "post_dialogue_actual_mission_id": post_dialogue_actual_mission,
            "atomic_start_text_only": True,
        }

    trusted_compact_after_dialogue = None
    if trusted_ocr_authorized:
        trusted_post_dialogue_visible_ui = _lightning_visible_ui_snapshot()
        if _lightning_visible_ui_is_pause_menu(trusted_post_dialogue_visible_ui):
            trusted_paused_preview_commit = (
                _lightning_click_paused_preview_start_sequence(
                    start_clicks=1,
                    pause_after_start=True,
                )
            )
            if trusted_paused_preview_commit.get("status") == "OK":
                return {
                    "status": "OK",
                    "reason": (
                        "trusted_ocr_paused_preview_board_clicked_after_dialogue"
                    ),
                    "initial_visible_start": initial_start,
                    "dialogue_dismiss": dialogue_dismiss,
                    "post_dialogue_recommendation": post_dialogue_recommendation,
                    "post_dialogue_actual_mission_id": post_dialogue_actual_mission,
                    "trusted_post_dialogue_visible_ui": (
                        trusted_post_dialogue_visible_ui
                    ),
                    "trusted_paused_preview_commit": trusted_paused_preview_commit,
                    "atomic_start_text_only": True,
                }
        trusted_compact_after_dialogue = (
            _lightning_try_compact_preview_start_after_missing_text(
                region_window_x=region_window_x,
                region_window_y=region_window_y,
                post_start_visible_ui=trusted_post_dialogue_visible_ui,
            )
        )
        if trusted_compact_after_dialogue.get("started"):
            return {
                "status": "OK",
                "reason": "trusted_ocr_compact_preview_clicked_after_dialogue",
                "initial_visible_start": initial_start,
                "dialogue_dismiss": dialogue_dismiss,
                "post_dialogue_recommendation": post_dialogue_recommendation,
                "post_dialogue_actual_mission_id": post_dialogue_actual_mission,
                "trusted_post_dialogue_visible_ui": trusted_post_dialogue_visible_ui,
                "trusted_compact_after_dialogue": trusted_compact_after_dialogue,
                "atomic_start_text_only": True,
            }

    post_dialogue_start = {}
    post_dialogue_start_attempts = []
    for attempt_index in range(2):
        if attempt_index > 0:
            time.sleep(0.25)
        post_dialogue_start = _lightning_click_visible_start_mission(
            dry_run=False,
            dismiss_dialogue=False,
        )
        post_dialogue_start_attempts.append(post_dialogue_start)
        if post_dialogue_start.get("status") == "OK":
            break
    if post_dialogue_start.get("status") != "OK":
        board_after_dialogue = None
        board_after_dialogue_snapshot = None
        board_after_dialogue_visible_ui = None
        board_after_dialogue_pause = None
        compact_after_dialogue = None
        if (
            post_dialogue_start.get("reason") == "start_mission_text_not_found"
            and post_dialogue_actual_mission == expected_preview_mission
        ):
            board_after_dialogue_visible_ui = _lightning_visible_ui_snapshot()
            paused_board_after_dialogue = None
            if _lightning_visible_ui_is_pause_menu(board_after_dialogue_visible_ui):
                paused_board_after_dialogue = (
                    _lightning_click_paused_preview_start_sequence(
                        start_clicks=1,
                        pause_after_start=True,
                    )
                )
                board_after_dialogue = paused_board_after_dialogue
                if paused_board_after_dialogue.get("status") == "OK":
                    board_after_dialogue_snapshot = (
                        paused_board_after_dialogue.get("post_commit_guard") or {}
                    ).get("post_commit_visible_ui")
                    return {
                        "status": "OK",
                        "reason": (
                            "paused_preview_board_clicked_after_dialogue_"
                            "missing_text"
                        ),
                        "initial_visible_start": initial_start,
                        "dialogue_dismiss": dialogue_dismiss,
                        "post_dialogue_start_attempts": (
                            post_dialogue_start_attempts
                        ),
                        "post_dialogue_recommendation": (
                            post_dialogue_recommendation
                        ),
                        "post_dialogue_actual_mission_id": (
                            post_dialogue_actual_mission
                        ),
                        "board_after_dialogue": board_after_dialogue,
                        "board_after_dialogue_snapshot": (
                            board_after_dialogue_snapshot
                        ),
                        "board_after_dialogue_visible_ui": (
                            board_after_dialogue_visible_ui
                        ),
                        "paused_board_after_dialogue": (
                            paused_board_after_dialogue
                        ),
                        "atomic_start_text_only": True,
                    }
                board_after_dialogue_snapshot = _lightning_live_snapshot()
            else:
                board_after_dialogue = _lightning_execute_route_start_sequence(
                    [
                        {
                            "kind": "control",
                            "control": "mission_preview_board",
                            "settle_seconds": 0.8,
                            "hold_seconds": 0.06,
                        }
                    ],
                    dry_run=False,
                )
            if board_after_dialogue.get("status") == "OK":
                board_after_dialogue_snapshot = _lightning_live_snapshot()
                board_after_dialogue_verified = (
                    _lightning_route_start_snapshot_proves_started(
                        board_after_dialogue_snapshot,
                    )
                )
                if not board_after_dialogue_verified:
                    board_after_dialogue_visible_ui = _lightning_visible_ui_snapshot()
                    board_after_dialogue_verified = (
                        _lightning_visible_ui_proves_deployment(
                            board_after_dialogue_visible_ui,
                        )
                    )
                if board_after_dialogue_verified:
                    return {
                        "status": "OK",
                        "reason": (
                            "verified_preview_board_clicked_after_dialogue_"
                            "missing_text"
                        ),
                        "initial_visible_start": initial_start,
                        "dialogue_dismiss": dialogue_dismiss,
                        "post_dialogue_start_attempts": post_dialogue_start_attempts,
                        "post_dialogue_recommendation": (
                            post_dialogue_recommendation
                        ),
                        "post_dialogue_actual_mission_id": (
                            post_dialogue_actual_mission
                        ),
                        "board_after_dialogue": board_after_dialogue,
                        "board_after_dialogue_snapshot": (
                            board_after_dialogue_snapshot
                        ),
                        "board_after_dialogue_visible_ui": (
                            board_after_dialogue_visible_ui
                        ),
                        "atomic_start_text_only": True,
                    }
            compact_after_dialogue = (
                _lightning_try_compact_preview_start_after_missing_text(
                    region_window_x=region_window_x,
                    region_window_y=region_window_y,
                    post_start_visible_ui=board_after_dialogue_visible_ui,
                )
            )
            if compact_after_dialogue.get("started"):
                return {
                    "status": "OK",
                    "reason": (
                        "compact_preview_clicked_after_dialogue_missing_text"
                    ),
                    "initial_visible_start": initial_start,
                    "dialogue_dismiss": dialogue_dismiss,
                    "post_dialogue_start_attempts": post_dialogue_start_attempts,
                    "post_dialogue_recommendation": post_dialogue_recommendation,
                    "post_dialogue_actual_mission_id": (
                        post_dialogue_actual_mission
                    ),
                    "board_after_dialogue": board_after_dialogue,
                    "board_after_dialogue_snapshot": board_after_dialogue_snapshot,
                    "board_after_dialogue_visible_ui": (
                        board_after_dialogue_visible_ui
                    ),
                    "compact_after_dialogue": compact_after_dialogue,
                    "atomic_start_text_only": True,
                }
        sticky_retry = None
        if (
            post_dialogue_start.get("reason") == "start_mission_text_not_found"
            and post_dialogue_actual_mission == expected_preview_mission
            and region_window_x is not None
            and region_window_y is not None
        ):
            sticky_retry = _lightning_execute_route_start_sequence(
                [
                    {
                        "kind": "point",
                        "window_x": int(region_window_x),
                        "window_y": int(region_window_y),
                        "description": (
                            "Lightning route region after sticky dialogue"
                        ),
                        "settle_seconds": 0.35,
                        "hold_seconds": 0.30,
                    }
                ],
                dry_run=False,
            )
            retry_recommendation = None
            retry_actual_mission = None
            retry_start = None
            if sticky_retry.get("status") == "OK":
                retry_recommendation = cmd_recommend_mission(
                    profile=profile,
                    routing=route_routing,
                    use_save_region_filter=False,
                    pause_map_peek=False,
                )
                retry_top3 = retry_recommendation.get("top3")
                if (
                    isinstance(retry_top3, list)
                    and retry_top3
                    and isinstance(retry_top3[0], dict)
                ):
                    retry_actual_mission = str(
                        retry_top3[0].get("mission_id") or "",
                    ).strip()
                if (
                    not _lightning_route_preview_source_verified(
                        retry_recommendation,
                        retry_actual_mission,
                        routing=route_routing,
                    )
                    or not retry_actual_mission
                ):
                    sticky_retry = {
                        **sticky_retry,
                        "status": "BLOCKED",
                        "reason": (
                            "route_preview_bridge_stale_after_sticky_dialogue_retry"
                            if _lightning_bridge_preview_recommendation_stale(
                                retry_recommendation,
                            )
                            else (
                                "route_preview_mission_unverified_after_"
                                "sticky_dialogue_retry"
                            )
                        ),
                    }
                elif retry_actual_mission != expected_preview_mission:
                    sticky_retry = {
                        **sticky_retry,
                        "status": "BLOCKED",
                        "reason": (
                            "route_preview_mission_mismatch_after_"
                            "sticky_dialogue_retry"
                        ),
                    }
                else:
                    retry_start = _lightning_click_visible_start_mission(
                        dry_run=False,
                        dismiss_dialogue=True,
                    )
                    sticky_retry = {
                        **sticky_retry,
                        "status": retry_start.get("status", "ERROR"),
                        "reason": (
                            "sticky_dialogue_region_reopened_start_clicked"
                            if retry_start.get("status") == "OK"
                            else retry_start.get(
                                "reason",
                                "sticky_dialogue_retry_start_failed",
                            )
                        ),
                        "start_click": retry_start,
                    }
            sticky_retry["retry_recommendation"] = retry_recommendation
            sticky_retry["retry_actual_mission_id"] = retry_actual_mission
            if sticky_retry.get("status") == "OK":
                return {
                    **retry_start,
                    "reason": "sticky_dialogue_region_reopened_start_clicked",
                    "initial_visible_start": initial_start,
                    "dialogue_dismiss": dialogue_dismiss,
                    "post_dialogue_start_attempts": post_dialogue_start_attempts,
                    "post_dialogue_recommendation": post_dialogue_recommendation,
                    "post_dialogue_actual_mission_id": post_dialogue_actual_mission,
                    "sticky_dialogue_retry": sticky_retry,
                    "atomic_start_text_only": True,
                }
        board_after_dialogue_pause = _lightning_ensure_pause_state(
            reason="verified_preview_board_no_transition_after_dialogue",
        )
        return {
            "status": "BLOCKED",
            "reason": "route_preview_start_text_missing_after_dialogue",
            "start_result": post_dialogue_start,
            "post_dialogue_start_attempts": post_dialogue_start_attempts,
            "initial_visible_start": initial_start,
            "dialogue_dismiss": dialogue_dismiss,
            "post_dialogue_recommendation": post_dialogue_recommendation,
            "post_dialogue_actual_mission_id": post_dialogue_actual_mission,
            "board_after_dialogue": board_after_dialogue,
            "board_after_dialogue_snapshot": board_after_dialogue_snapshot,
            "board_after_dialogue_visible_ui": board_after_dialogue_visible_ui,
            "compact_after_dialogue": compact_after_dialogue,
            "board_after_dialogue_pause": board_after_dialogue_pause,
            "sticky_dialogue_retry": sticky_retry,
            "atomic_start_text_only": True,
        }
    return {
        **post_dialogue_start,
        "reason": "lightning_war_dialogue_dismissed_visible_start_clicked",
        "initial_visible_start": initial_start,
        "dialogue_dismiss": dialogue_dismiss,
        "post_dialogue_start_attempts": post_dialogue_start_attempts,
            "post_dialogue_recommendation": post_dialogue_recommendation,
            "post_dialogue_actual_mission_id": post_dialogue_actual_mission,
            "trusted_compact_after_dialogue": trusted_compact_after_dialogue,
            "atomic_start_text_only": True,
        }


def _lightning_try_compact_preview_start_after_missing_text(
    *,
    region_window_x: int | None,
    region_window_y: int | None,
    post_start_visible_ui: dict | None,
) -> dict:
    """Try compact-preview commit points after verified textless preview proof."""
    attempts: list[dict] = []
    current_visible_ui = post_start_visible_ui
    builders = [
        (
            "compact_preview_region_point",
            lambda visible: _lightning_compact_preview_region_point_commit_sequence(
                region_window_x=region_window_x,
                region_window_y=region_window_y,
                post_start_visible_ui=visible,
            ),
        ),
        (
            "compact_preview_side_card",
            lambda visible: _lightning_compact_preview_side_card_commit_sequence(
                post_start_visible_ui=visible,
            ),
        ),
    ]
    for retry_kind, builder in builders:
        sequence = builder(current_visible_ui)
        if not sequence:
            attempts.append({
                "status": "SKIPPED",
                "retry_kind": retry_kind,
                "reason": "compact_preview_sequence_unavailable",
                "visible_ui": current_visible_ui,
            })
            continue
        attempt = _lightning_execute_route_start_sequence(sequence, dry_run=False)
        attempt["retry_kind"] = retry_kind
        attempt["sequence"] = sequence
        if attempt.get("status") == "OK":
            snapshot = _lightning_live_snapshot()
            attempt["post_start_snapshot"] = snapshot
            started = _lightning_route_start_snapshot_proves_started(snapshot)
            post_visible = None
            if not started:
                post_visible = _lightning_visible_ui_snapshot()
                attempt["post_start_visible_ui"] = post_visible
                started = _lightning_visible_ui_proves_deployment(post_visible)
                current_visible_ui = post_visible
            attempt["started"] = started
            attempts.append(attempt)
            if started:
                return {
                    "status": "OK",
                    "reason": "compact_preview_start_verified",
                    "retry_kind": retry_kind,
                    "started": True,
                    "attempts": attempts,
                }
        else:
            attempt["started"] = False
            attempts.append(attempt)
    return {
        "status": "BLOCKED",
        "reason": "compact_preview_start_not_verified",
        "started": False,
        "attempts": attempts,
    }


def _lightning_retry_verified_preview_no_transition(
    *,
    route_routing: str,
    expected_preview_mission: str,
    actual_preview_mission: str,
    visible_preview_ocr: dict | None,
    region_window_x: int | None,
    region_window_y: int | None,
    post_start_visible_ui: dict | None,
) -> dict:
    """Retry a proven preview commit before declaring Start Mission inert."""
    attempts: list[dict] = []
    if (
        not expected_preview_mission
        or not actual_preview_mission
        or not _lightning_route_mission_ids_match(
            expected_preview_mission,
            actual_preview_mission,
        )
        or not _lightning_visible_preview_ocr_start_authorized(
            visible_preview_ocr,
            actual_preview_mission,
            routing=route_routing,
        )
    ):
        return {
            "status": "SKIPPED",
            "reason": "verified_preview_retry_not_authorized",
            "expected_route_mission_id": expected_preview_mission or None,
            "actual_preview_mission_id": actual_preview_mission or None,
        }

    current_visible_ui = post_start_visible_ui
    if not _lightning_visible_ui_has_preview_commit_context(current_visible_ui):
        current_visible_ui = _lightning_visible_ui_snapshot()
    if not _lightning_visible_ui_has_preview_commit_context(current_visible_ui):
        return {
            "status": "SKIPPED",
            "reason": "verified_preview_retry_no_preview_context",
            "visible_ui": current_visible_ui,
        }

    visible_start = _lightning_click_visible_start_mission(
        dry_run=False,
        dismiss_dialogue=True,
    )
    attempts.append({
        "retry_kind": "current_visible_start_text",
        "result": visible_start,
    })
    if visible_start.get("status") == "OK":
        start_snapshot = _lightning_live_snapshot()
        start_visible_ui = None
        started = _lightning_route_start_snapshot_proves_started(start_snapshot)
        if not started:
            start_visible_ui = _lightning_visible_ui_snapshot()
            started = _lightning_visible_ui_proves_deployment(start_visible_ui)
        attempts[-1]["post_start_snapshot"] = start_snapshot
        if start_visible_ui is not None:
            attempts[-1]["post_start_visible_ui"] = start_visible_ui
        attempts[-1]["started"] = started
        if started:
            return {
                "status": "OK",
                "reason": "verified_preview_current_visible_start_clicked",
                "attempts": attempts,
                "post_start_snapshot": start_snapshot,
                "post_start_visible_ui": start_visible_ui,
            }
        current_visible_ui = start_visible_ui

    compact_retry = _lightning_try_compact_preview_start_after_missing_text(
        region_window_x=region_window_x,
        region_window_y=region_window_y,
        post_start_visible_ui=current_visible_ui,
    )
    attempts.append({
        "retry_kind": "compact_preview_commit",
        "result": compact_retry,
    })
    if compact_retry.get("started"):
        return {
            "status": "OK",
            "reason": "verified_preview_compact_commit_clicked",
            "attempts": attempts,
            "compact_retry": compact_retry,
        }

    if (
        region_window_x is not None
        and region_window_y is not None
        and _lightning_visible_ui_has_preview_commit_context(current_visible_ui)
    ):
        reveal_sequence = [
            {
                "kind": "point",
                "window_x": int(region_window_x),
                "window_y": int(region_window_y),
                "description": "Lightning verified preview region reselect",
                "settle_seconds": 0.12,
                "hold_seconds": 0.05,
                "source": "verified_preview_no_transition_reselect",
            },
            {
                "kind": "point",
                "window_x": _LIGHTNING_OPENING_PREVIEW_REVEAL_WINDOW_X,
                "window_y": _LIGHTNING_OPENING_PREVIEW_REVEAL_WINDOW_Y,
                "description": "Lightning verified preview reveal",
                "settle_seconds": 0.12,
                "hold_seconds": 0.05,
                "source": "verified_preview_no_transition_reveal",
            },
            {
                "kind": "point",
                "window_x": _LIGHTNING_OPENING_PREVIEW_COMMIT_WINDOW_X,
                "window_y": _LIGHTNING_OPENING_PREVIEW_COMMIT_WINDOW_Y,
                "description": "Lightning verified preview Start Mission",
                "settle_seconds": 0.35,
                "hold_seconds": 0.05,
                "source": "verified_preview_no_transition_commit",
            },
        ]
        reveal_retry = _lightning_execute_route_start_sequence(
            reveal_sequence,
            dry_run=False,
        )
        reveal_retry["sequence"] = reveal_sequence
        attempts.append({
            "retry_kind": "verified_preview_reveal_commit",
            "result": reveal_retry,
        })
        if reveal_retry.get("status") == "OK":
            reveal_snapshot = _lightning_live_snapshot()
            reveal_visible_ui = None
            started = _lightning_route_start_snapshot_proves_started(
                reveal_snapshot,
            )
            if not started:
                reveal_visible_ui = _lightning_visible_ui_snapshot()
                started = _lightning_visible_ui_proves_deployment(
                    reveal_visible_ui,
                )
            attempts[-1]["post_start_snapshot"] = reveal_snapshot
            if reveal_visible_ui is not None:
                attempts[-1]["post_start_visible_ui"] = reveal_visible_ui
            attempts[-1]["started"] = started
            if started:
                return {
                    "status": "OK",
                    "reason": "verified_preview_reveal_commit_clicked",
                    "attempts": attempts,
                    "post_start_snapshot": reveal_snapshot,
                    "post_start_visible_ui": reveal_visible_ui,
                }

    return {
        "status": "BLOCKED",
        "reason": "verified_preview_no_transition_retry_failed",
        "attempts": attempts,
        "visible_ui": current_visible_ui,
    }


def _lightning_dialogue_dismiss_control_steps() -> list[dict]:
    """Return trusted dialogue textbox clicks for dismissing advisor prompts."""
    if os.name == "nt":
        return [
            {
                "kind": "control",
                "control": "mission_preview_dialogue",
                "settle_seconds": 0.20,
                "hold_seconds": 0.18,
                "pre_click_seconds": 0.0,
            },
            {
                "kind": "control",
                "control": "mission_preview_dialogue",
                "settle_seconds": 0.55,
                "hold_seconds": 0.18,
                "pre_click_seconds": 0.0,
            },
        ]
    return [
        {
            "kind": "control",
            "control": "mission_preview_dialogue",
            "settle_seconds": 0.18,
            "hold_seconds": 0.06,
        },
        {
            "kind": "control",
            "control": "top_advisor_dialogue",
            "settle_seconds": 0.10,
            "hold_seconds": 0.05,
        },
        {
            "kind": "control",
            "control": "mission_preview_dialogue",
            "settle_seconds": 0.12,
            "hold_seconds": 0.05,
        },
        {
            "kind": "ui_key",
            "key": "space",
            "description": "Dismiss mission preview dialogue with Space",
            "settle_seconds": 0.08,
        },
        {
            "kind": "ui_key",
            "key": "enter",
            "description": "Dismiss mission preview dialogue with Enter",
            "settle_seconds": 0.08,
        },
    ]


def _lightning_click_paused_preview_start_sequence(
    *,
    dry_run: bool = False,
    dismiss_dialogue: bool = False,
    start_clicks: int = 1,
    pause_after_start: bool = True,
) -> dict:
    """Resume from pause and click the visible mission preview board."""
    from src.control.mac_click import _get_window_bounds

    clicks = max(1, int(start_clicks or 1))
    if os.name == "nt":
        sequence = [
            {
                "kind": "control",
                "control": "menu_continue",
                "settle_seconds": 0.6,
                "hold_seconds": 0.30,
            }
        ]
    else:
        sequence = [
            {
                "kind": "key",
                "key": "esc",
                "description": "Pause menu Escape resume",
                "settle_seconds": 0.18,
            }
        ]
    if dismiss_dialogue:
        sequence.extend(_lightning_dialogue_dismiss_control_steps())
    for index in range(clicks):
        sequence.append(
            {
                "kind": "control",
                "control": "mission_preview_board",
                "settle_seconds": 0.8 if index == clicks - 1 else 0.25,
                "hold_seconds": 0.06,
            }
        )

    if dry_run:
        return {
            "status": "DRY_RUN",
            "sequence": sequence,
            "pause_after_start": bool(pause_after_start),
            "post_commit_guard": (
                "screenshot_then_esc_pause" if pause_after_start else None
            ),
        }

    bounds = _get_window_bounds("Into the Breach")
    if bounds is None:
        return {"status": "ERROR", "error": "could not read app window bounds"}

    steps = []
    for item in sequence:
        if item["kind"] == "key":
            key = str(item.get("key") or "esc")
            if key.strip().lower() in {"esc", "escape"}:
                click = _lightning_press_pause_escape(
                    dry_run=False,
                    settle_seconds=item["settle_seconds"],
                )
            else:
                click = _lightning_press_ui_key(
                    key,
                    description=str(
                        item.get("description") or "Lightning route UI key",
                    ),
                    dry_run=False,
                    settle_seconds=item["settle_seconds"],
                )
        elif item["kind"] == "ui_key":
            click = _lightning_press_ui_key(
                str(item["key"]),
                description=str(
                    item.get("description") or "Lightning preview UI key",
                ),
                dry_run=False,
                settle_seconds=item["settle_seconds"],
            )
        else:
            click = _lightning_click_control_with_bounds(
                item["control"],
                bounds=bounds,
                dry_run=False,
                settle_seconds=item["settle_seconds"],
                hold_seconds=item["hold_seconds"],
            )
        steps.append(click)
        if click.get("status") != "OK":
            return {
                "status": "ERROR",
                "reason": "paused_preview_start_click_failed",
                "failed_step": item,
                "steps": steps,
                "window_bounds": bounds,
            }

    result = {"status": "OK", "steps": steps, "window_bounds": bounds}
    if pause_after_start:
        post_commit_guard = _lightning_post_commit_screenshot_pause_guard(
            reason="paused_preview_start_sequence",
        )
        result["post_commit_guard"] = post_commit_guard
        if post_commit_guard.get("status") != "OK":
            result["status"] = post_commit_guard.get("status", "BLOCKED")
            result["reason"] = post_commit_guard.get(
                "reason",
                "post_commit_pause_guard_failed",
            )
            if post_commit_guard.get("safe_to_think") is False:
                result["safe_to_think"] = False
        elif not post_commit_guard.get("started"):
            result["status"] = "BLOCKED"
            result["reason"] = "paused_preview_commit_no_transition"
    return result


def _lightning_click_live_preview_start_sequence(*, dry_run: bool = False) -> dict:
    """Click the already-visible mission preview board, then immediately pause."""
    from src.control.mac_click import _get_window_bounds

    sequence = [
        {
            "kind": "control",
            "control": "mission_preview_board",
            "settle_seconds": 0.8,
            "hold_seconds": 0.06,
        }
    ]
    if dry_run:
        return {
            "status": "DRY_RUN",
            "sequence": sequence,
            "pause_after_start": True,
            "post_commit_guard": "screenshot_then_esc_pause",
        }

    bounds = _get_window_bounds("Into the Breach")
    if bounds is None:
        return {"status": "ERROR", "error": "could not read app window bounds"}

    steps = []
    for item in sequence:
        click = _lightning_click_control_with_bounds(
            item["control"],
            bounds=bounds,
            dry_run=False,
            settle_seconds=item["settle_seconds"],
            hold_seconds=item["hold_seconds"],
        )
        steps.append(click)
        if click.get("status") != "OK":
            return {
                "status": "ERROR",
                "reason": "live_preview_start_click_failed",
                "failed_step": item,
                "steps": steps,
                "window_bounds": bounds,
            }

    result = {"status": "OK", "steps": steps, "window_bounds": bounds}
    post_commit_guard = _lightning_post_commit_screenshot_pause_guard(
        reason="live_preview_start_sequence",
    )
    result["post_commit_guard"] = post_commit_guard
    if post_commit_guard.get("status") != "OK":
        result["status"] = post_commit_guard.get("status", "BLOCKED")
        result["reason"] = post_commit_guard.get(
            "reason",
            "post_commit_pause_guard_failed",
        )
        if post_commit_guard.get("safe_to_think") is False:
            result["safe_to_think"] = False
    elif not post_commit_guard.get("started"):
        result["status"] = "BLOCKED"
        result["reason"] = "live_preview_commit_no_transition"
    return result


def _lightning_post_commit_screenshot_pause_guard(*, reason: str) -> dict:
    """Capture the live post-click frame, immediately Esc-pause, then classify."""
    from src.capture.window import take_screenshot

    tmp_path = Path(tempfile.gettempdir()) / (
        f"itb_lightning_post_commit_{os.getpid()}.png"
    )
    screenshot_error = None
    try:
        take_screenshot(tmp_path)
    except Exception as exc:
        screenshot_error = f"screenshot failed: {exc}"

    pause_click = _lightning_press_pause_escape(settle_seconds=0.12)
    pause_verify = _lightning_visible_ui_snapshot(include_ocr=True)
    pause_verified = _lightning_visible_ui_is_pause_menu(pause_verify)

    post_commit_visible_ui = None
    started = False
    if screenshot_error is None:
        post_commit_visible_ui = _classify_lightning_ui_image(tmp_path)
        post_commit_visible_ui["screenshot_path"] = str(tmp_path)
        visible_kind = str(post_commit_visible_ui.get("visible_ui") or "")
        started = visible_kind in {"deployment_screen", "combat_screen"}

    result = {
        "status": "OK" if pause_verified else "BLOCKED",
        "reason": (
            "post_commit_pause_verified"
            if pause_verified
            else "pause_not_verified_after_preview_commit"
        ),
        "guard_reason": reason,
        "screenshot_path": str(tmp_path),
        "screenshot_error": screenshot_error,
        "pause_click": pause_click,
        "pause_verify": pause_verify,
        "pause_verified": pause_verified,
        "post_commit_visible_ui": post_commit_visible_ui,
        "started": started,
        "safe_to_think": pause_verified,
    }
    if pause_click.get("status") != "OK":
        result["status"] = "ERROR"
        result["reason"] = "pause_after_preview_commit_failed"
        result["safe_to_think"] = False
    if screenshot_error is not None and pause_verified:
        result["status"] = "BLOCKED"
        result["reason"] = "post_commit_screenshot_failed"
    if pause_verified:
        try:
            session = _load_session()
            result["guard"] = _lightning_write_guard(
                session,
                guard_status="OK",
                reason=reason,
                visible_ui=pause_verify,
                click_result=pause_click,
            )
        except Exception as exc:
            result["guard_error"] = str(exc)
    return result


def _lightning_click_paused_visible_start_mission(
    *,
    dry_run: bool = False,
    dismiss_dialogue: bool = True,
    expected_mission_id: str | None = None,
    route_routing: str = "lightning_war",
    pause_after_start: bool = True,
    allow_expected_preview_start: bool = False,
) -> dict:
    """Resume from pause, verify the preview when requested, then click Start."""
    from src.control.mac_click import click_known_window_control

    planned_resume = "menu_continue" if os.name == "nt" else "pause_menu_escape"
    expected = str(expected_mission_id or "").strip()
    if dry_run:
        return {
            "status": "DRY_RUN",
            "planned_resume": planned_resume,
            "planned_start": "visible_start_mission",
            "dismiss_dialogue": bool(dismiss_dialogue),
            "expected_mission_id": expected or None,
            "pause_after_start": bool(pause_after_start),
            "allow_expected_preview_start": bool(allow_expected_preview_start),
        }

    if os.name == "nt":
        resume_result = click_known_window_control(
            "menu_continue",
            settle_seconds=0.65,
            hold_seconds=0.30,
        )
    else:
        resume_result = _lightning_press_pause_escape(settle_seconds=0.20)
    if resume_result.get("status") != "OK":
        return {
            "status": "ERROR",
            "reason": "resume_from_pause_failed",
            "resume_result": resume_result,
        }

    visible_preview_ocr = None
    if expected:
        visible_preview_ocr = _lightning_visible_preview_mission_ocr()
        actual = str(visible_preview_ocr.get("mission_id") or "").strip()
        authorized = _lightning_visible_preview_ocr_start_authorized(
            visible_preview_ocr,
            expected,
            routing=route_routing,
        )
        manual_expected_authorized = (
            bool(allow_expected_preview_start)
            and actual == expected
            and visible_preview_ocr.get("status") == "OK"
            and visible_preview_ocr.get("source") == "visible_preview_ocr"
        )
        if actual != expected or not (authorized or manual_expected_authorized):
            pause_click = _lightning_press_pause_escape(settle_seconds=0.08)
            pause_verify = _lightning_visible_ui_snapshot(include_ocr=True)
            result = {
                "status": "BLOCKED",
                "reason": "visible_preview_mission_unverified_before_start",
                "expected_mission_id": expected,
                "actual_preview_mission_id": actual or None,
                "visible_preview_ocr": visible_preview_ocr,
                "ocr_start_authorized": authorized,
                "manual_expected_preview_authorized": manual_expected_authorized,
                "resume_result": resume_result,
                "pause_click": pause_click,
                "pause_verify": pause_verify,
                "pause_verified": _lightning_visible_ui_is_pause_menu(
                    pause_verify,
                ),
                "next_step": (
                    "Stay paused. Do not click Start Mission until visible "
                    "preview OCR proves the expected mission and route policy."
                ),
            }
            if not result["pause_verified"]:
                result["safe_to_think"] = False
                result["reason"] = "pause_not_verified_after_preview_block"
            return result

    start_result = _lightning_click_visible_start_mission(
        dry_run=False,
        dismiss_dialogue=dismiss_dialogue,
    )
    result = {
        "status": start_result.get("status", "ERROR"),
        "resume_result": resume_result,
        "start_result": start_result,
    }
    if expected:
        result["expected_mission_id"] = expected
        result["visible_preview_ocr"] = visible_preview_ocr
        result["ocr_start_authorized"] = bool(authorized)
        result["manual_expected_preview_authorized"] = bool(
            allow_expected_preview_start and not authorized
        )
    if start_result.get("status") not in {"OK", "DRY_RUN"}:
        result["reason"] = start_result.get("reason", "visible_start_failed")
    if pause_after_start:
        pause_click = _lightning_press_pause_escape(settle_seconds=0.08)
        pause_verify = _lightning_visible_ui_snapshot(include_ocr=True)
        pause_verified = _lightning_visible_ui_is_pause_menu(pause_verify)
        result["pause_click"] = pause_click
        result["pause_verify"] = pause_verify
        result["pause_verified"] = pause_verified
        if pause_click.get("status") != "OK":
            result["status"] = "ERROR"
            result["reason"] = "pause_after_visible_start_failed"
            result["safe_to_think"] = False
        elif not pause_verified:
            result["status"] = "BLOCKED"
            result["reason"] = "pause_not_verified_after_visible_start"
            result["safe_to_think"] = False
    return result


def _lightning_pause_after_stop(
    result: dict,
    *,
    enabled: bool,
    click_ui: bool,
    dry_run: bool,
    reason: str,
    lightning_speed_loss_policy: bool = False,
) -> dict:
    """Attach a pause guard to a stopped conductor result when requested."""
    if not enabled:
        return result
    if dry_run or not click_ui:
        result["pause_guard"] = {
            "status": "DRY_RUN" if dry_run else "NO_CLICK",
            "planned_control": "pause",
            "reason": reason,
        }
        return result

    result["pause_guard"] = _lightning_timer_pause_guard_once(
        dry_run=False,
        click_ui=True,
        reason=reason,
        bridge_refine_before_pause=False,
        lightning_speed_loss_policy=lightning_speed_loss_policy,
    )
    result["next_step"] = (
        str(result.get("next_step") or "").rstrip()
        + " Check pause_guard before the next timed burst."
    ).strip()
    return result


def _lightning_resume_if_paused(
    *,
    dry_run: bool = False,
    click_ui: bool = True,
    use_verified_guard: bool = False,
    guard_max_age_seconds: float = 30.0,
) -> dict | None:
    """Click Continue when the pause menu is visible and the caller is ready."""
    if use_verified_guard:
        guard = _lightning_recent_verified_pause_guard(
            max_age_seconds=guard_max_age_seconds,
        )
        if guard.get("status") == "OK":
            planned_control = "menu_continue" if os.name == "nt" else "pause_menu_escape"
            result = {
                "status": (
                    "DRY_RUN"
                    if dry_run
                    else "NO_CLICK"
                    if not click_ui
                    else "PLANNED"
                ),
                "reason": "verified_pause_guard_visible",
                "planned_control": planned_control,
                "guard": guard,
                "fast_resume": True,
            }
            if dry_run or not click_ui:
                return result
            result["stale_bridge_cleanup"] = _clear_pending_bridge_command(
                "fast_resume_from_verified_pause_guard"
            )
            if os.name == "nt":
                from src.control.mac_click import _get_window_bounds

                bounds = _get_window_bounds("Into the Breach")
                if bounds is None:
                    result["status"] = "ERROR"
                    result["reason"] = "window_bounds_unavailable"
                    return result
                click_result = _lightning_click_control_with_bounds(
                    "menu_continue",
                    bounds=bounds,
                    settle_seconds=0.08,
                    hold_seconds=0.08,
                )
            else:
                click_result = _lightning_press_pause_escape(settle_seconds=0.04)
            result["status"] = click_result.get("status", "ERROR")
            result["click_result"] = click_result
            if click_result.get("status") != "OK":
                if _lightning_resume_key_failed(result):
                    fallback = _lightning_pause_menu_continue_fallback(
                        settle_seconds=0.12,
                        hold_seconds=0.08,
                    )
                    result["key_resume_failed_fallback"] = fallback
                    result["status"] = fallback.get("status", "ERROR")
                    result["click_result"] = fallback
                    if fallback.get("status") == "OK":
                        click_result = fallback
                        result["reason"] = (
                            "resumed_from_verified_pause_guard_continue_fallback"
                        )
                    else:
                        result["reason"] = "fast_resume_continue_fallback_failed"
                        result["error"] = fallback.get("error")
                        return result
                else:
                    result["reason"] = "fast_resume_click_failed"
                    result["error"] = click_result.get("error")
                    return result
            if click_result.get("status") != "OK" and result.get("status") != "OK":
                result["reason"] = "fast_resume_click_failed"
                result["error"] = click_result.get("error")
                return result
            try:
                result["guard_after_resume"] = _lightning_write_guard(
                    _load_session(),
                    guard_status="LIVE",
                    reason="fast_resume_from_verified_pause_guard",
                    click_result=click_result,
                    metadata={
                        "pause_verified": False,
                        "safe_to_think": False,
                        "timer_stop_verified": False,
                    },
                )
            except Exception as exc:
                result["guard_after_resume"] = {
                    "status": "ERROR",
                    "reason": "guard_invalidate_failed",
                    "error": str(exc),
                }
            result["reason"] = "resumed_from_verified_pause_guard"
            post_click_visible = _lightning_visible_ui_snapshot()
            result["post_click_visible_ui"] = {
                key: post_click_visible.get(key)
                for key in (
                    "status",
                    "visible_ui",
                    "recommended_control",
                    "screenshot_path",
                )
                if key in post_click_visible
            }
            if (
                post_click_visible.get("status") == "OK"
                and _lightning_visible_ui_is_pause_menu(post_click_visible)
            ):
                fallback = _lightning_press_pause_escape(settle_seconds=0.12)
                result["fallback_resume"] = fallback
                result["status"] = fallback.get("status", "ERROR")
                if fallback.get("status") != "OK":
                    result["reason"] = "fast_resume_escape_fallback_failed"
                    result["error"] = fallback.get("error")
                    return result
                fallback_visible = _lightning_visible_ui_snapshot()
                result["fallback_visible_ui"] = {
                    key: fallback_visible.get(key)
                    for key in (
                        "status",
                        "visible_ui",
                        "recommended_control",
                        "screenshot_path",
                    )
                    if key in fallback_visible
                }
                if (
                    fallback_visible.get("status") == "OK"
                    and _lightning_visible_ui_is_pause_menu(fallback_visible)
                ):
                    result["status"] = "BLOCKED"
                    result["reason"] = "fast_resume_from_pause_not_verified"
                    result["next_step"] = (
                        "Pause menu remained visible after the verified-guard "
                        "resume and Escape fallback; recalibrate resume before "
                        "continuing timed play."
                    )
                    return result
                result["reason"] = "resumed_from_verified_pause_guard_fallback"
            return result

    visible_ui = _lightning_visible_ui_snapshot()
    if visible_ui.get("status") != "OK":
        return {
            "status": "SKIPPED",
            "reason": "screen_classification_failed",
            "visible_ui": visible_ui,
        }
    if not (
        _lightning_visible_ui_is_pause_menu(visible_ui)
        or _lightning_visible_ui_has_pause_overlay_shape(visible_ui)
    ):
        return None
    planned_control = "menu_continue" if os.name == "nt" else "pause_menu_escape"
    result = {
        "status": "DRY_RUN" if dry_run else "NO_CLICK" if not click_ui else "PLANNED",
        "reason": "pause_menu_visible",
        "planned_control": planned_control,
        "visible_ui": visible_ui,
    }
    screenshot_path = visible_ui.get("screenshot_path")
    if screenshot_path:
        visible_timer = _lightning_visible_pause_timer_from_screenshot(screenshot_path)
        result["visible_timer"] = visible_timer
        visible_budget = _lightning_game_timer_budget(visible_timer.get("game_seconds"))
        result["visible_timer_budget"] = visible_budget
        if visible_budget.get("game_status") == "EXCEEDED":
            result["status"] = "BLOCKED"
            result["reason"] = "pause_menu_timer_budget_exceeded"
            result["next_step"] = "Start a fresh Lightning War timeline."
            return result
    if dry_run or not click_ui:
        return result

    result["stale_bridge_cleanup"] = _clear_pending_bridge_command(
        "resume_from_pause"
    )
    if os.name == "nt":
        from src.control.mac_click import _get_window_bounds

        bounds = _get_window_bounds("Into the Breach")
        if bounds is None:
            result["status"] = "ERROR"
            result["reason"] = "window_bounds_unavailable"
            return result
        click_result = _lightning_click_control_with_bounds(
            "menu_continue",
            bounds=bounds,
            settle_seconds=0.2,
        )
    else:
        click_result = _lightning_press_pause_escape()
    result["status"] = click_result.get("status", "ERROR")
    result["click_result"] = click_result
    if click_result.get("status") != "OK":
        if _lightning_resume_key_failed(result):
            fallback = _lightning_pause_menu_continue_fallback(
                settle_seconds=0.2,
                hold_seconds=0.08,
            )
            result["key_resume_failed_fallback"] = fallback
            result["status"] = fallback.get("status", "ERROR")
            result["click_result"] = fallback
            if fallback.get("status") == "OK":
                click_result = fallback
                result["reason"] = "resumed_from_pause_continue_fallback"
            else:
                result["reason"] = "resume_continue_fallback_failed"
                result["error"] = fallback.get("error")
                return result
        else:
            result["reason"] = "resume_click_failed"
            result["error"] = click_result.get("error")
            return result

    if result.get("reason") == "pause_menu_visible":
        result["reason"] = "resumed_from_pause"
    post_click_visible = _lightning_visible_ui_snapshot()
    result["post_click_visible_ui"] = {
        key: post_click_visible.get(key)
        for key in (
            "status",
            "visible_ui",
            "recommended_control",
            "screenshot_path",
        )
        if key in post_click_visible
    }
    if post_click_visible.get("status") == "OK":
        post_visible_kind = str(post_click_visible.get("visible_ui") or "")
        post_control = str(post_click_visible.get("recommended_control") or "")
        if (
            post_visible_kind
            and post_visible_kind != "pause_menu"
            and post_control != "menu_continue"
            and (
                post_visible_kind
                in {
                    "island_map",
                    "island_map_or_unknown",
                    "mission_preview_panel",
                    "deployment_screen",
                    "combat_screen",
                }
                or post_control
            )
        ):
            result["reason"] = "resumed_from_pause_visible_ui"
            return result
    if (
        post_click_visible.get("status") == "OK"
        and _lightning_visible_ui_is_pause_menu(post_click_visible)
    ):
        if os.name == "nt":
            retry_click = _lightning_click_control_with_bounds(
                "menu_continue",
                bounds=bounds,
                settle_seconds=0.35,
                hold_seconds=0.45,
            )
            result["retry_click_result"] = retry_click
            result["status"] = retry_click.get("status", "ERROR")
            if retry_click.get("status") != "OK":
                result["reason"] = "resume_retry_click_failed"
                result["error"] = retry_click.get("error")
                return result
            retry_visible = _lightning_visible_ui_snapshot()
            result["retry_visible_ui"] = {
                key: retry_visible.get(key)
                for key in (
                    "status",
                    "visible_ui",
                    "recommended_control",
                    "screenshot_path",
                )
                if key in retry_visible
            }
            if (
                retry_visible.get("status") != "OK"
                or not _lightning_visible_ui_is_pause_menu(retry_visible)
            ):
                result["reason"] = "resumed_from_pause_retry_click"
                return result
        fallback = _lightning_press_pause_escape(settle_seconds=0.2)
        result["fallback_resume"] = fallback
        result["status"] = fallback.get("status", "ERROR")
        if fallback.get("status") != "OK":
            result["reason"] = "resume_escape_fallback_failed"
            result["error"] = fallback.get("error")
            return result
        fallback_visible = _lightning_visible_ui_snapshot()
        result["fallback_visible_ui"] = {
            key: fallback_visible.get(key)
            for key in (
                "status",
                "visible_ui",
                "recommended_control",
                "screenshot_path",
            )
            if key in fallback_visible
        }
        if (
            fallback_visible.get("status") == "OK"
            and _lightning_visible_ui_is_pause_menu(fallback_visible)
        ):
            result["status"] = "BLOCKED"
            result["reason"] = "resume_from_pause_not_verified"
            result["next_step"] = (
                "Pause menu remained visible after Continue and Escape resume "
                "attempts; recalibrate the pause menu resume control before "
                "continuing timed play."
            )
        else:
            result["reason"] = "resumed_from_pause_escape_fallback"
    return result


class _LightningSubcallTimeout(Exception):
    """Raised by the local SIGALRM handler for bounded Lightning subcommands."""


def _lightning_quiet_call(
    func,
    *args,
    quiet: bool = False,
    timeout_seconds: float | None = None,
    timeout_reason: str = "lightning_subcall_timeout",
    **kwargs,
) -> tuple[dict, dict | None]:
    """Call a noisy command while optionally capturing stdout for speed runs."""
    from contextlib import redirect_stdout, nullcontext

    sink = _CountingOutput() if quiet else None
    timeout = None
    if timeout_seconds is not None:
        try:
            timeout = float(timeout_seconds)
        except (TypeError, ValueError):
            timeout = None
        if timeout is not None and timeout <= 0:
            timeout = None

    alarm_armed = False
    previous_handler = None
    previous_timer = None

    def _timeout_handler(_signum, _frame):
        raise _LightningSubcallTimeout(
            f"{timeout_reason} after {timeout:.1f}s"
        )

    if timeout is not None and os.name != "nt":
        try:
            import signal
            import threading

            if (
                hasattr(signal, "SIGALRM")
                and hasattr(signal, "ITIMER_REAL")
                and threading.current_thread() is threading.main_thread()
            ):
                previous_handler = signal.getsignal(signal.SIGALRM)
                signal.signal(signal.SIGALRM, _timeout_handler)
                previous_timer = signal.setitimer(signal.ITIMER_REAL, timeout)
                alarm_armed = True
        except Exception:
            alarm_armed = False

    global _SUPPRESS_RESULT_PRINT_DEPTH
    if quiet:
        _SUPPRESS_RESULT_PRINT_DEPTH += 1
    try:
        with redirect_stdout(sink) if quiet else nullcontext():
            result = func(*args, **kwargs)
    except _LightningSubcallTimeout as exc:
        result = {
            "status": "BLOCKED",
            "reason": timeout_reason,
            "timeout_seconds": round(float(timeout or 0.0), 2),
            "error": str(exc),
            "next_step": (
                "The Lightning helper exceeded its bounded subcall budget. "
                "Pause/inspect visible and bridge state before retrying from "
                "fresh evidence."
            ),
        }
    finally:
        if quiet:
            _SUPPRESS_RESULT_PRINT_DEPTH -= 1
        if alarm_armed:
            try:
                import signal

                signal.setitimer(signal.ITIMER_REAL, 0.0)
                signal.signal(signal.SIGALRM, previous_handler)
                if previous_timer and previous_timer[0] > 0:
                    signal.setitimer(
                        signal.ITIMER_REAL,
                        previous_timer[0],
                        previous_timer[1],
                    )
            except Exception:
                pass
    output = None
    if sink is not None:
        output = {
            "captured_stdout_lines": sink.lines,
            "captured_stdout_chars": sink.chars,
        }
    return result, output


def _lightning_visible_map_route_plan(
    *,
    profile: str,
    visible_ui: dict,
    route_routing: str = "lightning_war",
    quiet: bool = False,
    allow_pause_map_peek: bool = True,
) -> dict:
    """Score save routes and match them to the current visible island map."""
    if allow_pause_map_peek:
        recommendation, recommendation_output = _lightning_quiet_call(
            cmd_recommend_mission,
            profile=profile,
            routing=route_routing,
            pause_map_peek=True,
            quiet=quiet,
        )
    else:
        recommendation = _lightning_recommend_save_routes(
            profile=profile,
            routing=route_routing,
        )
        recommendation_output = None
    if isinstance(recommendation, dict):
        recommendation.setdefault("routing", route_routing)
    if recommendation_output:
        recommendation["quiet_output"] = recommendation_output
    route_target_hint = _lightning_route_target_hint_from_recommendation(
        recommendation,
    )
    raw_visual_regions = _lightning_visual_regions_from_recommendation(
        recommendation,
    )
    screenshot_path = visible_ui.get("screenshot_path") if isinstance(visible_ui, dict) else None
    if not (
        isinstance(raw_visual_regions, dict)
        and raw_visual_regions.get("status") == "OK"
        and raw_visual_regions.get("regions")
    ) and screenshot_path:
        raw_visual_regions = _lightning_extract_red_regions_from_image(screenshot_path)
    if not (
        isinstance(raw_visual_regions, dict)
        and raw_visual_regions.get("status") == "OK"
        and raw_visual_regions.get("regions")
    ):
        raw_visual_regions = _lightning_visual_regions_from_recommendation(
            recommendation,
        )
    label_screenshot_path = None
    if isinstance(raw_visual_regions, dict):
        label_screenshot_path = raw_visual_regions.get("screenshot_path")
    if not label_screenshot_path:
        label_screenshot_path = screenshot_path
    if label_screenshot_path:
        raw_visual_regions = _lightning_attach_region_ocr_labels(
            raw_visual_regions,
            label_screenshot_path,
        )
    visual_regions = _lightning_assign_visual_route_options(
        raw_visual_regions,
        recommendation,
    )
    route_candidates = _lightning_route_start_candidates(
        visual_regions,
        target_hint=route_target_hint,
        recommendation=recommendation,
    )
    route_fallback = None
    regions = (
        visual_regions.get("regions")
        if isinstance(visual_regions, dict)
        else None
    )
    visible_region_count = len(regions) if isinstance(regions, list) else 0
    recommendation_source = (
        recommendation.get("source") if isinstance(recommendation, dict) else None
    )
    route_candidates_have_mission = any(
        bool(candidate.get("mission_id"))
        for candidate in route_candidates
        if isinstance(candidate, dict)
    )
    ignored_stale_bridge_preview = (
        recommendation.get("ignored_bridge_preview")
        if isinstance(recommendation, dict)
        and isinstance(recommendation.get("ignored_bridge_preview"), dict)
        else None
    )
    stale_bridge_preview_recommendation = (
        isinstance(recommendation, dict)
        and recommendation_source == "bridge_preview"
        and _lightning_bridge_preview_recommendation_stale(recommendation)
    )
    needs_save_route_refresh = (
        visible_region_count > 1
        and isinstance(recommendation, dict)
        and (
            recommendation_source == "bridge_preview"
            or (
                recommendation_source in {"bridge", "saveData"}
                and not route_candidates_have_mission
            )
        )
    )
    if needs_save_route_refresh:
        save_recommendation = _lightning_recommend_save_routes(
            profile=profile,
            routing=route_routing,
        )
        if isinstance(save_recommendation, dict):
            save_recommendation.setdefault("routing", route_routing)
        save_visual_regions = _lightning_assign_visual_route_options(
            raw_visual_regions,
            save_recommendation,
        )
        save_route_target_hint = _lightning_route_target_hint_from_recommendation(
            save_recommendation,
        )
        save_route_candidates = _lightning_route_start_candidates(
            save_visual_regions,
            target_hint=save_route_target_hint,
            recommendation=save_recommendation,
        )
        save_route_candidates_have_mission = any(
            bool(candidate.get("mission_id"))
            for candidate in save_route_candidates
            if isinstance(candidate, dict)
        )
        if save_route_candidates and save_route_candidates_have_mission:
            save_has_auto_candidate = any(
                bool(candidate.get("auto_route_allowed"))
                for candidate in save_route_candidates
                if isinstance(candidate, dict)
            )
            route_fallback = {
                "status": "USED",
                "reason": (
                    "visible_map_ignored_stale_bridge_preview"
                    if recommendation_source == "bridge_preview"
                    else "visible_map_ignored_ambiguous_bridge_preview"
                    if recommendation_source == "bridge_preview"
                    else "visible_map_refreshed_unassigned_save_routes"
                    if recommendation_source == "saveData"
                    else "visible_map_ignored_unassigned_bridge_map"
                ),
                "original_source": recommendation_source,
                "original_top_mission": (
                    recommendation.get("top3", [{}])[0].get("mission_id")
                    if isinstance(recommendation.get("top3"), list)
                    and recommendation.get("top3")
                    and isinstance(recommendation.get("top3")[0], dict)
                    else None
                ),
                "save_source": save_recommendation.get("source"),
                "visible_region_count": visible_region_count,
                "save_auto_route_candidate": save_has_auto_candidate,
            }
            recommendation = save_recommendation
            route_target_hint = save_route_target_hint
            visual_regions = save_visual_regions
            route_candidates = save_route_candidates
        elif save_route_candidates:
            bridge_preview_probe_candidates = (
                recommendation_source == "bridge_preview"
                and bool(route_candidates)
                and all(
                    isinstance(candidate, dict)
                    and candidate.get("forced_preview_ambiguous")
                    and candidate.get("auto_route_block_reason")
                    == "forced_bridge_preview_multiple_visible_regions"
                    for candidate in route_candidates
                )
            )
            bridge_unassigned_probe_candidates = (
                route_routing == "lightning_baseline"
                and recommendation_source == "bridge"
                and isinstance(recommendation, dict)
                and recommendation.get("status") == "NO_ISLAND_MAP"
                and bool(route_candidates)
                and all(
                    isinstance(candidate, dict)
                    and not str(candidate.get("mission_id") or "").strip()
                    for candidate in route_candidates
                )
            )
            ocr_probe_candidates = (
                route_routing == "lightning_baseline"
                and bool(save_route_candidates)
                and visible_region_count > 0
            )
            live_preview_probe_candidates = (
                route_routing == "lightning_war"
                and bool(save_route_candidates)
                and visible_region_count > 0
            )
            probe_candidates_available = (
                bridge_preview_probe_candidates
                or bridge_unassigned_probe_candidates
                or ocr_probe_candidates
                or live_preview_probe_candidates
            )
            route_fallback = {
                "status": "PROBE" if probe_candidates_available else "BLOCKED",
                "reason": (
                    "visible_map_bridge_preview_probe_without_save_assignment"
                    if bridge_preview_probe_candidates
                    else "visible_map_bridge_probe_without_save_assignment"
                    if bridge_unassigned_probe_candidates
                    else "visible_map_ocr_probe_without_save_assignment"
                    if ocr_probe_candidates
                    else "visible_map_live_preview_probe_without_save_assignment"
                    if live_preview_probe_candidates
                    else "visible_map_save_refresh_unassigned"
                ),
                "original_source": recommendation_source,
                "visible_region_count": visible_region_count,
                "save_source": (
                    save_recommendation.get("source")
                    if isinstance(save_recommendation, dict)
                    else None
                ),
                "save_route_candidates": len(save_route_candidates),
                "save_route_candidates_with_mission": 0,
                "route_assignment": (
                    save_visual_regions.get("route_assignment")
                    if isinstance(save_visual_regions, dict)
                    else None
                ),
                "blocked_route_start_candidates": [
                    _lightning_compact_auto_route_candidate(candidate)
                    for candidate in save_route_candidates
                    if isinstance(candidate, dict)
                ],
            }
            if ignored_stale_bridge_preview is not None:
                route_fallback["ignored_bridge_preview"] = ignored_stale_bridge_preview
                route_fallback["ignored_bridge_preview_diagnostic_only"] = True
                if isinstance(recommendation, dict):
                    freshness = recommendation.get("bridge_preview_freshness")
                    if isinstance(freshness, dict):
                        route_fallback["bridge_preview_freshness"] = freshness
            if (
                (ocr_probe_candidates or live_preview_probe_candidates)
                and not bridge_preview_probe_candidates
                and not bridge_unassigned_probe_candidates
            ):
                probe_kind = (
                    "visible_preview_ocr"
                    if ocr_probe_candidates
                    else "live_preview_required"
                )
                route_candidates = [
                    {
                        **candidate,
                        "ocr_probe_route": True,
                        "auto_route_probe": probe_kind,
                    }
                    for candidate in save_route_candidates
                    if isinstance(candidate, dict)
                ]
            elif not probe_candidates_available:
                route_candidates = []
    if (
        not route_candidates
        and visible_region_count == 0
        and (
            ignored_stale_bridge_preview is not None
            or stale_bridge_preview_recommendation
        )
    ):
        route_fallback = {
            "status": "BLOCKED",
            "reason": "stale_bridge_preview_no_visual_route_identity",
            "original_source": recommendation_source,
            "visible_region_count": visible_region_count,
            "ignored_bridge_preview": ignored_stale_bridge_preview,
            "bridge_preview_freshness": (
                recommendation.get("bridge_preview_freshness")
                if isinstance(recommendation, dict)
                else None
            ),
            "route_assignment": (
                visual_regions.get("route_assignment")
                if isinstance(visual_regions, dict)
                else None
            ),
        }
    return {
        "recommendation": recommendation,
        "route_target_hint": route_target_hint,
        "visual_regions": visual_regions,
        "route_start_candidates": route_candidates,
        "route_fallback": route_fallback,
    }


def _lightning_opening_fast_visual_route_plan(
    *,
    visible_ui: dict,
    route_routing: str = "lightning_war",
) -> dict:
    """Build first-mission route candidates from the current screenshot only."""
    screenshot_path = (
        visible_ui.get("screenshot_path")
        if isinstance(visible_ui, dict)
        else None
    )
    raw_visual_regions = None
    if screenshot_path:
        raw_visual_regions = _lightning_extract_red_regions_from_image(
            screenshot_path,
        )
    if not isinstance(raw_visual_regions, dict):
        raw_visual_regions = {
            "status": "BLOCKED",
            "reason": "opening_fast_route_missing_screenshot",
        }
    recommendation = {
        "status": "OK",
        "source": "opening_fast_visual_probe",
        "routing": route_routing,
        "ranked": [],
        "top3": [],
    }
    visual_regions = _lightning_assign_visual_route_options(
        raw_visual_regions,
        recommendation,
    )
    route_candidates = _lightning_route_start_candidates(
        visual_regions,
        recommendation=recommendation,
    )
    route_candidates = [
        {
            **candidate,
            "auto_route_allowed": True,
            "auto_route_probe": "live_preview_required",
            "auto_route_probe_reason": "opening_fast_visual_region_live_preview",
            "ocr_probe_route": True,
            "opening_fast_visual_probe": True,
        }
        for candidate in route_candidates
        if isinstance(candidate, dict)
    ]
    route_fallback = {
        "status": "PROBE" if route_candidates else "BLOCKED",
        "reason": (
            "opening_fast_visual_live_preview_probe"
            if route_candidates
            else "opening_fast_visual_no_route_candidates"
        ),
        "source": "opening_fast_visual_probe",
        "visible_region_count": len(
            visual_regions.get("regions") or []
        ) if isinstance(visual_regions, dict) else 0,
    }
    return {
        "recommendation": recommendation,
        "route_target_hint": None,
        "visual_regions": visual_regions,
        "route_start_candidates": route_candidates,
        "route_fallback": route_fallback,
        "opening_fast_visual_route_plan": True,
    }


def _compact_turn_result_for_lightning(result: dict | None) -> dict | None:
    """Keep fast-loop summaries small while preserving all blocking payloads."""
    if not isinstance(result, dict):
        return result
    status = result.get("status")
    if _is_hard_stop_status(status) or "error" in result:
        return result
    if status not in {"PLAN", "ok", "TERMINAL_OR_MISSION_END"}:
        return result
    keep_keys = (
        "status",
        "turn",
        "phase",
        "save_phase",
        "active_mechs",
        "actions_completed",
        "score",
        "re_solves",
        "bridge_ack",
        "batch",
        "codex_computer_use_batch",
        "post_phase",
        "grid_power",
        "game_over",
        "desync",
    )
    compact = {key: result[key] for key in keep_keys if key in result}
    for key in (
        "fuzzy_detections",
        "soft_disabled",
        "soft_disables_fired_this_turn",
        "unknowns_flagged",
        "research_queue_peek",
    ):
        value = result.get(key)
        if value:
            compact[f"{key}_count"] = len(value) if hasattr(value, "__len__") else 1
    if result.get("solver_gap_events"):
        compact["solver_gap_events"] = result["solver_gap_events"]
    if isinstance(result.get("threat_audit"), dict):
        entries = result["threat_audit"].get("entries") or []
        compact["threat_audit_entries"] = len(entries)
    if "next_step" in result:
        compact["next_step"] = result["next_step"]
    return compact


def cmd_lightning_ui(
    control: str | None = None,
    *,
    dry_run: bool = False,
    list_controls: bool = False,
    include_ocr: bool = False,
    expected_mission_id: str | None = None,
    route_routing: str = "lightning_war",
    allow_expected_preview_start: bool = False,
    lightning_speed_loss_policy: bool = False,
) -> dict:
    """Click a calibrated Lightning War hot-path UI control locally."""
    from src.control.mac_click import (
        click_known_window_control,
        click_known_window_sequence,
        list_known_window_controls,
    )

    if control and _lightning_capture_slug(control) == "classify":
        result = _lightning_visible_ui_snapshot(include_ocr=include_ocr)
        print("\n=== LIGHTNING UI CLASSIFY ===")
        print(f"  status:     {result.get('status')}")
        print(f"  visible_ui: {result.get('visible_ui')}")
        print(f"  control:    {result.get('recommended_control')}")
        print(f"  confidence: {result.get('confidence')}")
        _print_result(result)
        return result

