    sequence = [
        part.strip()
        for chunk in str(control).split(",")
        for part in chunk.split("+")
        if part.strip()
    ]
    if len(sequence) > 1:
        result = click_known_window_sequence(sequence, dry_run=dry_run)
        print("\n=== LIGHTNING UI SEQUENCE ===")
